var e=JSON.parse(`[{"id":10754,"term":"announce","meaning":"발표하다; 알리다","partOfSpeech":"v.","example":"The manager will announce the new schedule on Friday.","exampleTranslation":"매니저가 금요일에 새 일정을 발표할 것이다.","category":"빈도 학습","level":8},{"id":10755,"term":"independent","meaning":"독립적인; 자립한","partOfSpeech":"adj.","example":"She became more independent after moving to a new city.","exampleTranslation":"새 도시로 이사한 후 그녀는 더 독립적으로 변했다.","category":"빈도 학습","level":8},{"id":10756,"term":"survey","meaning":"설문 조사; 조사하다","partOfSpeech":"n./v.","example":"Please fill out this short survey about your stay.","exampleTranslation":"숙박에 관한 이 짧은 설문 조사를 작성해 주세요.","category":"빈도 학습","level":8},{"id":10757,"term":"majority","meaning":"다수; 과반수","partOfSpeech":"n.","example":"The majority of guests preferred the buffet option.","exampleTranslation":"대다수 손님들이 뷔페 옵션을 선호했다.","category":"빈도 학습","level":8},{"id":10758,"term":"stick","meaning":"붙이다; 달라붙다; 막대기","partOfSpeech":"v./n.","example":"Just stick to the plan and everything will work out.","exampleTranslation":"그냥 계획대로 밀고 나가면 다 잘 될 거야.","category":"빈도 학습","level":8},{"id":10759,"term":"rich","meaning":"부유한; 풍부한","partOfSpeech":"adj.","example":"The soup has a rich flavor from the slow-cooked broth.","exampleTranslation":"그 수프는 오래 끓인 육수 덕분에 풍부한 맛이 난다.","category":"빈도 학습","level":8},{"id":10760,"term":"wind","meaning":"바람; 감다","partOfSpeech":"n./v.","example":"The wind knocked over my umbrella outside.","exampleTranslation":"바람이 밖에서 내 우산을 쓰러뜨렸어요.","category":"빈도 학습","level":8},{"id":10761,"term":"none","meaning":"아무것도 없음; 하나도 없음","partOfSpeech":"pron.","example":"None of the seats were available on that flight.","exampleTranslation":"그 항공편에는 빈 좌석이 하나도 없었어요.","category":"빈도 학습","level":8},{"id":10762,"term":"famous","meaning":"유명한","partOfSpeech":"adj.","example":"That restaurant is famous for its grilled chicken.","exampleTranslation":"그 식당은 구운 치킨으로 유명해요.","category":"빈도 학습","level":8},{"id":10763,"term":"blood","meaning":"피; 혈액","partOfSpeech":"n.","example":"The nurse took a blood sample before the checkup.","exampleTranslation":"간호사가 검진 전에 혈액 샘플을 채취했어요.","category":"빈도 학습","level":8},{"id":10764,"term":"appropriate","meaning":"적절한; 알맞은","partOfSpeech":"adj.","example":"Is this outfit appropriate for a job interview?","exampleTranslation":"이 옷차림이 취업 면접에 적절한가요?","category":"빈도 학습","level":8},{"id":10765,"term":"block","meaning":"블록; 막다","partOfSpeech":"n./v.","example":"The coffee shop is just one block from here.","exampleTranslation":"그 커피숍은 여기서 한 블록 거리예요.","category":"빈도 학습","level":8},{"id":10766,"term":"warm","meaning":"따뜻한; 따뜻하게 하다","partOfSpeech":"adj.","example":"It's warm enough to sit outside today.","exampleTranslation":"오늘은 밖에 앉아 있을 만큼 따뜻해요.","category":"빈도 학습","level":8},{"id":10767,"term":"count","meaning":"세다; 중요하다","partOfSpeech":"v.","example":"Every vote will count in this election.","exampleTranslation":"이번 선거에서는 모든 표가 중요해요.","category":"빈도 학습","level":8},{"id":10768,"term":"scene","meaning":"장면; 현장","partOfSpeech":"n.","example":"The opening scene of that movie really grabbed me.","exampleTranslation":"그 영화의 첫 장면이 정말 마음을 사로잡았어요.","category":"빈도 학습","level":8},{"id":10769,"term":"writer","meaning":"작가; 글 쓰는 사람","partOfSpeech":"n.","example":"My sister wants to become a writer someday.","exampleTranslation":"내 여동생은 언젠가 작가가 되고 싶어 해요.","category":"빈도 학습","level":8},{"id":10770,"term":"content","meaning":"내용; 만족한","partOfSpeech":"n./adj.","example":"The content of this video was really helpful.","exampleTranslation":"이 영상의 내용이 정말 도움이 됐어요.","category":"빈도 학습","level":8},{"id":10771,"term":"prevent","meaning":"막다; 예방하다","partOfSpeech":"v.","example":"Washing your hands can prevent a lot of illness.","exampleTranslation":"손을 씻으면 많은 질병을 예방할 수 있어요.","category":"빈도 학습","level":8},{"id":10772,"term":"safe","meaning":"안전한; 금고","partOfSpeech":"adj.","example":"Is it safe to walk alone here at night?","exampleTranslation":"밤에 여기를 혼자 걸어도 안전한가요?","category":"빈도 학습","level":8},{"id":10773,"term":"invite","meaning":"초대하다","partOfSpeech":"v.","example":"She decided to invite a few friends for dinner.","exampleTranslation":"그녀는 저녁 식사에 친구 몇 명을 초대하기로 했어요.","category":"빈도 학습","level":8},{"id":10774,"term":"mix","meaning":"섞다; 혼합","partOfSpeech":"v./n.","example":"Just mix the flour and butter together in a bowl.","exampleTranslation":"그릇에 밀가루와 버터를 함께 섞기만 하면 돼요.","category":"빈도 학습","level":8},{"id":10775,"term":"element","meaning":"요소; 성분","partOfSpeech":"n.","example":"Trust is a key element in any good relationship.","exampleTranslation":"신뢰는 좋은 관계의 핵심 요소예요.","category":"빈도 학습","level":8},{"id":10776,"term":"effective","meaning":"효과적인","partOfSpeech":"adj.","example":"That headache medicine was really effective.","exampleTranslation":"그 두통약은 정말 효과적이었어요.","category":"빈도 학습","level":8},{"id":10777,"term":"correct","meaning":"맞는; 고치다","partOfSpeech":"adj./v.","example":"Could you check if my answer is correct?","exampleTranslation":"제 답이 맞는지 확인해 줄 수 있어요?","category":"빈도 학습","level":8},{"id":10778,"term":"medical","meaning":"의학의; 의료의","partOfSpeech":"adj.","example":"She carried her medical records to the new clinic.","exampleTranslation":"그녀는 새 병원에 진료 기록을 가지고 갔어요.","category":"빈도 학습","level":8},{"id":10779,"term":"admit","meaning":"인정하다; 입장을 허락하다","partOfSpeech":"v.","example":"He finally had to admit that he was wrong.","exampleTranslation":"그는 결국 자신이 틀렸다는 걸 인정해야 했어요.","category":"빈도 학습","level":8},{"id":10780,"term":"beat","meaning":"이기다; 두드리다","partOfSpeech":"v.","example":"Our team managed to beat the other side by two points.","exampleTranslation":"우리 팀은 두 점 차로 상대를 이길 수 있었어요.","category":"빈도 학습","level":8},{"id":10781,"term":"telephone","meaning":"전화(기)","partOfSpeech":"n.","example":"The telephone rang just as I was leaving.","exampleTranslation":"내가 막 나가려는 순간 전화가 울렸어요.","category":"빈도 학습","level":8},{"id":10782,"term":"copy","meaning":"복사하다; 사본","partOfSpeech":"v./n.","example":"Can you copy this form and send it back to me?","exampleTranslation":"이 양식을 복사해서 저한테 돌려보낼 수 있나요?","category":"빈도 학습","level":8},{"id":10783,"term":"committee","meaning":"위원회","partOfSpeech":"n.","example":"The committee will meet again next Monday.","exampleTranslation":"위원회는 다음 주 월요일에 다시 모일 예정이에요.","category":"빈도 학습","level":8},{"id":10784,"term":"aware","meaning":"알고 있는; 의식하는","partOfSpeech":"adj.","example":"Were you aware that the store closes early today?","exampleTranslation":"오늘 가게가 일찍 문 닫는다는 걸 알고 계셨어요?","category":"빈도 학습","level":8},{"id":10785,"term":"advice","meaning":"조언; 충고","partOfSpeech":"n.","example":"Can I ask for your advice on something personal?","exampleTranslation":"개인적인 일에 대해 조언을 구해도 될까요?","category":"빈도 학습","level":8},{"id":10786,"term":"handle","meaning":"처리하다; 손잡이","partOfSpeech":"v./n.","example":"Don't worry, I can handle this situation.","exampleTranslation":"걱정하지 마세요, 제가 이 상황을 처리할 수 있어요.","category":"빈도 학습","level":8},{"id":10787,"term":"glass","meaning":"유리; 유리잔","partOfSpeech":"n.","example":"She poured a glass of cold water for her guest.","exampleTranslation":"그녀는 손님에게 차가운 물 한 잔을 따라 줬어요.","category":"빈도 학습","level":8},{"id":10788,"term":"trial","meaning":"시험; 재판","partOfSpeech":"n.","example":"You can sign up for a free trial before you buy.","exampleTranslation":"구매 전에 무료 체험에 가입할 수 있어요.","category":"빈도 학습","level":8},{"id":10789,"term":"radio","meaning":"라디오","partOfSpeech":"n.","example":"I like listening to the radio on my morning commute.","exampleTranslation":"나는 아침 출퇴근길에 라디오 듣는 걸 좋아해요.","category":"빈도 학습","level":8},{"id":10790,"term":"administration","meaning":"행정; 관리","partOfSpeech":"n.","example":"The school administration sent out a notice to parents.","exampleTranslation":"학교 행정실에서 학부모들에게 공지를 보냈어요.","category":"빈도 학습","level":8},{"id":10791,"term":"complex","meaning":"복잡한; 복합 시설","partOfSpeech":"adj./n.","example":"The directions were too complex for me to follow.","exampleTranslation":"그 안내가 너무 복잡해서 따라가기가 힘들었어요.","category":"빈도 학습","level":8},{"id":10792,"term":"text","meaning":"문자(메시지); 본문","partOfSpeech":"n./v.","example":"I'll text you when I get to the station.","exampleTranslation":"역에 도착하면 문자 보낼게요.","category":"빈도 학습","level":8},{"id":10793,"term":"context","meaning":"맥락; 상황","partOfSpeech":"n.","example":"You need to understand the context to get the joke.","exampleTranslation":"그 농담을 이해하려면 맥락을 알아야 해요.","category":"빈도 학습","level":8},{"id":10794,"term":"ride","meaning":"타다; 탑승","partOfSpeech":"v./n.","example":"Can I ride with you to the airport?","exampleTranslation":"공항까지 같이 타고 가도 될까요?","category":"빈도 학습","level":8},{"id":10795,"term":"directly","meaning":"직접; 곧바로","partOfSpeech":"adv.","example":"You should talk to her directly instead of texting.","exampleTranslation":"문자 말고 그녀에게 직접 말하는 게 좋겠어요.","category":"빈도 학습","level":8},{"id":10796,"term":"heavy","meaning":"무거운; 심한","partOfSpeech":"adj.","example":"This bag is too heavy for me to carry alone.","exampleTranslation":"이 가방은 너무 무거워서 혼자 들 수가 없어요.","category":"빈도 학습","level":8},{"id":10797,"term":"remove","meaning":"제거하다; 치우다","partOfSpeech":"v.","example":"Please remove your shoes before entering the house.","exampleTranslation":"집에 들어오기 전에 신발을 벗어 주세요.","category":"빈도 학습","level":8},{"id":10798,"term":"equipment","meaning":"장비; 기구","partOfSpeech":"n.","example":"The gym has all the equipment you need.","exampleTranslation":"그 헬스장에는 필요한 장비가 다 갖춰져 있어요.","category":"빈도 학습","level":8},{"id":10799,"term":"otherwise","meaning":"그렇지 않으면; 달리","partOfSpeech":"adv.","example":"Hurry up, otherwise we'll miss the bus.","exampleTranslation":"서두르세요, 그렇지 않으면 버스를 놓쳐요.","category":"빈도 학습","level":8},{"id":10800,"term":"title","meaning":"제목; 직함","partOfSpeech":"n.","example":"What's the title of the book you're reading?","exampleTranslation":"지금 읽고 있는 책의 제목이 뭐예요?","category":"빈도 학습","level":8},{"id":10801,"term":"extra","meaning":"추가의; 여분의","partOfSpeech":"adj.","example":"Can I get an extra blanket for the bed?","exampleTranslation":"침대에 쓸 담요를 하나 더 받을 수 있을까요?","category":"빈도 학습","level":8},{"id":10802,"term":"executive","meaning":"임원; 경영진","partOfSpeech":"n.","example":"She became a top executive at the company.","exampleTranslation":"그녀는 회사의 최고 임원이 됐어요.","category":"빈도 학습","level":8},{"id":10803,"term":"chair","meaning":"의자; 의장","partOfSpeech":"n.","example":"Please pull up a chair and sit with us.","exampleTranslation":"의자를 가져다가 우리랑 같이 앉아요.","category":"빈도 학습","level":8},{"id":10804,"term":"sample","meaning":"견본; 샘플","partOfSpeech":"n.","example":"Would you like a free sample of the new perfume?","exampleTranslation":"새 향수 무료 샘플 드릴까요?","category":"빈도 학습","level":8},{"id":10805,"term":"sex","meaning":"성별; 성","partOfSpeech":"n.","example":"The form asks for your name and sex.","exampleTranslation":"양식에 이름과 성별을 기입해야 해요.","category":"빈도 학습","level":8},{"id":10806,"term":"video","meaning":"영상; 동영상","partOfSpeech":"n.","example":"I watched a video about cooking pasta online.","exampleTranslation":"온라인에서 파스타 만드는 영상을 봤어요.","category":"빈도 학습","level":8},{"id":10807,"term":"connection","meaning":"연결; 관계","partOfSpeech":"n.","example":"The internet connection is really slow today.","exampleTranslation":"오늘 인터넷 연결이 너무 느려요.","category":"빈도 학습","level":8},{"id":10808,"term":"primary","meaning":"주요한; 기본적인","partOfSpeech":"adj.","example":"My primary goal this year is to save money.","exampleTranslation":"올해 제 주요 목표는 돈을 모으는 거예요.","category":"빈도 학습","level":8},{"id":10809,"term":"collect","meaning":"모으다; 수집하다","partOfSpeech":"v.","example":"I collect old coins as a hobby.","exampleTranslation":"저는 취미로 오래된 동전을 모아요.","category":"빈도 학습","level":8},{"id":10810,"term":"inform","meaning":"알리다; 통보하다","partOfSpeech":"v.","example":"Please inform me if your plans change.","exampleTranslation":"계획이 바뀌면 저에게 알려주세요.","category":"빈도 학습","level":8},{"id":10811,"term":"principle","meaning":"원칙; 원리","partOfSpeech":"n.","example":"Honesty is an important principle to live by.","exampleTranslation":"정직함은 삶에서 중요한 원칙이에요.","category":"빈도 학습","level":8},{"id":10812,"term":"appeal","meaning":"매력; 호소하다","partOfSpeech":"n./v.","example":"The appeal of living abroad attracted many young people.","exampleTranslation":"해외에 사는 매력이 많은 젊은이들을 끌어당겼어요.","category":"빈도 학습","level":8},{"id":10813,"term":"highly","meaning":"매우; 높이","partOfSpeech":"adv.","example":"She is highly respected by everyone at work.","exampleTranslation":"그녀는 직장 동료들에게 매우 존경받아요.","category":"빈도 학습","level":8},{"id":10814,"term":"trust","meaning":"신뢰; 믿다","partOfSpeech":"n./v.","example":"I trust my friend to keep a secret.","exampleTranslation":"저는 친구가 비밀을 지켜줄 거라고 믿어요.","category":"빈도 학습","level":8},{"id":10815,"term":"wonderful","meaning":"훌륭한; 멋진","partOfSpeech":"adj.","example":"We had a wonderful time at the beach.","exampleTranslation":"해변에서 정말 멋진 시간을 보냈어요.","category":"빈도 학습","level":8},{"id":10816,"term":"flat","meaning":"평평한; 아파트","partOfSpeech":"adj.","example":"The road was flat and easy to drive on.","exampleTranslation":"도로가 평평해서 운전하기 편했어요.","category":"빈도 학습","level":8},{"id":10817,"term":"absolutely","meaning":"완전히; 물론이죠","partOfSpeech":"adv.","example":"I absolutely love this restaurant.","exampleTranslation":"이 식당이 완전히 마음에 들어요.","category":"빈도 학습","level":8},{"id":10818,"term":"flow","meaning":"흐르다; 흐름","partOfSpeech":"n./v.","example":"The river flow was stronger after the rain.","exampleTranslation":"비가 온 후 강의 흐름이 더 세졌어요.","category":"빈도 학습","level":8},{"id":10819,"term":"fair","meaning":"공정한; 축제","partOfSpeech":"adj.","example":"It's not fair to blame him for everything.","exampleTranslation":"모든 걸 그의 탓으로 돌리는 건 공정하지 않아요.","category":"빈도 학습","level":8},{"id":10820,"term":"additional","meaning":"추가적인; 부가적인","partOfSpeech":"adj.","example":"There will be an additional charge for the service.","exampleTranslation":"그 서비스에는 추가 요금이 붙을 거예요.","category":"빈도 학습","level":8},{"id":10821,"term":"responsible","meaning":"책임감 있는; 담당인","partOfSpeech":"adj.","example":"She is responsible for managing the team's schedule.","exampleTranslation":"그녀가 팀 일정 관리를 담당하고 있어요.","category":"빈도 학습","level":8},{"id":10822,"term":"farm","meaning":"농장; 농사짓다","partOfSpeech":"n.","example":"We visited a farm and picked strawberries.","exampleTranslation":"농장을 방문해서 딸기를 직접 땄어요.","category":"빈도 학습","level":8},{"id":10823,"term":"collection","meaning":"수집품; 모음","partOfSpeech":"n.","example":"His collection of vintage records is impressive.","exampleTranslation":"그의 빈티지 레코드 수집품은 정말 인상적이에요.","category":"빈도 학습","level":8},{"id":10824,"term":"hang","meaning":"걸다; 매달다","partOfSpeech":"v.","example":"Can you hang the picture on that wall?","exampleTranslation":"저 벽에 그림을 걸어줄 수 있어요?","category":"빈도 학습","level":8},{"id":10825,"term":"negative","meaning":"부정적인; 나쁜","partOfSpeech":"adj.","example":"Try not to have a negative attitude at work.","exampleTranslation":"직장에서 부정적인 태도를 갖지 않으려고 노력해요.","category":"빈도 학습","level":8},{"id":10826,"term":"band","meaning":"악단; 띠","partOfSpeech":"n.","example":"The band played live music at the festival.","exampleTranslation":"그 악단이 축제에서 라이브 음악을 연주했어요.","category":"빈도 학습","level":8},{"id":10827,"term":"relative","meaning":"친척; 상대적인","partOfSpeech":"n./adj.","example":"I'm meeting a relative I haven't seen in years.","exampleTranslation":"몇 년 만에 못 본 친척을 만날 거예요.","category":"빈도 학습","level":8},{"id":10828,"term":"alternative","meaning":"대안; 다른 선택","partOfSpeech":"n.","example":"Is there an alternative route to avoid the traffic?","exampleTranslation":"교통체증을 피할 다른 길이 있을까요?","category":"빈도 학습","level":8},{"id":10829,"term":"software","meaning":"소프트웨어; 프로그램","partOfSpeech":"n.","example":"Please update the software on your phone.","exampleTranslation":"휴대폰에 소프트웨어를 업데이트해 주세요.","category":"빈도 학습","level":8},{"id":10830,"term":"pair","meaning":"한 쌍; 한 켤레","partOfSpeech":"n.","example":"I need a new pair of running shoes.","exampleTranslation":"새 운동화 한 켤레가 필요해요.","category":"빈도 학습","level":8},{"id":10831,"term":"attitude","meaning":"태도; 자세","partOfSpeech":"n.","example":"A positive attitude makes a big difference at work.","exampleTranslation":"긍정적인 태도는 직장에서 큰 차이를 만들어요.","category":"빈도 학습","level":8},{"id":10832,"term":"double","meaning":"두 배의; 두 배로 하다","partOfSpeech":"adj.","example":"I'd like a double espresso, please.","exampleTranslation":"에스프레소 더블로 주세요.","category":"빈도 학습","level":8},{"id":10833,"term":"leg","meaning":"다리","partOfSpeech":"n.","example":"My leg hurts after the long hike.","exampleTranslation":"오래 등산하고 나서 다리가 아파요.","category":"빈도 학습","level":8},{"id":10834,"term":"observe","meaning":"관찰하다; 준수하다","partOfSpeech":"v.","example":"We stopped to observe the birds by the lake.","exampleTranslation":"호수 근처에서 새들을 관찰하려고 잠시 멈췄어요.","category":"빈도 학습","level":8},{"id":10835,"term":"sentence","meaning":"문장; 판결","partOfSpeech":"n.","example":"Write your answer in a complete sentence.","exampleTranslation":"완전한 문장으로 답을 써주세요.","category":"빈도 학습","level":8},{"id":10836,"term":"print","meaning":"인쇄하다; 출력하다","partOfSpeech":"v.","example":"Can you print two copies of this document?","exampleTranslation":"이 문서를 두 부 출력해 줄 수 있어요?","category":"빈도 학습","level":8},{"id":10837,"term":"progress","meaning":"진전; 발전하다","partOfSpeech":"n.","example":"She has made great progress in her English studies.","exampleTranslation":"그녀는 영어 공부에서 큰 진전을 이뤘어요.","category":"빈도 학습","level":8},{"id":10838,"term":"truth","meaning":"진실; 사실","partOfSpeech":"n.","example":"Please tell me the truth about what happened.","exampleTranslation":"무슨 일이 있었는지 진실을 말해주세요.","category":"빈도 학습","level":8},{"id":10839,"term":"nobody","meaning":"아무도 ~않다","partOfSpeech":"pron.","example":"Nobody answered when I knocked on the door.","exampleTranslation":"문을 두드렸는데 아무도 대답하지 않았어요.","category":"빈도 학습","level":8},{"id":10840,"term":"examine","meaning":"살펴보다; 검사하다","partOfSpeech":"v.","example":"The doctor will examine you before giving a prescription.","exampleTranslation":"의사가 처방전을 내리기 전에 진찰할 거예요.","category":"빈도 학습","level":8},{"id":10841,"term":"lay","meaning":"놓다; 눕히다","partOfSpeech":"v.","example":"Please lay the blanket on the bed before the guests arrive.","exampleTranslation":"손님들이 오기 전에 침대에 담요를 깔아 두세요.","category":"빈도 학습","level":8},{"id":10842,"term":"speed","meaning":"속도; 빠르게 가다","partOfSpeech":"n./v.","example":"The train travels at a very high speed between the two cities.","exampleTranslation":"그 기차는 두 도시 사이를 매우 빠른 속도로 달려요.","category":"빈도 학습","level":8},{"id":10843,"term":"politics","meaning":"정치; 정치학","partOfSpeech":"n.","example":"She has been interested in politics since she was in college.","exampleTranslation":"그녀는 대학 시절부터 정치에 관심이 있었어요.","category":"빈도 학습","level":8},{"id":10844,"term":"display","meaning":"전시하다; 화면","partOfSpeech":"v./n.","example":"The museum will display the new paintings starting next week.","exampleTranslation":"박물관은 다음 주부터 새 그림들을 전시할 예정이에요.","category":"빈도 학습","level":8},{"id":10845,"term":"perfect","meaning":"완벽한; 완전한","partOfSpeech":"adj.","example":"This café is the perfect place to relax on a rainy day.","exampleTranslation":"이 카페는 비 오는 날 쉬기에 완벽한 장소예요.","category":"빈도 학습","level":8},{"id":10846,"term":"slightly","meaning":"약간; 조금","partOfSpeech":"adv.","example":"The price is slightly higher than I expected.","exampleTranslation":"가격이 제가 예상했던 것보다 약간 높네요.","category":"빈도 학습","level":8},{"id":10847,"term":"overall","meaning":"전반적인; 전체적으로","partOfSpeech":"adj.","example":"The overall quality of the food at this restaurant is excellent.","exampleTranslation":"이 식당 음식의 전반적인 품질은 훌륭해요.","category":"빈도 학습","level":8},{"id":10848,"term":"intend","meaning":"~할 의도이다; 계획하다","partOfSpeech":"v.","example":"I intend to finish the report before the end of the day.","exampleTranslation":"오늘 안에 보고서를 끝낼 생각이에요.","category":"빈도 학습","level":8},{"id":10849,"term":"user","meaning":"사용자; 이용자","partOfSpeech":"n.","example":"Every user needs to create an account to access the service.","exampleTranslation":"서비스를 이용하려면 모든 사용자가 계정을 만들어야 해요.","category":"빈도 학습","level":8},{"id":10850,"term":"respond","meaning":"응답하다; 반응하다","partOfSpeech":"v.","example":"She didn't respond to my message for two days.","exampleTranslation":"그녀는 이틀 동안 내 메시지에 답장을 하지 않았어요.","category":"빈도 학습","level":8},{"id":10851,"term":"regular","meaning":"규칙적인; 정기적인","partOfSpeech":"adj.","example":"He goes for a regular walk every morning before breakfast.","exampleTranslation":"그는 매일 아침 식사 전에 정기적으로 산책을 해요.","category":"빈도 학습","level":8},{"id":10852,"term":"physical","meaning":"신체적인; 물리적인","partOfSpeech":"adj.","example":"Regular physical activity helps keep your heart healthy.","exampleTranslation":"규칙적인 신체 활동은 심장을 건강하게 유지하는 데 도움이 돼요.","category":"빈도 학습","level":8},{"id":10853,"term":"apart","meaning":"떨어져; 따로","partOfSpeech":"adv.","example":"The two towns are only ten minutes apart by car.","exampleTranslation":"두 마을은 차로 10분밖에 떨어져 있지 않아요.","category":"빈도 학습","level":9},{"id":10854,"term":"suit","meaning":"잘 맞다; 정장","partOfSpeech":"v./n.","example":"This schedule should suit everyone on the team just fine.","exampleTranslation":"이 일정은 팀의 모든 사람에게 딱 맞을 거예요.","category":"빈도 학습","level":9},{"id":10855,"term":"federal","meaning":"연방의; 연방 정부의","partOfSpeech":"adj.","example":"The federal government announced new rules for online privacy.","exampleTranslation":"연방 정부가 온라인 개인 정보 보호에 관한 새 규정을 발표했어요.","category":"빈도 학습","level":9},{"id":10856,"term":"reveal","meaning":"드러내다; 밝히다","partOfSpeech":"v.","example":"She finally agreed to reveal the secret ingredient in her recipe.","exampleTranslation":"그녀는 결국 레시피의 비밀 재료를 공개하기로 했어요.","category":"빈도 학습","level":9},{"id":10857,"term":"percentage","meaning":"비율; 퍼센트","partOfSpeech":"n.","example":"A large percentage of the students passed the exam this year.","exampleTranslation":"올해는 많은 비율의 학생들이 시험에 합격했어요.","category":"빈도 학습","level":9},{"id":10858,"term":"peace","meaning":"평화; 평온","partOfSpeech":"n.","example":"I just need some peace and quiet after such a long day.","exampleTranslation":"이렇게 긴 하루를 보낸 뒤에는 그냥 조용한 평온이 필요해요.","category":"빈도 학습","level":9},{"id":10859,"term":"status","meaning":"상태; 지위","partOfSpeech":"n.","example":"Can you check the status of my delivery order online?","exampleTranslation":"제 배송 주문 상태를 온라인에서 확인해 주실 수 있나요?","category":"빈도 학습","level":9},{"id":10860,"term":"crime","meaning":"범죄; 죄","partOfSpeech":"n.","example":"The neighborhood watch group helps reduce crime in the area.","exampleTranslation":"자율 방범대가 그 지역의 범죄를 줄이는 데 도움을 줘요.","category":"빈도 학습","level":9},{"id":10861,"term":"decline","meaning":"감소하다; 거절하다","partOfSpeech":"v.","example":"Sales tend to decline during the cold winter months.","exampleTranslation":"매출은 추운 겨울철에 감소하는 경향이 있어요.","category":"빈도 학습","level":9},{"id":10862,"term":"decade","meaning":"10년","partOfSpeech":"n.","example":"A lot has changed in this city over the past decade.","exampleTranslation":"지난 10년 동안 이 도시는 많이 변했어요.","category":"빈도 학습","level":9},{"id":10863,"term":"warn","meaning":"경고하다; 주의를 주다","partOfSpeech":"v.","example":"The weather app will warn you if a storm is coming.","exampleTranslation":"날씨 앱이 폭풍이 오면 경고를 보내 줄 거예요.","category":"빈도 학습","level":9},{"id":10864,"term":"consumer","meaning":"소비자","partOfSpeech":"n.","example":"The new law is designed to protect the consumer from false advertising.","exampleTranslation":"새 법은 소비자를 허위 광고로부터 보호하기 위해 만들어졌어요.","category":"빈도 학습","level":9},{"id":10865,"term":"favor","meaning":"호의; 부탁","partOfSpeech":"n.","example":"Could you do me a favor and water my plants while I'm away?","exampleTranslation":"제가 없는 동안 화분에 물 좀 줄 수 있어요? 부탁이에요.","category":"빈도 학습","level":9},{"id":10866,"term":"dry","meaning":"건조한; 마른","partOfSpeech":"adj.","example":"My skin gets very dry in winter, so I use a lot of lotion.","exampleTranslation":"겨울에는 피부가 너무 건조해져서 로션을 많이 발라요.","category":"빈도 학습","level":9},{"id":10867,"term":"partner","meaning":"파트너; 동반자","partOfSpeech":"n.","example":"My business partner handles all the financial planning for the company.","exampleTranslation":"제 사업 파트너가 회사의 재무 계획을 전담하고 있어요.","category":"빈도 학습","level":9},{"id":10868,"term":"institution","meaning":"기관; 제도","partOfSpeech":"n.","example":"A bank is a financial institution that people use every day.","exampleTranslation":"은행은 사람들이 매일 이용하는 금융 기관이에요.","category":"빈도 학습","level":9},{"id":10869,"term":"spot","meaning":"발견하다; 장소","partOfSpeech":"v./n.","example":"I always go to the same spot in the park to eat my lunch.","exampleTranslation":"저는 항상 공원의 같은 장소에서 점심을 먹어요.","category":"빈도 학습","level":9},{"id":10870,"term":"horse","meaning":"말","partOfSpeech":"n.","example":"She learned to ride a horse when she was just seven years old.","exampleTranslation":"그녀는 겨우 일곱 살 때 말 타는 법을 배웠어요.","category":"빈도 학습","level":9},{"id":10871,"term":"eventually","meaning":"결국; 마침내","partOfSpeech":"adv.","example":"We got lost a few times but eventually found the restaurant.","exampleTranslation":"몇 번 길을 잃었지만 결국 식당을 찾았어요.","category":"빈도 학습","level":9},{"id":10872,"term":"heat","meaning":"열; 더위","partOfSpeech":"n.","example":"The heat from the oven made the whole kitchen feel warm.","exampleTranslation":"오븐의 열기 때문에 부엌 전체가 따뜻해졌어요.","category":"빈도 학습","level":9},{"id":10873,"term":"excite","meaning":"흥분시키다; 설레게 하다","partOfSpeech":"v.","example":"Long trips to new countries always excite me so much.","exampleTranslation":"새 나라로의 긴 여행은 항상 저를 엄청나게 설레게 해요.","category":"빈도 학습","level":9},{"id":10874,"term":"reader","meaning":"독자; 읽는 사람","partOfSpeech":"n.","example":"This blog has grown from a few friends to thousands of daily reader visits.","exampleTranslation":"이 블로그는 친구 몇 명에서 시작해 매일 수천 명의 독자가 방문해요.","category":"빈도 학습","level":9},{"id":10875,"term":"importance","meaning":"중요성; 중요함","partOfSpeech":"n.","example":"She stressed the importance of drinking enough water every day.","exampleTranslation":"그녀는 매일 충분한 물을 마시는 것의 중요성을 강조했어요.","category":"빈도 학습","level":9},{"id":10876,"term":"distance","meaning":"거리; 간격","partOfSpeech":"n.","example":"We could see the mountains in the distance from the balcony.","exampleTranslation":"발코니에서 저 멀리 산이 보였어요.","category":"빈도 학습","level":9},{"id":10877,"term":"grant","meaning":"허가하다; 보조금","partOfSpeech":"v./n.","example":"The city agreed to grant permission for the outdoor festival.","exampleTranslation":"시에서 야외 축제 개최를 허가하기로 했어요.","category":"빈도 학습","level":9},{"id":10878,"term":"feed","meaning":"먹이다; 먹이를 주다","partOfSpeech":"v.","example":"Don't forget to feed the cat before you leave the house.","exampleTranslation":"집을 나서기 전에 고양이 밥 주는 것 잊지 마세요.","category":"빈도 학습","level":9},{"id":10879,"term":"sector","meaning":"부문; 분야","partOfSpeech":"n.","example":"The tech sector has grown rapidly over the past few years.","exampleTranslation":"기술 부문은 지난 몇 년 동안 빠르게 성장했어요.","category":"빈도 학습","level":9},{"id":10880,"term":"mistake","meaning":"실수; 잘못","partOfSpeech":"n.","example":"I made a mistake and sent the wrong file.","exampleTranslation":"나는 실수로 잘못된 파일을 보냈어.","category":"빈도 학습","level":9},{"id":10881,"term":"satisfy","meaning":"만족시키다","partOfSpeech":"v.","example":"Nothing seemed to satisfy him at dinner.","exampleTranslation":"저녁 식사 때 아무것도 그를 만족시키지 못하는 것 같았어.","category":"빈도 학습","level":9},{"id":10882,"term":"chief","meaning":"최고 책임자; 주된","partOfSpeech":"n./adj.","example":"She talked to the chief about the new policy.","exampleTranslation":"그녀는 새 정책에 대해 최고 책임자와 이야기했어.","category":"빈도 학습","level":9},{"id":10883,"term":"cool","meaning":"시원한; 멋진","partOfSpeech":"adj.","example":"It was cool outside so we went for a walk.","exampleTranslation":"밖이 시원해서 우리는 산책을 나갔어.","category":"빈도 학습","level":9},{"id":10884,"term":"expert","meaning":"전문가","partOfSpeech":"n.","example":"We need an expert to fix this problem.","exampleTranslation":"이 문제를 해결할 전문가가 필요해.","category":"빈도 학습","level":9},{"id":10885,"term":"wave","meaning":"파도; 손을 흔들다","partOfSpeech":"n./v.","example":"She gave a wave as the bus pulled away.","exampleTranslation":"버스가 떠나자 그녀는 손을 흔들었어.","category":"빈도 학습","level":9},{"id":10886,"term":"south","meaning":"남쪽; 남부","partOfSpeech":"n.","example":"They drove south to escape the cold weather.","exampleTranslation":"그들은 추운 날씨를 피해 남쪽으로 운전했어.","category":"빈도 학습","level":9},{"id":10887,"term":"labor","meaning":"노동; 일하다","partOfSpeech":"n./v.","example":"The project required a lot of manual labor.","exampleTranslation":"그 프로젝트는 많은 육체 노동이 필요했어.","category":"빈도 학습","level":9},{"id":10888,"term":"surface","meaning":"표면; 겉면","partOfSpeech":"n.","example":"Wipe the surface clean before cooking.","exampleTranslation":"요리 전에 표면을 깨끗이 닦아.","category":"빈도 학습","level":9},{"id":10889,"term":"excellent","meaning":"훌륭한; 뛰어난","partOfSpeech":"adj.","example":"The food at that restaurant was excellent.","exampleTranslation":"그 식당 음식은 정말 훌륭했어.","category":"빈도 학습","level":9},{"id":10890,"term":"edge","meaning":"가장자리; 모서리","partOfSpeech":"n.","example":"Be careful near the edge of the platform.","exampleTranslation":"승강장 가장자리 근처에서 조심해.","category":"빈도 학습","level":9},{"id":10891,"term":"camp","meaning":"야영지; 캠프","partOfSpeech":"n.","example":"The kids had a great time at summer camp.","exampleTranslation":"아이들은 여름 캠프에서 즐거운 시간을 보냈어.","category":"빈도 학습","level":9},{"id":10892,"term":"audience","meaning":"관객; 청중","partOfSpeech":"n.","example":"The audience clapped loudly after the show.","exampleTranslation":"공연이 끝나자 관객들이 크게 박수를 쳤어.","category":"빈도 학습","level":9},{"id":10893,"term":"lift","meaning":"들어올리다; 엘리베이터","partOfSpeech":"v./n.","example":"Can you lift that box onto the shelf?","exampleTranslation":"저 상자를 선반 위로 들어올릴 수 있어?","category":"빈도 학습","level":9},{"id":10894,"term":"procedure","meaning":"절차; 방법","partOfSpeech":"n.","example":"Follow the procedure step by step.","exampleTranslation":"절차를 단계별로 따라가세요.","category":"빈도 학습","level":9},{"id":10895,"term":"global","meaning":"세계적인; 전반적인","partOfSpeech":"adj.","example":"Social media has made communication global.","exampleTranslation":"소셜 미디어 덕분에 소통이 세계적으로 이루어지게 됐어.","category":"빈도 학습","level":9},{"id":10896,"term":"struggle","meaning":"힘겹게 애쓰다; 고투","partOfSpeech":"v./n.","example":"I struggle to wake up early every morning.","exampleTranslation":"나는 매일 아침 일찍 일어나는 게 너무 힘들어.","category":"빈도 학습","level":9},{"id":10897,"term":"advertise","meaning":"광고하다; 홍보하다","partOfSpeech":"v.","example":"They advertise their products on social media.","exampleTranslation":"그들은 소셜 미디어에서 제품을 광고해.","category":"빈도 학습","level":9},{"id":10898,"term":"select","meaning":"선택하다; 고르다","partOfSpeech":"v.","example":"You can select any seat in this row.","exampleTranslation":"이 줄 아무 자리나 선택할 수 있어요.","category":"빈도 학습","level":9},{"id":10899,"term":"surround","meaning":"둘러싸다; 에워싸다","partOfSpeech":"v.","example":"Trees surround the house on all sides.","exampleTranslation":"나무들이 집 사방을 둘러싸고 있어.","category":"빈도 학습","level":9},{"id":10900,"term":"extent","meaning":"정도; 범위","partOfSpeech":"n.","example":"To some extent, I agree with what you said.","exampleTranslation":"어느 정도는 네 말에 동의해.","category":"빈도 학습","level":9},{"id":10901,"term":"river","meaning":"강","partOfSpeech":"n.","example":"We sat by the river and watched the sunset.","exampleTranslation":"우리는 강가에 앉아 노을을 바라봤어.","category":"빈도 학습","level":9},{"id":10902,"term":"fully","meaning":"완전히; 충분히","partOfSpeech":"adv.","example":"Make sure the door is fully closed.","exampleTranslation":"문이 완전히 닫혔는지 확인해.","category":"빈도 학습","level":9},{"id":10903,"term":"contrast","meaning":"대조; 차이","partOfSpeech":"n./v.","example":"The contrast between the two prices was huge.","exampleTranslation":"두 가격의 차이가 엄청났어.","category":"빈도 학습","level":9},{"id":10904,"term":"roll","meaning":"굴리다; 구르다","partOfSpeech":"v.","example":"The ball started to roll down the hill.","exampleTranslation":"공이 언덕 아래로 굴러 내려가기 시작했어.","category":"빈도 학습","level":9},{"id":10905,"term":"reality","meaning":"현실; 실제","partOfSpeech":"n.","example":"The reality is that we don't have enough time.","exampleTranslation":"현실은 우리에게 시간이 충분하지 않다는 거야.","category":"빈도 학습","level":9},{"id":10906,"term":"photograph","meaning":"사진","partOfSpeech":"n.","example":"She framed the photograph and hung it on the wall.","exampleTranslation":"그녀는 사진을 액자에 넣어 벽에 걸었어.","category":"빈도 학습","level":9},{"id":10907,"term":"artist","meaning":"예술가; 화가","partOfSpeech":"n.","example":"The artist sold her painting at the market.","exampleTranslation":"그 예술가는 시장에서 자신의 그림을 팔았어.","category":"빈도 학습","level":9},{"id":10908,"term":"conflict","meaning":"갈등; 충돌","partOfSpeech":"n./v.","example":"There was a conflict between the two neighbors.","exampleTranslation":"두 이웃 사이에 갈등이 있었어.","category":"빈도 학습","level":9},{"id":10909,"term":"entire","meaning":"전체의; 온","partOfSpeech":"adj.","example":"She read the entire book in one day.","exampleTranslation":"그녀는 하루 만에 책 전체를 읽었어.","category":"빈도 학습","level":9},{"id":10910,"term":"presence","meaning":"존재; 참석","partOfSpeech":"n.","example":"Your presence at the meeting really matters.","exampleTranslation":"회의에 네가 참석하는 게 정말 중요해.","category":"빈도 학습","level":9},{"id":10911,"term":"crowd","meaning":"군중; 무리","partOfSpeech":"n.","example":"A large crowd gathered in the town square.","exampleTranslation":"마을 광장에 많은 군중이 모였어.","category":"빈도 학습","level":9},{"id":10912,"term":"gas","meaning":"가스; 휘발유","partOfSpeech":"n.","example":"We stopped to fill up the gas on the highway.","exampleTranslation":"우리는 고속도로에서 차에 휘발유를 넣으러 멈췄어.","category":"빈도 학습","level":9},{"id":10913,"term":"shift","meaning":"바꾸다; 교대 근무","partOfSpeech":"v./n.","example":"He had to shift his schedule to fit the meeting.","exampleTranslation":"그는 회의에 맞추려고 일정을 바꿔야 했어.","category":"빈도 학습","level":9},{"id":10914,"term":"net","meaning":"그물; 순(純)","partOfSpeech":"n./adj.","example":"The fisherman pulled in his net after an hour.","exampleTranslation":"어부는 한 시간 후에 그물을 끌어올렸어.","category":"빈도 학습","level":9},{"id":10915,"term":"category","meaning":"범주; 분류","partOfSpeech":"n.","example":"Which category does this product belong to?","exampleTranslation":"이 제품은 어떤 범주에 속하나요?","category":"빈도 학습","level":9},{"id":10916,"term":"secretary","meaning":"비서; 장관","partOfSpeech":"n.","example":"The secretary scheduled all the appointments.","exampleTranslation":"비서가 모든 예약 일정을 잡았어.","category":"빈도 학습","level":9},{"id":10917,"term":"defense","meaning":"방어; 수비","partOfSpeech":"n.","example":"The team's defense was strong throughout the game.","exampleTranslation":"경기 내내 그 팀의 수비는 탄탄했어.","category":"빈도 학습","level":9},{"id":10918,"term":"quick","meaning":"빠른; 신속한","partOfSpeech":"adj.","example":"Let's grab a quick lunch before the meeting.","exampleTranslation":"회의 전에 빠르게 점심을 먹자.","category":"빈도 학습","level":9},{"id":10919,"term":"spread","meaning":"퍼지다; 바르다","partOfSpeech":"v.","example":"Spread some butter on the toast.","exampleTranslation":"토스트에 버터를 좀 발라.","category":"빈도 학습","level":9},{"id":10920,"term":"nuclear","meaning":"핵의; 원자력의","partOfSpeech":"adj.","example":"Many countries are debating whether to use nuclear energy.","exampleTranslation":"많은 나라들이 핵에너지 사용 여부를 논의하고 있다.","category":"빈도 학습","level":9},{"id":10921,"term":"driver","meaning":"운전사; 운전자","partOfSpeech":"n.","example":"The driver stopped to let passengers get off the bus.","exampleTranslation":"운전사가 승객들이 버스에서 내릴 수 있도록 멈췄다.","category":"빈도 학습","level":9},{"id":10922,"term":"ball","meaning":"공; 볼","partOfSpeech":"n.","example":"He kicked the ball into the goal.","exampleTranslation":"그는 공을 골대 안으로 찼다.","category":"빈도 학습","level":9},{"id":10923,"term":"cry","meaning":"울다; 외치다","partOfSpeech":"v.","example":"She started to cry when she heard the sad news.","exampleTranslation":"그녀는 슬픈 소식을 듣고 울기 시작했다.","category":"빈도 학습","level":9},{"id":10924,"term":"introduction","meaning":"소개; 도입","partOfSpeech":"n.","example":"The teacher gave a brief introduction before starting the lesson.","exampleTranslation":"선생님은 수업을 시작하기 전에 간단한 소개를 했다.","category":"빈도 학습","level":9},{"id":10925,"term":"requirement","meaning":"요건; 필요 조건","partOfSpeech":"n.","example":"A valid passport is a requirement for traveling abroad.","exampleTranslation":"유효한 여권은 해외여행의 필요 조건이다.","category":"빈도 학습","level":9},{"id":10926,"term":"north","meaning":"북쪽; 북부","partOfSpeech":"n.","example":"They drove north for three hours to reach the cabin.","exampleTranslation":"그들은 오두막에 가려고 북쪽으로 세 시간을 운전했다.","category":"빈도 학습","level":9},{"id":10927,"term":"senior","meaning":"선임의; 손위의","partOfSpeech":"adj.","example":"She was promoted to a senior position after five years.","exampleTranslation":"그녀는 5년 후 선임 직책으로 승진했다.","category":"빈도 학습","level":9},{"id":10928,"term":"photo","meaning":"사진","partOfSpeech":"n.","example":"Can you take a photo of us in front of the fountain?","exampleTranslation":"분수대 앞에서 우리 사진 좀 찍어 줄 수 있어요?","category":"빈도 학습","level":9},{"id":10929,"term":"refuse","meaning":"거절하다; 거부하다","partOfSpeech":"v.","example":"She had every right to refuse the request.","exampleTranslation":"그녀는 그 요청을 거절할 충분한 권리가 있었다.","category":"빈도 학습","level":9},{"id":10930,"term":"transport","meaning":"운송하다; 수송","partOfSpeech":"n./v.","example":"Public transport in this city is fast and affordable.","exampleTranslation":"이 도시의 대중교통은 빠르고 저렴하다.","category":"빈도 학습","level":9},{"id":10931,"term":"emerge","meaning":"나타나다; 드러나다","partOfSpeech":"v.","example":"New details began to emerge as the investigation continued.","exampleTranslation":"수사가 계속되면서 새로운 세부 사항이 드러나기 시작했다.","category":"빈도 학습","level":9},{"id":10932,"term":"concept","meaning":"개념; 관념","partOfSpeech":"n.","example":"The concept of sharing is taught to children from an early age.","exampleTranslation":"나눔의 개념은 어릴 때부터 아이들에게 가르쳐진다.","category":"빈도 학습","level":9},{"id":10933,"term":"island","meaning":"섬","partOfSpeech":"n.","example":"They spent their honeymoon on a small tropical island.","exampleTranslation":"그들은 작은 열대 섬에서 신혼여행을 보냈다.","category":"빈도 학습","level":9},{"id":10934,"term":"reform","meaning":"개혁하다; 개혁","partOfSpeech":"n./v.","example":"The government announced plans to reform the healthcare system.","exampleTranslation":"정부는 의료 시스템을 개혁할 계획을 발표했다.","category":"빈도 학습","level":9},{"id":10935,"term":"neither","meaning":"둘 다 아닌; 어느 쪽도 아닌","partOfSpeech":"conj.","example":"Neither option seemed right, so we looked for a third choice.","exampleTranslation":"어느 쪽 선택지도 맞지 않아서, 우리는 세 번째 선택지를 찾았다.","category":"빈도 학습","level":9},{"id":10936,"term":"football","meaning":"축구; 풋볼","partOfSpeech":"n.","example":"The kids play football in the park every Saturday morning.","exampleTranslation":"아이들은 매주 토요일 아침 공원에서 축구를 한다.","category":"빈도 학습","level":9},{"id":10937,"term":"survive","meaning":"살아남다; 생존하다","partOfSpeech":"v.","example":"The plant can survive without water for several weeks.","exampleTranslation":"그 식물은 몇 주 동안 물 없이 살아남을 수 있다.","category":"빈도 학습","level":9},{"id":10938,"term":"background","meaning":"배경; 경력","partOfSpeech":"n.","example":"She has a strong background in finance and accounting.","exampleTranslation":"그녀는 재무와 회계 분야에서 탄탄한 경력을 갖고 있다.","category":"빈도 학습","level":9},{"id":10939,"term":"technique","meaning":"기법; 기술","partOfSpeech":"n.","example":"The chef showed us his technique for making a perfect omelet.","exampleTranslation":"요리사가 완벽한 오믈렛을 만드는 기법을 우리에게 보여줬다.","category":"빈도 학습","level":9},{"id":10940,"term":"improvement","meaning":"개선; 향상","partOfSpeech":"n.","example":"There has been a noticeable improvement in her English recently.","exampleTranslation":"최근 그녀의 영어 실력에 눈에 띄는 향상이 있었다.","category":"빈도 학습","level":9},{"id":10941,"term":"tool","meaning":"도구; 수단","partOfSpeech":"n.","example":"A good dictionary is an essential tool for language learners.","exampleTranslation":"좋은 사전은 언어 학습자에게 필수적인 도구다.","category":"빈도 학습","level":9},{"id":10942,"term":"consequence","meaning":"결과; 결말","partOfSpeech":"n.","example":"Think carefully before you act — every action has a consequence.","exampleTranslation":"행동하기 전에 신중하게 생각해라 — 모든 행동에는 결과가 따른다.","category":"빈도 학습","level":9},{"id":10943,"term":"circumstance","meaning":"상황; 환경","partOfSpeech":"n.","example":"Under no circumstance should you leave the children alone.","exampleTranslation":"어떤 상황에서도 아이들을 혼자 두어서는 안 된다.","category":"빈도 학습","level":9},{"id":10944,"term":"smoke","meaning":"연기; 담배를 피우다","partOfSpeech":"n./v.","example":"Thick smoke filled the room when the fire started.","exampleTranslation":"불이 나자 짙은 연기가 방을 가득 채웠다.","category":"빈도 학습","level":9},{"id":10945,"term":"reaction","meaning":"반응; 반사 행동","partOfSpeech":"n.","example":"Her reaction to the surprise party was priceless.","exampleTranslation":"깜짝 파티에 대한 그녀의 반응은 정말 인상적이었다.","category":"빈도 학습","level":9},{"id":10946,"term":"lesson","meaning":"수업; 교훈","partOfSpeech":"n.","example":"I have a piano lesson every Tuesday afternoon.","exampleTranslation":"나는 매주 화요일 오후에 피아노 수업이 있다.","category":"빈도 학습","level":9},{"id":10947,"term":"brain","meaning":"뇌; 두뇌","partOfSpeech":"n.","example":"Exercise is good for your brain as well as your body.","exampleTranslation":"운동은 몸뿐만 아니라 뇌에도 좋다.","category":"빈도 학습","level":9},{"id":10948,"term":"mass","meaning":"대량의; 덩어리","partOfSpeech":"n.","example":"A large mass of people gathered in the city square.","exampleTranslation":"도시 광장에 많은 사람들이 대거 모였다.","category":"빈도 학습","level":9},{"id":10949,"term":"funny","meaning":"웃긴; 이상한","partOfSpeech":"adj.","example":"He told a funny story that made everyone laugh.","exampleTranslation":"그는 모두를 웃게 만든 재밌는 이야기를 했다.","category":"빈도 학습","level":9},{"id":10950,"term":"contribute","meaning":"기여하다; 공헌하다","partOfSpeech":"v.","example":"Everyone can contribute to a cleaner environment in small ways.","exampleTranslation":"누구나 작은 방식으로 더 깨끗한 환경에 기여할 수 있다.","category":"빈도 학습","level":9},{"id":10951,"term":"failure","meaning":"실패; 실패작","partOfSpeech":"n.","example":"Don't let one failure stop you from trying again.","exampleTranslation":"한 번의 실패가 다시 도전하는 것을 막지 않게 해라.","category":"빈도 학습","level":9},{"id":10952,"term":"speaker","meaning":"연사; 말하는 사람","partOfSpeech":"n.","example":"The guest speaker shared her experience living abroad.","exampleTranslation":"초청 연사는 해외 생활 경험을 공유했다.","category":"빈도 학습","level":9},{"id":10953,"term":"bottom","meaning":"바닥; 맨 아래","partOfSpeech":"n.","example":"The keys fell to the bottom of her bag.","exampleTranslation":"열쇠가 그녀의 가방 바닥으로 떨어졌다.","category":"빈도 학습","level":9},{"id":10954,"term":"adopt","meaning":"채택하다; 입양하다","partOfSpeech":"v.","example":"They decided to adopt a healthier lifestyle after the doctor's advice.","exampleTranslation":"그들은 의사의 조언을 듣고 더 건강한 생활 방식을 채택하기로 했다.","category":"빈도 학습","level":9},{"id":10955,"term":"combine","meaning":"결합하다; 합치다","partOfSpeech":"v.","example":"You can combine lemon and honey to soothe a sore throat.","exampleTranslation":"레몬과 꿀을 합치면 인후통을 완화할 수 있다.","category":"빈도 학습","level":9},{"id":10956,"term":"mountain","meaning":"산","partOfSpeech":"n.","example":"They hiked up the mountain and enjoyed the view from the top.","exampleTranslation":"그들은 산을 올라 정상에서 경치를 즐겼다.","category":"빈도 학습","level":9},{"id":10957,"term":"waste","meaning":"낭비하다; 쓰레기","partOfSpeech":"n./v.","example":"Don't waste food — there are people who have nothing to eat.","exampleTranslation":"음식을 낭비하지 마라 — 먹을 것이 없는 사람들이 있다.","category":"빈도 학습","level":9},{"id":10958,"term":"hide","meaning":"숨다; 숨기다","partOfSpeech":"v.","example":"The kids love to hide behind the curtains during hide and seek.","exampleTranslation":"아이들은 숨바꼭질 중에 커튼 뒤에 숨는 것을 좋아한다.","category":"빈도 학습","level":9},{"id":10959,"term":"marriage","meaning":"결혼; 혼인","partOfSpeech":"n.","example":"Their marriage has been strong for over twenty years.","exampleTranslation":"그들의 결혼 생활은 20년 이상 탄탄하게 이어지고 있다.","category":"빈도 학습","level":10},{"id":10960,"term":"meal","meaning":"식사; 끼니","partOfSpeech":"n.","example":"We had a delicious meal at that new restaurant.","exampleTranslation":"우리는 그 새 식당에서 맛있는 식사를 했어.","category":"빈도 학습","level":10},{"id":10961,"term":"bag","meaning":"가방; 봉지","partOfSpeech":"n.","example":"She put her lunch in a paper bag.","exampleTranslation":"그녀는 점심을 종이봉지에 넣었어.","category":"빈도 학습","level":10},{"id":10962,"term":"repeat","meaning":"반복하다; 다시 말하다","partOfSpeech":"v.","example":"Could you repeat that? I didn't catch it.","exampleTranslation":"다시 말해 줄 수 있어요? 못 들었어요.","category":"빈도 학습","level":10},{"id":10963,"term":"equal","meaning":"동등한; 같은","partOfSpeech":"adj.","example":"Everyone deserves equal treatment at work.","exampleTranslation":"직장에서 모든 사람은 동등한 대우를 받을 자격이 있어.","category":"빈도 학습","level":10},{"id":10964,"term":"expression","meaning":"표현; 표정","partOfSpeech":"n.","example":"His expression showed that he was surprised.","exampleTranslation":"그의 표정을 보면 놀랐다는 게 느껴졌어.","category":"빈도 학습","level":10},{"id":10965,"term":"plus","meaning":"더하기; 게다가","partOfSpeech":"prep.","example":"The room rate is $80 plus tax.","exampleTranslation":"객실 요금은 세금 포함해서 80달러야.","category":"빈도 학습","level":10},{"id":10966,"term":"extremely","meaning":"매우; 극도로","partOfSpeech":"adv.","example":"It was extremely hot in the city last summer.","exampleTranslation":"지난여름 도시는 극도로 더웠어.","category":"빈도 학습","level":10},{"id":10967,"term":"owner","meaning":"주인; 소유자","partOfSpeech":"n.","example":"The owner of the café greeted us at the door.","exampleTranslation":"카페 주인이 문 앞에서 우리를 반갑게 맞아 줬어.","category":"빈도 학습","level":10},{"id":10968,"term":"plane","meaning":"비행기; 평면","partOfSpeech":"n.","example":"Our plane lands in Tokyo at noon.","exampleTranslation":"우리 비행기는 정오에 도쿄에 착륙해.","category":"빈도 학습","level":10},{"id":10969,"term":"commercial","meaning":"상업적인; 광고","partOfSpeech":"adj.","example":"The city center is mostly a commercial area.","exampleTranslation":"시내 중심은 대부분 상업 지역이야.","category":"빈도 학습","level":10},{"id":10970,"term":"lady","meaning":"여성; 숙녀","partOfSpeech":"n.","example":"A lady at the front desk helped me check in.","exampleTranslation":"프런트 데스크의 한 여성이 체크인을 도와줬어.","category":"빈도 학습","level":10},{"id":10971,"term":"duty","meaning":"의무; 세금(관세)","partOfSpeech":"n.","example":"It's your duty to report any safety issues.","exampleTranslation":"안전 문제를 신고하는 건 당신의 의무예요.","category":"빈도 학습","level":10},{"id":10972,"term":"connect","meaning":"연결하다; 접속하다","partOfSpeech":"v.","example":"I need to connect my laptop to the Wi-Fi.","exampleTranslation":"노트북을 와이파이에 연결해야 해.","category":"빈도 학습","level":10},{"id":10973,"term":"cultural","meaning":"문화적인; 문화의","partOfSpeech":"adj.","example":"Visiting temples gave me a cultural experience.","exampleTranslation":"절을 방문하는 건 문화적인 경험이었어.","category":"빈도 학습","level":10},{"id":10974,"term":"arrange","meaning":"준비하다; 정리하다","partOfSpeech":"v.","example":"Can you arrange a taxi for 7 a.m.?","exampleTranslation":"오전 7시에 택시 좀 불러 줄 수 있어요?","category":"빈도 학습","level":10},{"id":10975,"term":"scheme","meaning":"계획; 제도","partOfSpeech":"n.","example":"They launched a scheme to reduce food waste.","exampleTranslation":"그들은 음식물 낭비를 줄이는 계획을 시작했어.","category":"빈도 학습","level":10},{"id":10976,"term":"unfortunately","meaning":"안타깝게도; 불행히도","partOfSpeech":"adv.","example":"Unfortunately, the concert was canceled due to rain.","exampleTranslation":"안타깝게도 비 때문에 콘서트가 취소됐어.","category":"빈도 학습","level":10},{"id":10977,"term":"brief","meaning":"짧은; 간략한","partOfSpeech":"adj.","example":"She gave a brief summary of the meeting.","exampleTranslation":"그녀는 회의를 짧게 요약해 줬어.","category":"빈도 학습","level":10},{"id":10978,"term":"bird","meaning":"새","partOfSpeech":"n.","example":"A bird was singing outside my window this morning.","exampleTranslation":"오늘 아침 창밖에서 새가 노래하고 있었어.","category":"빈도 학습","level":10},{"id":10979,"term":"demonstrate","meaning":"보여 주다; 시연하다","partOfSpeech":"v.","example":"The chef will demonstrate how to make the sauce.","exampleTranslation":"셰프가 소스 만드는 방법을 직접 보여 줄 거야.","category":"빈도 학습","level":10},{"id":10980,"term":"contribution","meaning":"기여; 공헌","partOfSpeech":"n.","example":"Her contribution to the project was huge.","exampleTranslation":"프로젝트에 대한 그녀의 기여는 정말 컸어.","category":"빈도 학습","level":10},{"id":10981,"term":"appreciate","meaning":"감사하다; 높이 평가하다","partOfSpeech":"v.","example":"I really appreciate your help with this.","exampleTranslation":"이 일에 도움을 주셔서 정말 감사해요.","category":"빈도 학습","level":10},{"id":10982,"term":"chapter","meaning":"장(章); 챕터","partOfSpeech":"n.","example":"I finished the first chapter of the novel last night.","exampleTranslation":"어젯밤에 소설 첫 번째 장을 다 읽었어.","category":"빈도 학습","level":10},{"id":10983,"term":"secret","meaning":"비밀; 비밀의","partOfSpeech":"n.","example":"Can you keep a secret? I'm planning a surprise party.","exampleTranslation":"비밀 지킬 수 있어? 깜짝 파티를 준비하고 있거든.","category":"빈도 학습","level":10},{"id":10984,"term":"apparently","meaning":"보아하니; 겉보기에","partOfSpeech":"adv.","example":"Apparently the store closes early on Sundays.","exampleTranslation":"보아하니 그 가게는 일요일에 일찍 닫는 것 같아.","category":"빈도 학습","level":10},{"id":10985,"term":"novel","meaning":"소설; 새로운","partOfSpeech":"n.","example":"She read the whole novel in one weekend.","exampleTranslation":"그녀는 주말 내내 소설 한 권을 다 읽었어.","category":"빈도 학습","level":10},{"id":10986,"term":"union","meaning":"연합; 노동조합","partOfSpeech":"n.","example":"The workers voted to join a union.","exampleTranslation":"노동자들은 노동조합에 가입하기로 투표했어.","category":"빈도 학습","level":10},{"id":10987,"term":"burn","meaning":"타다; 불에 데다","partOfSpeech":"v.","example":"Be careful not to burn your hand on the stove.","exampleTranslation":"가스레인지에 손 데지 않게 조심해.","category":"빈도 학습","level":10},{"id":10988,"term":"trend","meaning":"유행; 추세","partOfSpeech":"n.","example":"The latest trend is wearing oversized jackets.","exampleTranslation":"요즘 유행은 오버사이즈 재킷을 입는 거야.","category":"빈도 학습","level":10},{"id":10989,"term":"initial","meaning":"처음의; 초기의","partOfSpeech":"adj.","example":"My initial reaction was complete surprise.","exampleTranslation":"처음 반응은 완전히 놀라는 거였어.","category":"빈도 학습","level":10},{"id":10990,"term":"pleasure","meaning":"즐거움; 기쁨","partOfSpeech":"n.","example":"It was a pleasure meeting you at the conference.","exampleTranslation":"컨퍼런스에서 만나서 정말 반가웠어요.","category":"빈도 학습","level":10},{"id":10991,"term":"suggestion","meaning":"제안; 추천","partOfSpeech":"n.","example":"Do you have any suggestion for a good place to eat?","exampleTranslation":"좋은 식당 추천해 줄 수 있어?","category":"빈도 학습","level":10},{"id":10992,"term":"critical","meaning":"중요한; 비판적인","partOfSpeech":"adj.","example":"Getting enough sleep is critical for your health.","exampleTranslation":"충분한 수면은 건강에 매우 중요해.","category":"빈도 학습","level":10},{"id":10993,"term":"gather","meaning":"모이다; 모으다","partOfSpeech":"v.","example":"Friends and family gather here every holiday.","exampleTranslation":"매 명절마다 친구들과 가족이 여기에 모여.","category":"빈도 학습","level":10},{"id":10994,"term":"mostly","meaning":"주로; 대부분","partOfSpeech":"adv.","example":"I mostly walk to work, but sometimes I take the bus.","exampleTranslation":"주로 걸어서 출근하지만 가끔 버스를 타기도 해.","category":"빈도 학습","level":10},{"id":10995,"term":"earth","meaning":"지구; 땅","partOfSpeech":"n.","example":"The earth gets warmer every year.","exampleTranslation":"지구는 해마다 점점 더 따뜻해지고 있어.","category":"빈도 학습","level":10},{"id":10996,"term":"pop","meaning":"터지다; 잠깐 들르다","partOfSpeech":"v.","example":"I'll pop into the store and grab some milk.","exampleTranslation":"잠깐 가게에 들러서 우유 사 올게.","category":"빈도 학습","level":10},{"id":10997,"term":"essential","meaning":"필수적인; 꼭 필요한","partOfSpeech":"adj.","example":"A passport is essential for international travel.","exampleTranslation":"해외여행에는 여권이 꼭 필요해.","category":"빈도 학습","level":10},{"id":10998,"term":"desire","meaning":"바라다; 욕구","partOfSpeech":"n./v.","example":"She has a strong desire to travel the world.","exampleTranslation":"그녀는 세계를 여행하고 싶은 강한 욕구가 있어.","category":"빈도 학습","level":10},{"id":10999,"term":"promote","meaning":"홍보하다; 승진시키다","partOfSpeech":"v.","example":"They promote their products on social media.","exampleTranslation":"그들은 소셜 미디어에서 자신들의 제품을 홍보해.","category":"빈도 학습","level":10},{"id":11000,"term":"employ","meaning":"고용하다; (방법을) 쓰다","partOfSpeech":"v.","example":"We need to employ more staff for the holidays.","exampleTranslation":"우리는 연휴를 대비해 직원을 더 고용해야 해요.","category":"빈도 학습","level":10},{"id":11001,"term":"path","meaning":"길, 경로; 진로","partOfSpeech":"n.","example":"Just follow this path to the river.","exampleTranslation":"이 길만 따라가면 강이 나와요.","category":"빈도 학습","level":10},{"id":11002,"term":"topic","meaning":"주제, 화제","partOfSpeech":"n.","example":"Let's change the topic, this is boring.","exampleTranslation":"주제를 바꾸자, 이건 지루해.","category":"빈도 학습","level":10},{"id":11003,"term":"attract","meaning":"끌어당기다, (마음을) 끌다","partOfSpeech":"v.","example":"The new store should attract a lot of customers.","exampleTranslation":"새 가게는 많은 손님을 끌어들일 거예요.","category":"빈도 학습","level":10},{"id":11004,"term":"engage","meaning":"(주의를) 끌다; 참여하다","partOfSpeech":"v.","example":"Good teachers know how to engage their students.","exampleTranslation":"좋은 선생님은 학생들의 관심을 끄는 법을 알아요.","category":"빈도 학습","level":10},{"id":11005,"term":"powerful","meaning":"강력한, 힘센","partOfSpeech":"adj.","example":"This little engine is surprisingly powerful.","exampleTranslation":"이 작은 엔진은 놀랄 만큼 힘이 세요.","category":"빈도 학습","level":10},{"id":11006,"term":"flower","meaning":"꽃","partOfSpeech":"n.","example":"He gave her a single red flower.","exampleTranslation":"그는 그녀에게 빨간 꽃 한 송이를 주었어요.","category":"빈도 학습","level":10},{"id":11007,"term":"crisis","meaning":"위기, 고비","partOfSpeech":"n.","example":"The country is facing a serious economic crisis.","exampleTranslation":"그 나라는 심각한 경제 위기를 겪고 있어요.","category":"빈도 학습","level":10},{"id":11008,"term":"settle","meaning":"정착하다; (문제를) 해결하다","partOfSpeech":"v.","example":"They want to settle in a quiet town.","exampleTranslation":"그들은 조용한 마을에 정착하고 싶어 해요.","category":"빈도 학습","level":10},{"id":11009,"term":"boat","meaning":"배, 보트","partOfSpeech":"n.","example":"We took a small boat across the lake.","exampleTranslation":"우리는 작은 배를 타고 호수를 건넜어요.","category":"빈도 학습","level":10},{"id":11010,"term":"aid","meaning":"도움, 원조; 돕다","partOfSpeech":"n./v.","example":"They sent food and medical aid to the area.","exampleTranslation":"그들은 그 지역에 식량과 의료 지원을 보냈어요.","category":"빈도 학습","level":10},{"id":11011,"term":"fan","meaning":"팬, 애호가; 선풍기","partOfSpeech":"n.","example":"I'm a huge fan of that band.","exampleTranslation":"나는 그 밴드의 열렬한 팬이에요.","category":"빈도 학습","level":10},{"id":11012,"term":"kitchen","meaning":"부엌, 주방","partOfSpeech":"n.","example":"Mom is cooking dinner in the kitchen.","exampleTranslation":"엄마가 부엌에서 저녁을 만들고 있어요.","category":"빈도 학습","level":10},{"id":11013,"term":"twice","meaning":"두 번; 두 배로","partOfSpeech":"adv.","example":"I've already seen this movie twice.","exampleTranslation":"나는 이 영화를 벌써 두 번 봤어요.","category":"빈도 학습","level":10},{"id":11014,"term":"safety","meaning":"안전","partOfSpeech":"n.","example":"Please wear a helmet for your own safety.","exampleTranslation":"본인의 안전을 위해 헬멧을 착용하세요.","category":"빈도 학습","level":10},{"id":11015,"term":"engineer","meaning":"기술자, 엔지니어","partOfSpeech":"n.","example":"My sister works as a software engineer.","exampleTranslation":"내 여동생은 소프트웨어 기술자로 일해요.","category":"빈도 학습","level":10},{"id":11016,"term":"quiet","meaning":"조용한, 고요한","partOfSpeech":"adj.","example":"Please be quiet, the baby is sleeping.","exampleTranslation":"조용히 해 주세요, 아기가 자고 있어요.","category":"빈도 학습","level":10},{"id":11017,"term":"insurance","meaning":"보험","partOfSpeech":"n.","example":"Do you have health insurance here?","exampleTranslation":"여기 건강 보험에 가입돼 있나요?","category":"빈도 학습","level":10},{"id":11018,"term":"divide","meaning":"나누다, 가르다","partOfSpeech":"v.","example":"Let's divide the pizza into eight slices.","exampleTranslation":"피자를 여덟 조각으로 나누자.","category":"빈도 학습","level":10},{"id":11019,"term":"length","meaning":"길이; (시간의) 길이","partOfSpeech":"n.","example":"What is the length of this table?","exampleTranslation":"이 탁자의 길이는 얼마예요?","category":"빈도 학습","level":10},{"id":11020,"term":"investigation","meaning":"조사, 수사","partOfSpeech":"n.","example":"The police started an investigation into the case.","exampleTranslation":"경찰이 그 사건에 대한 수사를 시작했어요.","category":"빈도 학습","level":10},{"id":11021,"term":"package","meaning":"소포, 꾸러미","partOfSpeech":"n.","example":"A package arrived for you this morning.","exampleTranslation":"오늘 아침에 당신 앞으로 소포가 왔어요.","category":"빈도 학습","level":10},{"id":11022,"term":"somewhere","meaning":"어딘가에","partOfSpeech":"adv.","example":"Let's go somewhere warm this winter.","exampleTranslation":"이번 겨울엔 어딘가 따뜻한 곳으로 가자.","category":"빈도 학습","level":10},{"id":11023,"term":"expand","meaning":"확장하다, 넓히다","partOfSpeech":"v.","example":"The company plans to expand into Asia.","exampleTranslation":"그 회사는 아시아로 사업을 확장할 계획이에요.","category":"빈도 학습","level":10},{"id":11024,"term":"obvious","meaning":"분명한, 뻔한","partOfSpeech":"adj.","example":"It's obvious that she likes you.","exampleTranslation":"그녀가 너를 좋아하는 건 뻔해.","category":"빈도 학습","level":10},{"id":11025,"term":"jump","meaning":"뛰다, 점프하다","partOfSpeech":"v.","example":"Don't jump on the bed, please.","exampleTranslation":"침대 위에서 뛰지 마세요.","category":"빈도 학습","level":10},{"id":11026,"term":"weapon","meaning":"무기","partOfSpeech":"n.","example":"The guard carried a weapon at his side.","exampleTranslation":"그 경비원은 옆구리에 무기를 차고 있었어요.","category":"빈도 학습","level":10},{"id":11027,"term":"relatively","meaning":"비교적, 상대적으로","partOfSpeech":"adv.","example":"The test was relatively easy this time.","exampleTranslation":"이번 시험은 비교적 쉬웠어요.","category":"빈도 학습","level":10},{"id":11028,"term":"host","meaning":"주최자, 주인; 진행하다","partOfSpeech":"n./v.","example":"Our host welcomed us with a big smile.","exampleTranslation":"주인은 환한 미소로 우리를 맞아 주었어요.","category":"빈도 학습","level":10},{"id":11029,"term":"winter","meaning":"겨울","partOfSpeech":"n.","example":"It gets very cold here in winter.","exampleTranslation":"이곳은 겨울에 무척 추워져요.","category":"빈도 학습","level":10},{"id":11030,"term":"district","meaning":"지역, 구역","partOfSpeech":"n.","example":"She lives in the business district downtown.","exampleTranslation":"그녀는 시내 상업 지구에 살아요.","category":"빈도 학습","level":10},{"id":11031,"term":"broad","meaning":"넓은; 폭넓은","partOfSpeech":"adj.","example":"He has broad shoulders and a kind face.","exampleTranslation":"그는 어깨가 넓고 인상이 좋아요.","category":"빈도 학습","level":10},{"id":11032,"term":"tire","meaning":"타이어; 피곤하게 하다","partOfSpeech":"n./v.","example":"I think the front tire is flat.","exampleTranslation":"앞바퀴 타이어가 펑크 난 것 같아요.","category":"빈도 학습","level":10},{"id":11033,"term":"spring","meaning":"봄; 용수철","partOfSpeech":"n.","example":"The flowers bloom in early spring.","exampleTranslation":"그 꽃들은 이른 봄에 피어요.","category":"빈도 학습","level":10},{"id":11034,"term":"spirit","meaning":"정신, 영혼; 기운","partOfSpeech":"n.","example":"She has a strong fighting spirit.","exampleTranslation":"그녀는 강한 투지를 가지고 있어요.","category":"빈도 학습","level":10},{"id":11035,"term":"actual","meaning":"실제의, 진짜의","partOfSpeech":"adj.","example":"The actual cost was higher than we expected.","exampleTranslation":"실제 비용은 우리가 예상한 것보다 높았어요.","category":"빈도 학습","level":10},{"id":11036,"term":"pool","meaning":"수영장; 웅덩이","partOfSpeech":"n.","example":"The kids are swimming in the pool.","exampleTranslation":"아이들이 수영장에서 헤엄치고 있어요.","category":"빈도 학습","level":10},{"id":11037,"term":"battle","meaning":"전투, 싸움","partOfSpeech":"n.","example":"They fought a long battle for freedom.","exampleTranslation":"그들은 자유를 위해 오랜 싸움을 벌였어요.","category":"빈도 학습","level":10},{"id":11038,"term":"tradition","meaning":"전통, 관습","partOfSpeech":"n.","example":"It's a family tradition to eat together.","exampleTranslation":"함께 식사하는 것은 우리 집안의 전통이에요.","category":"빈도 학습","level":10},{"id":11039,"term":"hardly","meaning":"거의 ~않다","partOfSpeech":"adv.","example":"I can hardly hear you, speak up please.","exampleTranslation":"목소리가 거의 안 들려요, 좀 크게 말해 주세요.","category":"빈도 학습","level":10},{"id":11040,"term":"award","meaning":"상; 수여하다","partOfSpeech":"n./v.","example":"She won an award for her outstanding work.","exampleTranslation":"그녀는 뛰어난 활약으로 상을 받았어요.","category":"빈도 학습","level":10},{"id":11041,"term":"coach","meaning":"코치; 훈련시키다","partOfSpeech":"n./v.","example":"The coach told us to warm up before practice.","exampleTranslation":"코치가 연습 전에 준비 운동을 하라고 했어요.","category":"빈도 학습","level":10},{"id":11042,"term":"experiment","meaning":"실험; 실험하다","partOfSpeech":"n./v.","example":"We did a fun experiment in science class today.","exampleTranslation":"오늘 과학 시간에 재미있는 실험을 했어요.","category":"빈도 학습","level":10},{"id":11043,"term":"consideration","meaning":"고려; 배려","partOfSpeech":"n.","example":"Price is an important consideration when buying a car.","exampleTranslation":"차를 살 때 가격은 중요한 고려 사항이에요.","category":"빈도 학습","level":10},{"id":11044,"term":"strange","meaning":"이상한; 낯선","partOfSpeech":"adj.","example":"There was a strange noise coming from the basement.","exampleTranslation":"지하에서 이상한 소리가 났어요.","category":"빈도 학습","level":10},{"id":11045,"term":"possibly","meaning":"어쩌면; 아마도","partOfSpeech":"adv.","example":"Could you possibly help me move this sofa?","exampleTranslation":"이 소파 옮기는 것 좀 도와주실 수 있을까요?","category":"빈도 학습","level":10},{"id":11046,"term":"threat","meaning":"위협; 협박","partOfSpeech":"n.","example":"The storm posed a serious threat to the coastal towns.","exampleTranslation":"그 폭풍은 해안 마을에 심각한 위협이 됐어요.","category":"빈도 학습","level":10},{"id":11047,"term":"accident","meaning":"사고; 우연","partOfSpeech":"n.","example":"There was a car accident on the highway this morning.","exampleTranslation":"오늘 아침 고속도로에서 교통사고가 났어요.","category":"빈도 학습","level":10},{"id":11048,"term":"impossible","meaning":"불가능한","partOfSpeech":"adj.","example":"It felt impossible to wake up early on weekends.","exampleTranslation":"주말에 일찍 일어나는 건 불가능하게 느껴졌어요.","category":"빈도 학습","level":10},{"id":11049,"term":"revenue","meaning":"수익; 세입","partOfSpeech":"n.","example":"The new store brought in more revenue than expected.","exampleTranslation":"새 매장은 예상보다 더 많은 수익을 냈어요.","category":"빈도 학습","level":10},{"id":11050,"term":"enable","meaning":"가능하게 하다; 활성화하다","partOfSpeech":"v.","example":"This app will enable you to track your expenses easily.","exampleTranslation":"이 앱으로 지출을 쉽게 관리할 수 있어요.","category":"빈도 학습","level":10},{"id":11051,"term":"afraid","meaning":"두려워하는; 걱정하는","partOfSpeech":"adj.","example":"She was afraid of speaking in front of the class.","exampleTranslation":"그녀는 반 친구들 앞에서 발표하는 것을 두려워했어요.","category":"빈도 학습","level":10},{"id":11052,"term":"active","meaning":"활동적인; 적극적인","partOfSpeech":"adj.","example":"He stays active by jogging every morning.","exampleTranslation":"그는 매일 아침 조깅으로 활동적인 생활을 유지해요.","category":"빈도 학습","level":10},{"id":11053,"term":"conclude","meaning":"결론 짓다; 마치다","partOfSpeech":"v.","example":"They couldn't conclude the meeting without a final decision.","exampleTranslation":"최종 결정 없이는 회의를 마무리할 수 없었어요.","category":"빈도 학습","level":10},{"id":11054,"term":"religious","meaning":"종교적인; 신앙심 깊은","partOfSpeech":"adj.","example":"They visit the temple as part of their religious practice.","exampleTranslation":"그들은 종교 생활의 일환으로 사원을 방문해요.","category":"빈도 학습","level":10},{"id":11055,"term":"cancer","meaning":"암","partOfSpeech":"n.","example":"Early detection makes cancer much easier to treat.","exampleTranslation":"조기 발견을 하면 암 치료가 훨씬 수월해요.","category":"빈도 학습","level":10},{"id":11056,"term":"convince","meaning":"납득시키다; 설득하다","partOfSpeech":"v.","example":"He tried to convince his parents to let him study abroad.","exampleTranslation":"그는 부모님을 설득해 해외 유학을 허락받으려 했어요.","category":"빈도 학습","level":10},{"id":11057,"term":"vary","meaning":"다양하다; 달라지다","partOfSpeech":"v.","example":"Prices vary depending on the season and location.","exampleTranslation":"가격은 계절과 지역에 따라 달라져요.","category":"빈도 학습","level":10},{"id":11058,"term":"environmental","meaning":"환경의; 환경과 관련된","partOfSpeech":"adj.","example":"The company is making changes to reduce its environmental impact.","exampleTranslation":"그 회사는 환경 영향을 줄이기 위해 변화를 꾀하고 있어요.","category":"빈도 학습","level":10},{"id":11059,"term":"sun","meaning":"태양; 햇빛","partOfSpeech":"n.","example":"The sun was so bright that I needed sunglasses.","exampleTranslation":"햇빛이 너무 강해서 선글라스가 필요했어요.","category":"빈도 학습","level":10},{"id":11060,"term":"blow","meaning":"불다; 강타","partOfSpeech":"v./n.","example":"A strong wind started to blow as we left the house.","exampleTranslation":"집을 나서자 강한 바람이 불기 시작했어요.","category":"빈도 학습","level":10},{"id":11061,"term":"volume","meaning":"음량; 양; 부피","partOfSpeech":"n.","example":"Can you turn down the volume on the TV?","exampleTranslation":"TV 음량 좀 줄여줄 수 있어요?","category":"빈도 학습","level":10},{"id":11062,"term":"location","meaning":"위치; 장소","partOfSpeech":"n.","example":"The restaurant's location is right next to the subway station.","exampleTranslation":"그 식당은 지하철역 바로 옆에 있어요.","category":"빈도 학습","level":10},{"id":11063,"term":"invest","meaning":"투자하다","partOfSpeech":"v.","example":"She decided to invest her savings in a small business.","exampleTranslation":"그녀는 저축한 돈을 소규모 사업에 투자하기로 했어요.","category":"빈도 학습","level":10},{"id":11064,"term":"proceed","meaning":"진행하다; 나아가다","partOfSpeech":"v.","example":"Once everyone is ready, we can proceed with the meeting.","exampleTranslation":"모두 준비가 되면 회의를 진행할 수 있어요.","category":"빈도 학습","level":10},{"id":11065,"term":"wash","meaning":"씻다; 세탁하다","partOfSpeech":"v.","example":"Don't forget to wash your hands before eating.","exampleTranslation":"식사 전에 손 씻는 것 잊지 마세요.","category":"빈도 학습","level":10},{"id":11066,"term":"actor","meaning":"배우","partOfSpeech":"n.","example":"My favorite actor just announced a new movie.","exampleTranslation":"내가 좋아하는 배우가 새 영화를 발표했어요.","category":"빈도 학습","level":11},{"id":11067,"term":"glad","meaning":"기쁜; 반가운","partOfSpeech":"adj.","example":"I'm so glad you could make it to the party.","exampleTranslation":"파티에 와줘서 정말 기뻐요.","category":"빈도 학습","level":11},{"id":11068,"term":"tape","meaning":"테이프; 붙이다","partOfSpeech":"n./v.","example":"She used tape to hang the poster on the wall.","exampleTranslation":"그녀는 테이프로 포스터를 벽에 붙였어요.","category":"빈도 학습","level":11},{"id":11069,"term":"whereas","meaning":"반면에; ~인 데 반해","partOfSpeech":"conj.","example":"She loves spicy food, whereas her husband prefers mild dishes.","exampleTranslation":"그녀는 매운 음식을 좋아하는 반면, 남편은 순한 음식을 선호해요.","category":"빈도 학습","level":11},{"id":11070,"term":"opposite","meaning":"반대의; 맞은편","partOfSpeech":"adj./n.","example":"The pharmacy is on the opposite side of the street.","exampleTranslation":"약국은 길 맞은편에 있어요.","category":"빈도 학습","level":11},{"id":11071,"term":"stone","meaning":"돌; 돌멩이","partOfSpeech":"n.","example":"The kids were skipping stone across the river.","exampleTranslation":"아이들이 강에서 돌 던지기 놀이를 하고 있었어요.","category":"빈도 학습","level":11},{"id":11072,"term":"sum","meaning":"합계; 금액","partOfSpeech":"n.","example":"The sum of all our expenses was higher than we expected.","exampleTranslation":"모든 지출의 합계가 예상보다 높았어요.","category":"빈도 학습","level":11},{"id":11073,"term":"murder","meaning":"살인; 살해하다","partOfSpeech":"n./v.","example":"The detective was called in to investigate the murder.","exampleTranslation":"형사가 살인 사건을 수사하기 위해 호출됐어요.","category":"빈도 학습","level":11},{"id":11074,"term":"soldier","meaning":"군인; 병사","partOfSpeech":"n.","example":"The soldier returned home after a long deployment.","exampleTranslation":"그 군인은 긴 해외 근무를 마치고 귀국했어요.","category":"빈도 학습","level":11},{"id":11075,"term":"finance","meaning":"재정; 금융","partOfSpeech":"n.","example":"She studied finance and now works at a bank.","exampleTranslation":"그녀는 금융을 전공해서 지금은 은행에서 일해요.","category":"빈도 학습","level":11},{"id":11076,"term":"hate","meaning":"싫어하다; 미워하다","partOfSpeech":"v.","example":"I hate being late, so I always leave early.","exampleTranslation":"저는 늦는 게 너무 싫어서 항상 일찍 출발해요.","category":"빈도 학습","level":11},{"id":11077,"term":"egg","meaning":"달걀; 알","partOfSpeech":"n.","example":"I usually have a boiled egg for breakfast.","exampleTranslation":"저는 보통 아침에 삶은 달걀을 먹어요.","category":"빈도 학습","level":11},{"id":11078,"term":"concert","meaning":"콘서트; 연주회","partOfSpeech":"n.","example":"We got tickets to a live concert downtown next week.","exampleTranslation":"다음 주 시내에서 열리는 콘서트 티켓을 구했어요.","category":"빈도 학습","level":11},{"id":11079,"term":"shock","meaning":"충격; 놀라게 하다","partOfSpeech":"n./v.","example":"The news of his resignation came as a total shock.","exampleTranslation":"그가 사직했다는 소식은 완전한 충격이었어요.","category":"빈도 학습","level":11},{"id":11080,"term":"comfortable","meaning":"편안한; 안락한","partOfSpeech":"adj.","example":"This sofa is so comfortable I could sleep on it.","exampleTranslation":"이 소파는 너무 편안해서 그 위에서 잘 수도 있을 것 같아.","category":"빈도 학습","level":11},{"id":11081,"term":"usual","meaning":"평소의; 보통의","partOfSpeech":"adj.","example":"I woke up later than usual this morning.","exampleTranslation":"오늘 아침에는 평소보다 늦게 일어났어.","category":"빈도 학습","level":11},{"id":11082,"term":"carefully","meaning":"조심스럽게; 신중하게","partOfSpeech":"adv.","example":"Please read the instructions carefully before you start.","exampleTranslation":"시작하기 전에 안내사항을 꼼꼼히 읽어 주세요.","category":"빈도 학습","level":11},{"id":11083,"term":"pack","meaning":"짐을 싸다; 꾸리다","partOfSpeech":"v.","example":"I need to pack my bag before the flight tomorrow.","exampleTranslation":"내일 비행 전에 가방을 싸야 해.","category":"빈도 학습","level":11},{"id":11084,"term":"recall","meaning":"기억해 내다; 떠올리다","partOfSpeech":"v.","example":"I can't recall where I left my keys.","exampleTranslation":"열쇠를 어디에 뒀는지 기억이 안 나.","category":"빈도 학습","level":11},{"id":11085,"term":"wine","meaning":"와인; 포도주","partOfSpeech":"n.","example":"She ordered a glass of red wine with dinner.","exampleTranslation":"그녀는 저녁 식사에 레드 와인 한 잔을 주문했어.","category":"빈도 학습","level":11},{"id":11086,"term":"camera","meaning":"카메라","partOfSpeech":"n.","example":"He forgot to bring his camera to the wedding.","exampleTranslation":"그는 결혼식에 카메라를 가져오는 걸 깜빡했어.","category":"빈도 학습","level":11},{"id":11087,"term":"theater","meaning":"극장; 영화관","partOfSpeech":"n.","example":"The new movie is playing at the theater downtown.","exampleTranslation":"새 영화가 시내 극장에서 상영 중이야.","category":"빈도 학습","level":11},{"id":11088,"term":"cycle","meaning":"순환; 주기","partOfSpeech":"n.","example":"The washing machine is in the middle of its cycle.","exampleTranslation":"세탁기가 지금 작동 중간이야.","category":"빈도 학습","level":11},{"id":11089,"term":"totally","meaning":"완전히; 전혀","partOfSpeech":"adv.","example":"I totally forgot about our meeting this afternoon.","exampleTranslation":"오늘 오후 약속을 완전히 잊어버렸어.","category":"빈도 학습","level":11},{"id":11090,"term":"visitor","meaning":"방문객; 손님","partOfSpeech":"n.","example":"We had a visitor from out of town last weekend.","exampleTranslation":"지난 주말에 다른 도시에서 손님이 왔었어.","category":"빈도 학습","level":11},{"id":11091,"term":"freedom","meaning":"자유","partOfSpeech":"n.","example":"Living alone gives you a lot of freedom.","exampleTranslation":"혼자 사는 건 자유가 많아.","category":"빈도 학습","level":11},{"id":11092,"term":"construction","meaning":"공사; 건설","partOfSpeech":"n.","example":"The road is closed because of construction nearby.","exampleTranslation":"근처에 공사 중이라 도로가 막혔어.","category":"빈도 학습","level":11},{"id":11093,"term":"dear","meaning":"소중한; 친애하는","partOfSpeech":"adj.","example":"She is a dear friend who always listens to me.","exampleTranslation":"그녀는 항상 내 말을 들어주는 소중한 친구야.","category":"빈도 학습","level":11},{"id":11094,"term":"objective","meaning":"목표; 객관적인","partOfSpeech":"n./adj.","example":"My main objective this year is to get fit.","exampleTranslation":"올해 나의 주요 목표는 건강해지는 거야.","category":"빈도 학습","level":11},{"id":11095,"term":"moreover","meaning":"게다가; 더욱이","partOfSpeech":"adv.","example":"The hotel was clean; moreover, the staff were very friendly.","exampleTranslation":"호텔은 깔끔했고, 게다가 직원들도 매우 친절했어.","category":"빈도 학습","level":11},{"id":11096,"term":"historical","meaning":"역사적인; 역사에 관한","partOfSpeech":"adj.","example":"We visited a historical site on our trip to Europe.","exampleTranslation":"유럽 여행 중에 역사적인 유적지를 방문했어.","category":"빈도 학습","level":11},{"id":11097,"term":"oppose","meaning":"반대하다","partOfSpeech":"v.","example":"Many residents oppose the plan to build a new highway.","exampleTranslation":"많은 주민들이 새 고속도로 건설 계획에 반대해.","category":"빈도 학습","level":11},{"id":11098,"term":"vehicle","meaning":"차량; 탈것","partOfSpeech":"n.","example":"You need a permit to park your vehicle here.","exampleTranslation":"여기에 차량을 주차하려면 허가증이 필요해.","category":"빈도 학습","level":11},{"id":11099,"term":"scientist","meaning":"과학자","partOfSpeech":"n.","example":"The scientist announced a major discovery last week.","exampleTranslation":"그 과학자는 지난주에 중요한 발견을 발표했어.","category":"빈도 학습","level":11},{"id":11100,"term":"route","meaning":"경로; 길","partOfSpeech":"n.","example":"The fastest route to the airport is the highway.","exampleTranslation":"공항까지 가장 빠른 경로는 고속도로야.","category":"빈도 학습","level":11},{"id":11101,"term":"bind","meaning":"묶다; 결속시키다","partOfSpeech":"v.","example":"Use a rubber band to bind those papers together.","exampleTranslation":"고무줄로 그 종이들을 묶어 놔.","category":"빈도 학습","level":11},{"id":11102,"term":"belong","meaning":"속하다; ~의 것이다","partOfSpeech":"v.","example":"Does this umbrella belong to you?","exampleTranslation":"이 우산 당신 거예요?","category":"빈도 학습","level":11},{"id":11103,"term":"taste","meaning":"맛; 맛이 나다","partOfSpeech":"n./v.","example":"Can you taste the garlic in this dish?","exampleTranslation":"이 요리에서 마늘 맛 나지 않아?","category":"빈도 학습","level":11},{"id":11104,"term":"tonight","meaning":"오늘 밤","partOfSpeech":"adv.","example":"Are you doing anything special tonight?","exampleTranslation":"오늘 밤에 특별한 일 있어?","category":"빈도 학습","level":11},{"id":11105,"term":"fashion","meaning":"유행; 패션","partOfSpeech":"n.","example":"She keeps up with the latest fashion trends.","exampleTranslation":"그녀는 최신 패션 트렌드를 항상 따라가.","category":"빈도 학습","level":11},{"id":11106,"term":"danger","meaning":"위험","partOfSpeech":"n.","example":"There's a sign warning of danger near the cliff.","exampleTranslation":"절벽 근처에 위험을 경고하는 표지판이 있어.","category":"빈도 학습","level":11},{"id":11107,"term":"bomb","meaning":"폭탄","partOfSpeech":"n.","example":"The police found a bomb near the train station.","exampleTranslation":"경찰이 기차역 근처에서 폭탄을 발견했어.","category":"빈도 학습","level":11},{"id":11108,"term":"army","meaning":"군대; 육군","partOfSpeech":"n.","example":"Her brother joined the army right after high school.","exampleTranslation":"그녀의 남동생은 고등학교를 졸업하자마자 군대에 입대했어.","category":"빈도 학습","level":11},{"id":11109,"term":"dangerous","meaning":"위험한","partOfSpeech":"adj.","example":"It's dangerous to walk alone at night in that area.","exampleTranslation":"그 지역에서 밤에 혼자 걷는 건 위험해.","category":"빈도 학습","level":11},{"id":11110,"term":"decrease","meaning":"감소하다; 줄이다","partOfSpeech":"v.","example":"Sales usually decrease during the winter months.","exampleTranslation":"매출은 보통 겨울철에 줄어들어.","category":"빈도 학습","level":11},{"id":11111,"term":"hurt","meaning":"다치다; 아프다","partOfSpeech":"v.","example":"My back really hurt after sitting all day.","exampleTranslation":"하루 종일 앉아 있었더니 허리가 정말 아팠어.","category":"빈도 학습","level":11},{"id":11112,"term":"council","meaning":"의회; 위원회","partOfSpeech":"n.","example":"The city council voted to approve the new park.","exampleTranslation":"시의회가 새 공원 조성안을 승인하는 표결을 했어.","category":"빈도 학습","level":11},{"id":11113,"term":"editor","meaning":"편집자; 편집장","partOfSpeech":"n.","example":"The editor asked her to shorten the article a bit.","exampleTranslation":"편집장이 그녀에게 기사를 좀 줄여달라고 했어.","category":"빈도 학습","level":11},{"id":11114,"term":"normally","meaning":"보통; 정상적으로","partOfSpeech":"adv.","example":"I normally get up around seven in the morning.","exampleTranslation":"나는 보통 아침 7시쯤 일어나.","category":"빈도 학습","level":11},{"id":11115,"term":"sight","meaning":"시야; 광경","partOfSpeech":"n.","example":"The sunset over the ocean was a beautiful sight.","exampleTranslation":"바다 위로 지는 노을은 정말 아름다운 광경이었어.","category":"빈도 학습","level":11},{"id":11116,"term":"generate","meaning":"만들어 내다; 발생시키다","partOfSpeech":"v.","example":"The event managed to generate a lot of interest online.","exampleTranslation":"그 행사는 온라인에서 많은 관심을 이끌어냈어.","category":"빈도 학습","level":11},{"id":11117,"term":"gift","meaning":"선물; 재능","partOfSpeech":"n.","example":"She bought a small gift for her friend's birthday.","exampleTranslation":"그녀는 친구 생일에 작은 선물을 샀어.","category":"빈도 학습","level":11},{"id":11118,"term":"deny","meaning":"부인하다; 거부하다","partOfSpeech":"v.","example":"He tried to deny eating the last slice of cake.","exampleTranslation":"그는 마지막 케이크 조각을 먹었다는 걸 부인하려 했어.","category":"빈도 학습","level":11},{"id":11119,"term":"guest","meaning":"손님; 초대객","partOfSpeech":"n.","example":"We have a guest staying with us for the weekend.","exampleTranslation":"주말 동안 우리 집에 묵는 손님이 있어.","category":"빈도 학습","level":11},{"id":11120,"term":"anybody","meaning":"누구든지; 아무도","partOfSpeech":"pron.","example":"Is anybody home right now?","exampleTranslation":"지금 집에 누구 있어요?","category":"빈도 학습","level":11},{"id":11121,"term":"bedroom","meaning":"침실","partOfSpeech":"n.","example":"The kids share a bedroom on the second floor.","exampleTranslation":"아이들은 2층 침실을 함께 쓰고 있어요.","category":"빈도 학습","level":11},{"id":11122,"term":"climb","meaning":"오르다; 올라가다","partOfSpeech":"v.","example":"We decided to climb the hill before sunset.","exampleTranslation":"우리는 해 지기 전에 언덕을 오르기로 했어요.","category":"빈도 학습","level":11},{"id":11123,"term":"basically","meaning":"기본적으로; 사실상","partOfSpeech":"adv.","example":"Basically, you just fill out the form and submit it.","exampleTranslation":"기본적으로 양식을 작성해서 제출하면 돼요.","category":"빈도 학습","level":11},{"id":11124,"term":"violence","meaning":"폭력; 난폭함","partOfSpeech":"n.","example":"The film contains scenes of violence.","exampleTranslation":"그 영화에는 폭력적인 장면이 있어요.","category":"빈도 학습","level":11},{"id":11125,"term":"minister","meaning":"장관; 목사","partOfSpeech":"n.","example":"The minister announced a new education policy.","exampleTranslation":"장관이 새로운 교육 정책을 발표했어요.","category":"빈도 학습","level":11},{"id":11126,"term":"mainly","meaning":"주로; 대부분","partOfSpeech":"adv.","example":"I mainly use my phone for messaging and photos.","exampleTranslation":"저는 주로 메시지와 사진용으로 폰을 사용해요.","category":"빈도 학습","level":11},{"id":11127,"term":"mouth","meaning":"입; 입구","partOfSpeech":"n.","example":"Please cover your mouth when you cough.","exampleTranslation":"기침할 때는 입을 가려 주세요.","category":"빈도 학습","level":11},{"id":11128,"term":"noise","meaning":"소음; 잡음","partOfSpeech":"n.","example":"There was so much noise from the street last night.","exampleTranslation":"어젯밤 거리에서 소음이 너무 심했어요.","category":"빈도 학습","level":11},{"id":11129,"term":"manner","meaning":"방식; 태도","partOfSpeech":"n.","example":"She spoke in a very calm and polite manner.","exampleTranslation":"그녀는 매우 차분하고 예의 바른 태도로 말했어요.","category":"빈도 학습","level":11},{"id":11130,"term":"gun","meaning":"총; 권총","partOfSpeech":"n.","example":"The security officer carried a gun on duty.","exampleTranslation":"그 경비원은 근무 중에 총을 지니고 있었어요.","category":"빈도 학습","level":11},{"id":11131,"term":"square","meaning":"광장; 정사각형","partOfSpeech":"n.","example":"Let's meet at the square near the fountain.","exampleTranslation":"분수 근처 광장에서 만나요.","category":"빈도 학습","level":11},{"id":11132,"term":"occasion","meaning":"경우; 특별한 행사","partOfSpeech":"n.","example":"We only use this tablecloth on a special occasion.","exampleTranslation":"우리는 특별한 자리에만 이 식탁보를 사용해요.","category":"빈도 학습","level":11},{"id":11133,"term":"familiar","meaning":"친숙한; 잘 아는","partOfSpeech":"adj.","example":"That song sounds familiar to me.","exampleTranslation":"그 노래가 저한테 익숙하게 들려요.","category":"빈도 학습","level":11},{"id":11134,"term":"ignore","meaning":"무시하다; 못 본 척하다","partOfSpeech":"v.","example":"Don't ignore the warning signs on the road.","exampleTranslation":"도로 위 경고 표지를 무시하지 마세요.","category":"빈도 학습","level":11},{"id":11135,"term":"destroy","meaning":"파괴하다; 망치다","partOfSpeech":"v.","example":"The storm could destroy the crops overnight.","exampleTranslation":"폭풍이 하룻밤 사이에 농작물을 망칠 수도 있어요.","category":"빈도 학습","level":11},{"id":11136,"term":"affair","meaning":"일; 사건; 관계","partOfSpeech":"n.","example":"That's a private affair and none of your business.","exampleTranslation":"그건 사적인 일이라 당신이 관여할 바가 아니에요.","category":"빈도 학습","level":11},{"id":11137,"term":"civil","meaning":"시민의; 민간의; 예의 바른","partOfSpeech":"adj.","example":"They settled the dispute through civil court.","exampleTranslation":"그들은 민사 법원을 통해 분쟁을 해결했어요.","category":"빈도 학습","level":11},{"id":11138,"term":"locate","meaning":"위치를 찾다; ~에 위치하다","partOfSpeech":"v.","example":"Can you locate the nearest pharmacy on the map?","exampleTranslation":"지도에서 가장 가까운 약국을 찾아줄 수 있어요?","category":"빈도 학습","level":11},{"id":11139,"term":"citizen","meaning":"시민; 국민","partOfSpeech":"n.","example":"Every citizen has the right to vote.","exampleTranslation":"모든 시민은 투표할 권리가 있어요.","category":"빈도 학습","level":11},{"id":11140,"term":"temperature","meaning":"온도; 체온","partOfSpeech":"n.","example":"The temperature outside dropped below zero last night.","exampleTranslation":"어젯밤 바깥 온도가 영하로 떨어졌어요.","category":"빈도 학습","level":11},{"id":11141,"term":"gold","meaning":"금; 황금색","partOfSpeech":"n.","example":"She wore a necklace made of gold.","exampleTranslation":"그녀는 금으로 만든 목걸이를 하고 있었어요.","category":"빈도 학습","level":11},{"id":11142,"term":"domestic","meaning":"국내의; 가정의","partOfSpeech":"adj.","example":"We only fly domestic routes for now.","exampleTranslation":"저희는 지금은 국내선만 운항해요.","category":"빈도 학습","level":11},{"id":11143,"term":"load","meaning":"짐; 부담; 싣다","partOfSpeech":"n./v.","example":"The truck was carrying a heavy load of furniture.","exampleTranslation":"트럭은 무거운 가구 짐을 싣고 가고 있었어요.","category":"빈도 학습","level":11},{"id":11144,"term":"belief","meaning":"믿음; 신념","partOfSpeech":"n.","example":"Her belief in hard work never wavered.","exampleTranslation":"열심히 일하면 된다는 그녀의 믿음은 흔들리지 않았어요.","category":"빈도 학습","level":11},{"id":11145,"term":"troop","meaning":"군대; 부대; 무리","partOfSpeech":"n.","example":"A troop of soldiers marched through the town.","exampleTranslation":"군인 부대가 마을을 행진해 지나갔어요.","category":"빈도 학습","level":11},{"id":11146,"term":"technical","meaning":"기술적인; 전문적인","partOfSpeech":"adj.","example":"The manual is full of technical terms I don't understand.","exampleTranslation":"설명서에 제가 이해 못 하는 기술 용어가 가득해요.","category":"빈도 학습","level":11},{"id":11147,"term":"remind","meaning":"상기시키다; 생각나게 하다","partOfSpeech":"v.","example":"Can you remind me to call the dentist tomorrow?","exampleTranslation":"내일 치과에 전화하라고 알려줄 수 있어요?","category":"빈도 학습","level":11},{"id":11148,"term":"arrangement","meaning":"준비; 배열; 협의","partOfSpeech":"n.","example":"We made an arrangement to meet at noon.","exampleTranslation":"우리는 정오에 만나기로 약속을 잡았어요.","category":"빈도 학습","level":11},{"id":11149,"term":"skin","meaning":"피부; 껍질","partOfSpeech":"n.","example":"Apply sunscreen to protect your skin from the sun.","exampleTranslation":"햇볕으로부터 피부를 보호하려면 자외선 차단제를 발라요.","category":"빈도 학습","level":11},{"id":11150,"term":"prison","meaning":"교도소; 감옥","partOfSpeech":"n.","example":"He spent three years in prison for fraud.","exampleTranslation":"그는 사기죄로 교도소에서 3년을 보냈어요.","category":"빈도 학습","level":11},{"id":11151,"term":"switch","meaning":"바꾸다; 스위치","partOfSpeech":"n./v.","example":"I decided to switch to a different phone plan.","exampleTranslation":"저는 다른 휴대폰 요금제로 바꾸기로 했어요.","category":"빈도 학습","level":11},{"id":11152,"term":"fairly","meaning":"꽤; 상당히; 공정하게","partOfSpeech":"adv.","example":"The exam was fairly easy compared to last year.","exampleTranslation":"시험이 작년에 비해 꽤 쉬웠어요.","category":"빈도 학습","level":11},{"id":11153,"term":"wood","meaning":"나무; 목재","partOfSpeech":"n.","example":"This table is made from solid wood.","exampleTranslation":"이 테이블은 단단한 목재로 만들어졌어요.","category":"빈도 학습","level":11},{"id":11154,"term":"participate","meaning":"참가하다; 참여하다","partOfSpeech":"v.","example":"Everyone is welcome to participate in the discussion.","exampleTranslation":"누구든지 토론에 참여하셔도 됩니다.","category":"빈도 학습","level":11},{"id":11155,"term":"tough","meaning":"힘든; 강인한; 질긴","partOfSpeech":"adj.","example":"It was a tough week, but we got through it.","exampleTranslation":"힘든 한 주였지만 우리는 잘 버텨냈어요.","category":"빈도 학습","level":11},{"id":11156,"term":"tear","meaning":"눈물; 찢다","partOfSpeech":"n./v.","example":"She wiped a tear from her cheek.","exampleTranslation":"그녀는 볼에 흐른 눈물을 닦았어요.","category":"빈도 학습","level":11},{"id":11157,"term":"representative","meaning":"대표자; 대리인","partOfSpeech":"n.","example":"Please speak with a customer service representative.","exampleTranslation":"고객 서비스 담당자에게 말씀해 주세요.","category":"빈도 학습","level":11},{"id":11158,"term":"capacity","meaning":"수용력; 능력; 용량","partOfSpeech":"n.","example":"The hall has a capacity of five hundred people.","exampleTranslation":"그 홀은 500명을 수용할 수 있어요.","category":"빈도 학습","level":11},{"id":11159,"term":"shake","meaning":"흔들다; 악수하다","partOfSpeech":"v.","example":"Remember to shake the bottle before pouring.","exampleTranslation":"따르기 전에 병을 흔드는 것 잊지 마세요.","category":"빈도 학습","level":11},{"id":11160,"term":"assessment","meaning":"평가; 사정","partOfSpeech":"n.","example":"The teacher gave a fair assessment of each student's progress.","exampleTranslation":"선생님은 각 학생의 발전 상황을 공정하게 평가했다.","category":"빈도 학습","level":11},{"id":11161,"term":"shoe","meaning":"신발; 구두","partOfSpeech":"n.","example":"She bought a new pair of shoe at the mall yesterday.","exampleTranslation":"그녀는 어제 쇼핑몰에서 새 신발 한 켤레를 샀다.","category":"빈도 학습","level":11},{"id":11162,"term":"ad","meaning":"광고","partOfSpeech":"n.","example":"I saw an ad for that restaurant on social media.","exampleTranslation":"나는 소셜 미디어에서 그 식당 광고를 봤다.","category":"빈도 학습","level":11},{"id":11163,"term":"hall","meaning":"복도; 홀","partOfSpeech":"n.","example":"The kids were running down the hall making lots of noise.","exampleTranslation":"아이들이 복도를 뛰어다니며 시끄럽게 굴었다.","category":"빈도 학습","level":11},{"id":11164,"term":"regulation","meaning":"규정; 규제","partOfSpeech":"n.","example":"The new regulation requires all drivers to wear seatbelts.","exampleTranslation":"새 규정은 모든 운전자가 안전벨트를 착용하도록 요구한다.","category":"빈도 학습","level":11},{"id":11165,"term":"escape","meaning":"탈출하다; 벗어나다","partOfSpeech":"v.","example":"She likes to escape the city on weekends and go hiking.","exampleTranslation":"그녀는 주말에 도시를 벗어나 하이킹하러 가는 것을 좋아한다.","category":"빈도 학습","level":11},{"id":11166,"term":"studio","meaning":"스튜디오; 작업실","partOfSpeech":"n.","example":"He rents a small studio near the university.","exampleTranslation":"그는 대학교 근처에 작은 스튜디오를 임대해 살고 있다.","category":"빈도 학습","level":11},{"id":11167,"term":"proper","meaning":"적절한; 제대로 된","partOfSpeech":"adj.","example":"Make sure you get proper sleep before the interview tomorrow.","exampleTranslation":"내일 면접 전에 제대로 잠을 자도록 해.","category":"빈도 학습","level":11},{"id":11168,"term":"component","meaning":"구성 요소; 부품","partOfSpeech":"n.","example":"Each component of the machine must be checked regularly.","exampleTranslation":"기계의 각 부품은 정기적으로 점검해야 한다.","category":"빈도 학습","level":11},{"id":11169,"term":"afford","meaning":"(돈·시간을) 감당하다; 여유가 있다","partOfSpeech":"v.","example":"I can't afford to eat out every day on my budget.","exampleTranslation":"내 예산으로는 매일 외식할 여유가 없다.","category":"빈도 학습","level":11},{"id":11170,"term":"lawyer","meaning":"변호사","partOfSpeech":"n.","example":"She hired a lawyer to help with the contract.","exampleTranslation":"그녀는 계약서 처리를 돕도록 변호사를 고용했다.","category":"빈도 학습","level":11},{"id":11171,"term":"suspect","meaning":"의심하다; 용의자","partOfSpeech":"v./n.","example":"I suspect the milk has gone bad because it smells odd.","exampleTranslation":"냄새가 이상한 걸 보니 우유가 상한 것 같다.","category":"빈도 학습","level":11},{"id":11172,"term":"cup","meaning":"컵; 한 잔","partOfSpeech":"n.","example":"Can I have a cup of coffee before we start?","exampleTranslation":"시작하기 전에 커피 한 잔 마셔도 될까?","category":"빈도 학습","level":12},{"id":11173,"term":"description","meaning":"설명; 묘사","partOfSpeech":"n.","example":"The job description listed all the tasks involved.","exampleTranslation":"직무 설명서에는 관련된 모든 업무가 나열되어 있었다.","category":"빈도 학습","level":12},{"id":11174,"term":"confidence","meaning":"자신감; 확신","partOfSpeech":"n.","example":"He spoke with confidence during the presentation.","exampleTranslation":"그는 발표 중에 자신감 있게 말했다.","category":"빈도 학습","level":12},{"id":11175,"term":"industrial","meaning":"산업의; 공업의","partOfSpeech":"adj.","example":"The old industrial area has been turned into loft apartments.","exampleTranslation":"오래된 공업 지구가 로프트 아파트로 바뀌었다.","category":"빈도 학습","level":12},{"id":11176,"term":"complain","meaning":"불평하다; 항의하다","partOfSpeech":"v.","example":"He always complain about the food being too salty.","exampleTranslation":"그는 음식이 너무 짜다고 항상 불평한다.","category":"빈도 학습","level":12},{"id":11177,"term":"perspective","meaning":"관점; 시각","partOfSpeech":"n.","example":"Try to see the situation from a different perspective.","exampleTranslation":"다른 관점에서 그 상황을 바라보려고 노력해봐.","category":"빈도 학습","level":12},{"id":11178,"term":"arrest","meaning":"체포하다; 체포","partOfSpeech":"v./n.","example":"The police had to arrest the man for theft.","exampleTranslation":"경찰은 그 남자를 절도 혐의로 체포해야 했다.","category":"빈도 학습","level":12},{"id":11179,"term":"assess","meaning":"평가하다; 가늠하다","partOfSpeech":"v.","example":"The doctor needs to assess your condition before treatment.","exampleTranslation":"의사는 치료 전에 당신의 상태를 평가해야 한다.","category":"빈도 학습","level":12},{"id":11180,"term":"register","meaning":"등록하다; 접수하다","partOfSpeech":"v.","example":"Don't forget to register for the class before it fills up.","exampleTranslation":"자리가 다 차기 전에 수업 등록하는 거 잊지 마.","category":"빈도 학습","level":12},{"id":11181,"term":"asset","meaning":"자산; 강점","partOfSpeech":"n.","example":"Her language skills are a great asset in this job.","exampleTranslation":"그녀의 언어 능력은 이 직업에서 큰 강점이다.","category":"빈도 학습","level":12},{"id":11182,"term":"signal","meaning":"신호; 신호를 보내다","partOfSpeech":"n./v.","example":"The driver gave a signal before turning left.","exampleTranslation":"운전자는 좌회전하기 전에 신호를 보냈다.","category":"빈도 학습","level":12},{"id":11183,"term":"finger","meaning":"손가락","partOfSpeech":"n.","example":"She cut her finger while chopping vegetables.","exampleTranslation":"그녀는 채소를 썰다가 손가락을 베었다.","category":"빈도 학습","level":12},{"id":11184,"term":"relevant","meaning":"관련 있는; 적절한","partOfSpeech":"adj.","example":"Please share only relevant information during the meeting.","exampleTranslation":"회의 중에는 관련 있는 정보만 공유해 주세요.","category":"빈도 학습","level":12},{"id":11185,"term":"explore","meaning":"탐험하다; 살펴보다","partOfSpeech":"v.","example":"We had a whole day to explore the city on our own.","exampleTranslation":"우리는 도시를 자유롭게 탐험할 하루를 통째로 가졌다.","category":"빈도 학습","level":12},{"id":11186,"term":"leadership","meaning":"리더십; 지도력","partOfSpeech":"n.","example":"Her strong leadership helped the team through a tough project.","exampleTranslation":"그녀의 강한 리더십이 팀이 힘든 프로젝트를 헤쳐나가도록 도왔다.","category":"빈도 학습","level":12},{"id":11187,"term":"commitment","meaning":"헌신; 약속","partOfSpeech":"n.","example":"His commitment to the job impressed the whole office.","exampleTranslation":"일에 대한 그의 헌신은 사무실 전체에 깊은 인상을 남겼다.","category":"빈도 학습","level":12},{"id":11188,"term":"wake","meaning":"깨다; 깨우다","partOfSpeech":"v.","example":"I usually wake up at seven even without an alarm.","exampleTranslation":"나는 보통 알람 없이도 일곱 시에 잠에서 깬다.","category":"빈도 학습","level":12},{"id":11189,"term":"necessarily","meaning":"반드시; 필연적으로","partOfSpeech":"adv.","example":"More money doesn't necessarily mean more happiness.","exampleTranslation":"돈이 더 많다고 해서 반드시 더 행복한 것은 아니다.","category":"빈도 학습","level":12},{"id":11190,"term":"bright","meaning":"밝은; 똑똑한","partOfSpeech":"adj.","example":"The kitchen feels much bigger with bright walls.","exampleTranslation":"밝은 벽 덕분에 주방이 훨씬 더 넓어 보인다.","category":"빈도 학습","level":12},{"id":11191,"term":"frame","meaning":"틀; 액자; 짜다","partOfSpeech":"n./v.","example":"She put the photo in a wooden frame on her desk.","exampleTranslation":"그녀는 사진을 나무 액자에 넣어 책상 위에 올려두었다.","category":"빈도 학습","level":12},{"id":11192,"term":"slowly","meaning":"천천히; 서서히","partOfSpeech":"adv.","example":"The traffic was moving slowly due to the accident ahead.","exampleTranslation":"앞쪽 사고 때문에 차들이 천천히 움직이고 있었다.","category":"빈도 학습","level":12},{"id":11193,"term":"bond","meaning":"유대; 결속; 채권","partOfSpeech":"n.","example":"Traveling together really strengthened our bond as friends.","exampleTranslation":"함께 여행을 하면서 친구로서의 유대가 정말 강해졌다.","category":"빈도 학습","level":12},{"id":11194,"term":"hole","meaning":"구멍","partOfSpeech":"n.","example":"There's a hole in my jacket pocket and I keep losing coins.","exampleTranslation":"재킷 주머니에 구멍이 있어서 계속 동전을 잃어버리고 있다.","category":"빈도 학습","level":12},{"id":11195,"term":"tie","meaning":"묶다; 넥타이; 동점","partOfSpeech":"v./n.","example":"Can you help me tie this knot? I can't get it right.","exampleTranslation":"이 매듭 묶는 것 좀 도와줄 수 있어? 잘 안 돼.","category":"빈도 학습","level":12},{"id":11196,"term":"internal","meaning":"내부의; 내적인","partOfSpeech":"adj.","example":"The company sent an internal memo about the new policy.","exampleTranslation":"회사는 새 정책에 관한 내부 공문을 발송했다.","category":"빈도 학습","level":12},{"id":11197,"term":"chain","meaning":"체인; 연결; 묶다","partOfSpeech":"n./v.","example":"That coffee shop is part of a chain with locations across the country.","exampleTranslation":"그 커피숍은 전국 각지에 매장이 있는 체인점이다.","category":"빈도 학습","level":12},{"id":11198,"term":"literature","meaning":"문학; 문헌","partOfSpeech":"n.","example":"She grew up loving literature and now writes her own stories.","exampleTranslation":"그녀는 문학을 사랑하며 자랐고 지금은 직접 이야기를 쓴다.","category":"빈도 학습","level":12},{"id":11199,"term":"victim","meaning":"피해자; 희생자","partOfSpeech":"n.","example":"The charity supports victim of natural disasters worldwide.","exampleTranslation":"그 자선단체는 전 세계 자연재해 피해자들을 지원한다.","category":"빈도 학습","level":12},{"id":11200,"term":"threaten","meaning":"위협하다; 협박하다","partOfSpeech":"v.","example":"Don't threaten me or I'll call the police.","exampleTranslation":"나를 협박하면 경찰을 부를 거야.","category":"빈도 학습","level":12},{"id":11201,"term":"division","meaning":"분할; 부서","partOfSpeech":"n.","example":"There is a clear division between the two teams.","exampleTranslation":"두 팀 사이에는 명확한 구분이 있다.","category":"빈도 학습","level":12},{"id":11202,"term":"secure","meaning":"안전한; 확보하다","partOfSpeech":"adj./v.","example":"Make sure the door is secure before you leave.","exampleTranslation":"나가기 전에 문이 잘 잠겼는지 확인해.","category":"빈도 학습","level":12},{"id":11203,"term":"amaze","meaning":"놀라게 하다; 깜짝 놀라게 하다","partOfSpeech":"v.","example":"The view from the top never fails to amaze me.","exampleTranslation":"꼭대기에서 보이는 경치는 항상 나를 놀라게 한다.","category":"빈도 학습","level":12},{"id":11204,"term":"device","meaning":"기기; 장치","partOfSpeech":"n.","example":"Don't forget to charge your device before the trip.","exampleTranslation":"여행 전에 기기 충전하는 것 잊지 마.","category":"빈도 학습","level":12},{"id":11205,"term":"birth","meaning":"탄생; 출생","partOfSpeech":"n.","example":"She registered the birth at the local office.","exampleTranslation":"그녀는 지역 사무소에 출생 신고를 했다.","category":"빈도 학습","level":12},{"id":11206,"term":"forest","meaning":"숲; 산림","partOfSpeech":"n.","example":"We went for a long walk in the forest.","exampleTranslation":"우리는 숲속에서 오래 산책했다.","category":"빈도 학습","level":12},{"id":11207,"term":"label","meaning":"라벨; 꼬리표; 표시하다","partOfSpeech":"n./v.","example":"Check the label for the washing instructions.","exampleTranslation":"세탁 방법은 라벨을 확인해 봐.","category":"빈도 학습","level":12},{"id":11208,"term":"root","meaning":"뿌리; 근원","partOfSpeech":"n.","example":"The root of the problem was poor communication.","exampleTranslation":"문제의 근원은 소통 부재였다.","category":"빈도 학습","level":12},{"id":11209,"term":"factory","meaning":"공장","partOfSpeech":"n.","example":"My uncle works at a car factory nearby.","exampleTranslation":"삼촌은 근처 자동차 공장에서 일한다.","category":"빈도 학습","level":12},{"id":11210,"term":"channel","meaning":"채널; 수로; 경로","partOfSpeech":"n.","example":"Switch to a different channel if you're bored.","exampleTranslation":"지루하면 다른 채널로 돌려봐.","category":"빈도 학습","level":12},{"id":11211,"term":"investigate","meaning":"조사하다; 수사하다","partOfSpeech":"v.","example":"The police are going to investigate the incident.","exampleTranslation":"경찰이 그 사건을 수사할 예정이다.","category":"빈도 학습","level":12},{"id":11212,"term":"recommendation","meaning":"추천; 권고","partOfSpeech":"n.","example":"Do you have any restaurant recommendation for tonight?","exampleTranslation":"오늘 저녁에 추천해 줄 식당 있어?","category":"빈도 학습","level":12},{"id":11213,"term":"rank","meaning":"순위; 등급; 순위를 매기다","partOfSpeech":"n./v.","example":"She got the top rank in her class this year.","exampleTranslation":"그녀는 올해 반에서 1등을 차지했다.","category":"빈도 학습","level":12},{"id":11214,"term":"typical","meaning":"전형적인; 보통의","partOfSpeech":"adj.","example":"A typical day for me starts with coffee.","exampleTranslation":"나의 평범한 하루는 커피로 시작된다.","category":"빈도 학습","level":12},{"id":11215,"term":"west","meaning":"서쪽; 서부","partOfSpeech":"n.","example":"The sun sets in the west every evening.","exampleTranslation":"해는 매일 저녁 서쪽으로 진다.","category":"빈도 학습","level":12},{"id":11216,"term":"friendly","meaning":"친절한; 다정한","partOfSpeech":"adj.","example":"Everyone at the office was so friendly to me.","exampleTranslation":"사무실 사람들이 모두 나에게 정말 친절했다.","category":"빈도 학습","level":12},{"id":11217,"term":"resident","meaning":"주민; 거주자","partOfSpeech":"n.","example":"Local resident complained about the noise at night.","exampleTranslation":"지역 주민이 밤 소음에 대해 항의했다.","category":"빈도 학습","level":12},{"id":11218,"term":"provision","meaning":"공급; 대비; 조항","partOfSpeech":"n.","example":"The contract has a provision for early termination.","exampleTranslation":"계약서에는 조기 해지에 관한 조항이 있다.","category":"빈도 학습","level":12},{"id":11219,"term":"concentrate","meaning":"집중하다; 모으다","partOfSpeech":"v.","example":"I can't concentrate when the TV is on.","exampleTranslation":"TV가 켜져 있으면 집중이 안 된다.","category":"빈도 학습","level":12},{"id":11220,"term":"plenty","meaning":"충분히; 많음","partOfSpeech":"n.","example":"There's plenty of food left, so help yourself.","exampleTranslation":"음식이 충분히 남아 있으니 마음껏 먹어.","category":"빈도 학습","level":12},{"id":11221,"term":"export","meaning":"수출하다; 수출","partOfSpeech":"v./n.","example":"Korea continues to export cars to many countries.","exampleTranslation":"한국은 여러 나라에 자동차를 계속 수출한다.","category":"빈도 학습","level":12},{"id":11222,"term":"entirely","meaning":"완전히; 전적으로","partOfSpeech":"adv.","example":"I entirely agree with what you just said.","exampleTranslation":"방금 한 말에 전적으로 동의해.","category":"빈도 학습","level":12},{"id":11223,"term":"strongly","meaning":"강하게; 강력히","partOfSpeech":"adv.","example":"I strongly suggest you see a doctor soon.","exampleTranslation":"빨리 병원에 가 보길 강력히 권해.","category":"빈도 학습","level":12},{"id":11224,"term":"bridge","meaning":"다리; 이어주다","partOfSpeech":"n./v.","example":"We crossed the old bridge to reach the village.","exampleTranslation":"우리는 오래된 다리를 건너 마을에 도착했다.","category":"빈도 학습","level":12},{"id":11225,"term":"consist","meaning":"구성되다; 이루어지다","partOfSpeech":"v.","example":"The team consist of five experienced members.","exampleTranslation":"그 팀은 경험 많은 다섯 명으로 구성되어 있다.","category":"빈도 학습","level":12},{"id":11226,"term":"graduate","meaning":"졸업하다; 졸업생","partOfSpeech":"v./n.","example":"She plans to graduate next spring.","exampleTranslation":"그녀는 내년 봄에 졸업할 계획이다.","category":"빈도 학습","level":12},{"id":11227,"term":"brand","meaning":"브랜드; 상표","partOfSpeech":"n.","example":"What brand of sneakers are you wearing?","exampleTranslation":"어떤 브랜드 운동화 신고 있어?","category":"빈도 학습","level":12},{"id":11228,"term":"moral","meaning":"도덕적인; 교훈","partOfSpeech":"adj./n.","example":"It's a moral duty to help people in need.","exampleTranslation":"어려운 사람을 돕는 건 도덕적 의무다.","category":"빈도 학습","level":12},{"id":11229,"term":"insist","meaning":"주장하다; 고집하다","partOfSpeech":"v.","example":"She insist on paying for the whole meal.","exampleTranslation":"그녀는 식사비 전부를 내겠다고 고집했다.","category":"빈도 학습","level":12},{"id":11230,"term":"combination","meaning":"조합; 결합","partOfSpeech":"n.","example":"That color combination really works well together.","exampleTranslation":"그 색 조합은 정말 잘 어울린다.","category":"빈도 학습","level":12},{"id":11231,"term":"abuse","meaning":"남용; 학대; 남용하다","partOfSpeech":"n./v.","example":"Don't abuse your position to get special favors.","exampleTranslation":"특혜를 받으려고 지위를 남용하지 마.","category":"빈도 학습","level":12},{"id":11232,"term":"ice","meaning":"얼음","partOfSpeech":"n.","example":"Can you put some ice in my drink, please?","exampleTranslation":"제 음료에 얼음 좀 넣어 줄 수 있어요?","category":"빈도 학습","level":12},{"id":11233,"term":"principal","meaning":"주요한; 교장","partOfSpeech":"adj./n.","example":"The principal reason we moved was the rent.","exampleTranslation":"우리가 이사한 주된 이유는 집세 때문이었다.","category":"빈도 학습","level":12},{"id":11234,"term":"master","meaning":"숙달하다; 달인; 주인","partOfSpeech":"v./n.","example":"It takes time to master a new language.","exampleTranslation":"새 언어를 숙달하는 데는 시간이 걸린다.","category":"빈도 학습","level":12},{"id":11235,"term":"definitely","meaning":"확실히; 분명히","partOfSpeech":"adv.","example":"I'll definitely be there by seven.","exampleTranslation":"일곱 시까지 반드시 거기 갈게.","category":"빈도 학습","level":12},{"id":11236,"term":"session","meaning":"시간; 수업; 회의","partOfSpeech":"n.","example":"Our training session starts at nine tomorrow.","exampleTranslation":"우리 훈련 수업은 내일 아홉 시에 시작해.","category":"빈도 학습","level":12},{"id":11237,"term":"grade","meaning":"학년; 등급; 성적","partOfSpeech":"n.","example":"She got an A grade on her final exam.","exampleTranslation":"그녀는 기말고사에서 A 점수를 받았다.","category":"빈도 학습","level":12},{"id":11238,"term":"nevertheless","meaning":"그럼에도 불구하고; 그래도","partOfSpeech":"adv.","example":"It was raining, nevertheless we went for a walk.","exampleTranslation":"비가 왔지만 그래도 우리는 산책을 나갔다.","category":"빈도 학습","level":12},{"id":11239,"term":"predict","meaning":"예측하다; 예언하다","partOfSpeech":"v.","example":"Nobody can predict exactly what will happen next.","exampleTranslation":"다음에 무슨 일이 일어날지 아무도 정확히 예측할 수 없다.","category":"빈도 학습","level":12},{"id":11240,"term":"previously","meaning":"이전에; 예전에","partOfSpeech":"adv.","example":"I previously lived in Seoul before moving here.","exampleTranslation":"나는 여기로 이사 오기 전에 서울에 살았어요.","category":"빈도 학습","level":12},{"id":11241,"term":"protection","meaning":"보호; 보호 장치","partOfSpeech":"n.","example":"You should wear sunscreen for protection from UV rays.","exampleTranslation":"자외선 보호를 위해 선크림을 바르는 게 좋아요.","category":"빈도 학습","level":12},{"id":11242,"term":"largely","meaning":"대체로; 주로","partOfSpeech":"adv.","example":"The project was largely finished by Friday.","exampleTranslation":"그 프로젝트는 금요일까지 대체로 마무리됐어요.","category":"빈도 학습","level":12},{"id":11243,"term":"wed","meaning":"결혼하다","partOfSpeech":"v.","example":"They plan to wed next spring in a small ceremony.","exampleTranslation":"그들은 내년 봄에 소규모 예식으로 결혼할 계획이에요.","category":"빈도 학습","level":12},{"id":11244,"term":"shot","meaning":"주사; 촬영; 시도","partOfSpeech":"n.","example":"The nurse gave me a shot in the arm.","exampleTranslation":"간호사가 제 팔에 주사를 놓았어요.","category":"빈도 학습","level":12},{"id":11245,"term":"appearance","meaning":"외모; 모습; 출연","partOfSpeech":"n.","example":"His appearance changed a lot after the haircut.","exampleTranslation":"그는 머리를 자르고 나서 모습이 많이 바뀌었어요.","category":"빈도 학습","level":12},{"id":11246,"term":"reasonable","meaning":"합리적인; 적당한","partOfSpeech":"adj.","example":"The hotel price was very reasonable for a city center location.","exampleTranslation":"도심에 위치치고는 호텔 가격이 꽤 적당했어요.","category":"빈도 학습","level":12},{"id":11247,"term":"guarantee","meaning":"보증하다; 보장","partOfSpeech":"n./v.","example":"This product comes with a two-year guarantee.","exampleTranslation":"이 제품은 2년 품질 보증이 포함돼 있어요.","category":"빈도 학습","level":12},{"id":11248,"term":"till","meaning":"~까지; ~때까지","partOfSpeech":"prep.","example":"Let's wait here till the rain stops.","exampleTranslation":"비가 그칠 때까지 여기서 기다려요.","category":"빈도 학습","level":12},{"id":11249,"term":"theme","meaning":"주제; 테마","partOfSpeech":"n.","example":"The party has a beach theme this year.","exampleTranslation":"올해 파티 테마는 해변이에요.","category":"빈도 학습","level":12},{"id":11250,"term":"judgment","meaning":"판단; 판결","partOfSpeech":"n.","example":"Trust your own judgment when making big decisions.","exampleTranslation":"큰 결정을 내릴 때는 본인의 판단을 믿으세요.","category":"빈도 학습","level":12},{"id":11251,"term":"odd","meaning":"이상한; 홀수의","partOfSpeech":"adj.","example":"It was odd that no one answered the door.","exampleTranslation":"아무도 문을 열어주지 않은 게 이상했어요.","category":"빈도 학습","level":12},{"id":11252,"term":"loan","meaning":"대출; 빌려줌","partOfSpeech":"n.","example":"She took out a loan to buy a new car.","exampleTranslation":"그녀는 새 차를 사기 위해 대출을 받았어요.","category":"빈도 학습","level":12},{"id":11253,"term":"definition","meaning":"정의; 뜻풀이","partOfSpeech":"n.","example":"Look up the definition of that word in the dictionary.","exampleTranslation":"사전에서 그 단어의 뜻을 찾아보세요.","category":"빈도 학습","level":12},{"id":11254,"term":"elect","meaning":"선출하다; 선택하다","partOfSpeech":"v.","example":"The members will elect a new president next month.","exampleTranslation":"회원들이 다음 달에 새 회장을 선출할 거예요.","category":"빈도 학습","level":12},{"id":11255,"term":"atmosphere","meaning":"분위기; 대기","partOfSpeech":"n.","example":"The restaurant had a very cozy atmosphere.","exampleTranslation":"그 식당은 분위기가 아주 아늑했어요.","category":"빈도 학습","level":12},{"id":11256,"term":"farmer","meaning":"농부; 농장주","partOfSpeech":"n.","example":"The farmer woke up early to tend the crops.","exampleTranslation":"농부는 작물을 돌보기 위해 일찍 일어났어요.","category":"빈도 학습","level":12},{"id":11257,"term":"comparison","meaning":"비교; 대조","partOfSpeech":"n.","example":"In comparison with last year, sales have improved a lot.","exampleTranslation":"작년과 비교하면 매출이 많이 올랐어요.","category":"빈도 학습","level":12},{"id":11258,"term":"characteristic","meaning":"특성; 특징적인","partOfSpeech":"n.","example":"Honesty is her most admirable characteristic.","exampleTranslation":"정직함은 그녀의 가장 존경스러운 특성이에요.","category":"빈도 학습","level":12},{"id":11259,"term":"license","meaning":"면허(증); 허가","partOfSpeech":"n.","example":"You need a valid license to drive on public roads.","exampleTranslation":"공도에서 운전하려면 유효한 면허증이 필요해요.","category":"빈도 학습","level":12},{"id":11260,"term":"rely","meaning":"의존하다; 믿다","partOfSpeech":"v.","example":"You can always rely on her to keep a secret.","exampleTranslation":"비밀을 지키는 건 그녀를 항상 믿어도 돼요.","category":"빈도 학습","level":12},{"id":11261,"term":"narrow","meaning":"좁은; 좁히다","partOfSpeech":"adj.","example":"The alley was too narrow for two people to pass side by side.","exampleTranslation":"그 골목은 두 사람이 나란히 지나가기엔 너무 좁았어요.","category":"빈도 학습","level":12},{"id":11262,"term":"succeed","meaning":"성공하다; 뒤를 잇다","partOfSpeech":"v.","example":"If you work hard, you will succeed eventually.","exampleTranslation":"열심히 하면 결국 성공할 거예요.","category":"빈도 학습","level":12},{"id":11263,"term":"identity","meaning":"정체성; 신원","partOfSpeech":"n.","example":"Please show your identity card at the front desk.","exampleTranslation":"안내 데스크에서 신분증을 제시해 주세요.","category":"빈도 학습","level":12},{"id":11264,"term":"desk","meaning":"책상; 안내 데스크","partOfSpeech":"n.","example":"She keeps her desk very neat and organized.","exampleTranslation":"그녀는 책상을 항상 깔끔하게 정리해 둬요.","category":"빈도 학습","level":12},{"id":11265,"term":"seriously","meaning":"진지하게; 심각하게","partOfSpeech":"adv.","example":"You should seriously consider taking a break.","exampleTranslation":"잠깐 쉬는 것을 진지하게 고려해 보세요.","category":"빈도 학습","level":12},{"id":11266,"term":"wild","meaning":"야생의; 거친; 흥분한","partOfSpeech":"adj.","example":"We spotted a wild deer on our morning hike.","exampleTranslation":"아침 등산 중에 야생 사슴을 발견했어요.","category":"빈도 학습","level":12},{"id":11267,"term":"empty","meaning":"비어 있는; 비우다","partOfSpeech":"adj.","example":"The fridge is empty — we need to go shopping.","exampleTranslation":"냉장고가 텅 비었어요 — 장을 보러 가야 해요.","category":"빈도 학습","level":12},{"id":11268,"term":"commission","meaning":"수수료; 위원회; 위임하다","partOfSpeech":"n.","example":"The agent earns a commission on every sale.","exampleTranslation":"그 중개인은 판매 건마다 수수료를 받아요.","category":"빈도 학습","level":12},{"id":11269,"term":"unique","meaning":"독특한; 유일한","partOfSpeech":"adj.","example":"Each person has a unique fingerprint.","exampleTranslation":"사람마다 고유한 지문이 있어요.","category":"빈도 학습","level":12},{"id":11270,"term":"association","meaning":"협회; 연관; 연상","partOfSpeech":"n.","example":"She joined the local teachers association last year.","exampleTranslation":"그녀는 작년에 지역 교사 협회에 가입했어요.","category":"빈도 학습","level":12},{"id":11271,"term":"instrument","meaning":"악기; 도구; 기기","partOfSpeech":"n.","example":"What instrument do you play?","exampleTranslation":"어떤 악기를 연주하세요?","category":"빈도 학습","level":12},{"id":11272,"term":"investor","meaning":"투자자","partOfSpeech":"n.","example":"The startup attracted several investor meetings this week.","exampleTranslation":"그 스타트업은 이번 주에 여러 투자자 미팅을 유치했어요.","category":"빈도 학습","level":12},{"id":11273,"term":"practical","meaning":"실용적인; 현실적인","partOfSpeech":"adj.","example":"A backpack is more practical than a suitcase for day trips.","exampleTranslation":"당일치기 여행에는 캐리어보다 배낭이 더 실용적이에요.","category":"빈도 학습","level":12},{"id":11274,"term":"lovely","meaning":"사랑스러운; 아름다운","partOfSpeech":"adj.","example":"What a lovely view from the balcony!","exampleTranslation":"발코니에서 보이는 경치가 정말 아름다워요!","category":"빈도 학습","level":12},{"id":11275,"term":"soft","meaning":"부드러운; 연한","partOfSpeech":"adj.","example":"The baby's skin is incredibly soft.","exampleTranslation":"아기 피부가 믿을 수 없을 만큼 부드러워요.","category":"빈도 학습","level":12},{"id":11276,"term":"row","meaning":"줄; 열; 노를 젓다","partOfSpeech":"n.","example":"We sat in the front row at the concert.","exampleTranslation":"우리는 콘서트에서 맨 앞줄에 앉았어요.","category":"빈도 학습","level":12},{"id":11277,"term":"youth","meaning":"청소년; 젊음","partOfSpeech":"n.","example":"The youth of today are very comfortable with technology.","exampleTranslation":"요즘 청소년들은 기술에 매우 익숙해요.","category":"빈도 학습","level":12},{"id":11278,"term":"lock","meaning":"잠그다; 자물쇠","partOfSpeech":"n./v.","example":"Make sure to lock the door before you leave.","exampleTranslation":"나가기 전에 반드시 문을 잠그세요.","category":"빈도 학습","level":12},{"id":11279,"term":"fuel","meaning":"연료; 부채질하다","partOfSpeech":"n.","example":"We need to stop for fuel before the highway.","exampleTranslation":"고속도로 타기 전에 연료를 넣으러 들러야 해요.","category":"빈도 학습","level":13},{"id":11280,"term":"expectation","meaning":"기대; 예상","partOfSpeech":"n.","example":"The new restaurant exceeded everyone's expectation.","exampleTranslation":"그 새 식당은 모두의 기대를 뛰어넘었다.","category":"빈도 학습","level":13},{"id":11281,"term":"employment","meaning":"고용; 취업","partOfSpeech":"n.","example":"She found employment at a local hospital.","exampleTranslation":"그녀는 지역 병원에 취업했다.","category":"빈도 학습","level":13},{"id":11282,"term":"celebrate","meaning":"축하하다; 기념하다","partOfSpeech":"v.","example":"Let's celebrate your promotion with dinner tonight.","exampleTranslation":"오늘 저녁 식사로 네 승진을 축하하자.","category":"빈도 학습","level":13},{"id":11283,"term":"sexual","meaning":"성적인; 성(性)에 관한","partOfSpeech":"adj.","example":"The company has a strict sexual harassment policy.","exampleTranslation":"그 회사는 엄격한 성희롱 방지 정책을 갖고 있다.","category":"빈도 학습","level":13},{"id":11284,"term":"shoulder","meaning":"어깨; (책임을) 떠맡다","partOfSpeech":"n./v.","example":"My shoulder has been sore since yesterday.","exampleTranslation":"어제부터 어깨가 아프다.","category":"빈도 학습","level":13},{"id":11285,"term":"breath","meaning":"숨; 호흡","partOfSpeech":"n.","example":"Take a deep breath before you speak.","exampleTranslation":"말하기 전에 깊게 숨을 들이쉬어.","category":"빈도 학습","level":13},{"id":11286,"term":"increasingly","meaning":"점점 더; 갈수록","partOfSpeech":"adv.","example":"Remote work has become increasingly common these days.","exampleTranslation":"요즘 재택근무가 점점 더 흔해지고 있다.","category":"빈도 학습","level":13},{"id":11287,"term":"import","meaning":"수입하다; 수입품","partOfSpeech":"v./n.","example":"We import fresh fruit from South America every week.","exampleTranslation":"우리는 매주 남아메리카에서 신선한 과일을 수입한다.","category":"빈도 학습","level":13},{"id":11288,"term":"bottle","meaning":"병; 병에 담다","partOfSpeech":"n.","example":"Can you grab a bottle of water from the fridge?","exampleTranslation":"냉장고에서 물 한 병 꺼내줄 수 있어?","category":"빈도 학습","level":13},{"id":11289,"term":"sheet","meaning":"시트; 종이 한 장","partOfSpeech":"n.","example":"Please print the form on a single sheet of paper.","exampleTranslation":"양식을 종이 한 장에 인쇄해 주세요.","category":"빈도 학습","level":13},{"id":11290,"term":"engine","meaning":"엔진; 기관","partOfSpeech":"n.","example":"The engine made a strange noise on the highway.","exampleTranslation":"고속도로에서 엔진이 이상한 소리를 냈다.","category":"빈도 학습","level":13},{"id":11291,"term":"cast","meaning":"던지다; (빛·그림자를) 드리우다; 출연진","partOfSpeech":"v./n.","example":"The tree cast a long shadow across the garden.","exampleTranslation":"나무가 정원을 가로질러 긴 그림자를 드리웠다.","category":"빈도 학습","level":13},{"id":11292,"term":"notion","meaning":"생각; 개념","partOfSpeech":"n.","example":"I have no notion of where he went.","exampleTranslation":"그가 어디 갔는지 전혀 모르겠다.","category":"빈도 학습","level":13},{"id":11293,"term":"conservative","meaning":"보수적인; 신중한","partOfSpeech":"adj.","example":"My grandmother has very conservative views on fashion.","exampleTranslation":"할머니는 패션에 대해 매우 보수적인 생각을 갖고 계신다.","category":"빈도 학습","level":13},{"id":11294,"term":"journey","meaning":"여정; 여행","partOfSpeech":"n.","example":"The journey from Seoul to Busan took about three hours.","exampleTranslation":"서울에서 부산까지 여정이 약 세 시간 걸렸다.","category":"빈도 학습","level":13},{"id":11295,"term":"opposition","meaning":"반대; 저항","partOfSpeech":"n.","example":"There was strong opposition to the new parking rules.","exampleTranslation":"새 주차 규칙에 강한 반대가 있었다.","category":"빈도 학습","level":13},{"id":11296,"term":"relief","meaning":"안도; 안심","partOfSpeech":"n.","example":"It was a huge relief when the test results came back negative.","exampleTranslation":"검사 결과가 음성으로 나왔을 때 크게 안도했다.","category":"빈도 학습","level":13},{"id":11297,"term":"debt","meaning":"빚; 부채","partOfSpeech":"n.","example":"He worked extra shifts to pay off his debt.","exampleTranslation":"그는 빚을 갚기 위해 추가 근무를 했다.","category":"빈도 학습","level":13},{"id":11298,"term":"honor","meaning":"명예; 영광; 존중하다","partOfSpeech":"n./v.","example":"It's a great honor to receive this award.","exampleTranslation":"이 상을 받게 되어 큰 영광입니다.","category":"빈도 학습","level":13},{"id":11299,"term":"outcome","meaning":"결과; 성과","partOfSpeech":"n.","example":"We're still waiting for the outcome of the meeting.","exampleTranslation":"우리는 아직 회의 결과를 기다리고 있다.","category":"빈도 학습","level":13},{"id":11300,"term":"blame","meaning":"탓하다; 비난하다","partOfSpeech":"v./n.","example":"Don't blame me for the traffic — we left on time.","exampleTranslation":"교통 체증은 내 탓 하지 마 — 우리 제시간에 출발했잖아.","category":"빈도 학습","level":13},{"id":11301,"term":"explanation","meaning":"설명; 해명","partOfSpeech":"n.","example":"He gave a clear explanation of the new schedule.","exampleTranslation":"그는 새 일정에 대해 명확한 설명을 해주었다.","category":"빈도 학습","level":13},{"id":11302,"term":"arise","meaning":"생기다; 발생하다","partOfSpeech":"v.","example":"Problems can arise if you skip the instructions.","exampleTranslation":"설명서를 건너뛰면 문제가 생길 수 있다.","category":"빈도 학습","level":13},{"id":11303,"term":"musical","meaning":"음악적인; 뮤지컬","partOfSpeech":"adj./n.","example":"She comes from a very musical family.","exampleTranslation":"그녀는 음악적 재능이 넘치는 가족 출신이다.","category":"빈도 학습","level":13},{"id":11304,"term":"dad","meaning":"아빠; 아버지","partOfSpeech":"n.","example":"My dad taught me how to ride a bike.","exampleTranslation":"아빠가 나에게 자전거 타는 법을 가르쳐 주셨다.","category":"빈도 학습","level":13},{"id":11305,"term":"declare","meaning":"선언하다; 신고하다","partOfSpeech":"v.","example":"You must declare any food items at customs.","exampleTranslation":"세관에서 식품류는 반드시 신고해야 한다.","category":"빈도 학습","level":13},{"id":11306,"term":"retire","meaning":"은퇴하다; 퇴직하다","partOfSpeech":"v.","example":"My uncle plans to retire next spring.","exampleTranslation":"삼촌은 내년 봄에 은퇴할 계획이다.","category":"빈도 학습","level":13},{"id":11307,"term":"tiny","meaning":"아주 작은; 조그마한","partOfSpeech":"adj.","example":"There's a tiny crack in the phone screen.","exampleTranslation":"휴대폰 화면에 아주 작은 금이 가 있다.","category":"빈도 학습","level":13},{"id":11308,"term":"careful","meaning":"조심스러운; 신중한","partOfSpeech":"adj.","example":"Be careful when you cross the street.","exampleTranslation":"길을 건널 때 조심해.","category":"빈도 학습","level":13},{"id":11309,"term":"suitable","meaning":"적합한; 알맞은","partOfSpeech":"adj.","example":"This jacket isn't suitable for cold weather.","exampleTranslation":"이 재킷은 추운 날씨에 적합하지 않다.","category":"빈도 학습","level":13},{"id":11310,"term":"native","meaning":"원래의; 태생의; 원주민","partOfSpeech":"adj./n.","example":"She's a native speaker of Spanish.","exampleTranslation":"그녀는 스페인어 원어민이다.","category":"빈도 학습","level":13},{"id":11311,"term":"analyze","meaning":"분석하다","partOfSpeech":"v.","example":"We need to analyze the customer feedback carefully.","exampleTranslation":"고객 피드백을 꼼꼼히 분석해야 한다.","category":"빈도 학습","level":13},{"id":11312,"term":"witness","meaning":"목격자; 목격하다","partOfSpeech":"n./v.","example":"She was the only witness to the accident.","exampleTranslation":"그녀는 그 사고의 유일한 목격자였다.","category":"빈도 학습","level":13},{"id":11313,"term":"mail","meaning":"우편; 이메일; 우송하다","partOfSpeech":"n./v.","example":"I got some mail from the bank this morning.","exampleTranslation":"오늘 아침에 은행에서 우편물이 왔다.","category":"빈도 학습","level":13},{"id":11314,"term":"terrible","meaning":"끔찍한; 형편없는","partOfSpeech":"adj.","example":"I had a terrible headache all day.","exampleTranslation":"하루 종일 두통이 끔찍했다.","category":"빈도 학습","level":13},{"id":11315,"term":"researcher","meaning":"연구자; 연구원","partOfSpeech":"n.","example":"The researcher published her findings last month.","exampleTranslation":"그 연구원은 지난달 자신의 연구 결과를 발표했다.","category":"빈도 학습","level":13},{"id":11316,"term":"ordinary","meaning":"평범한; 보통의","partOfSpeech":"adj.","example":"It was just an ordinary Monday morning.","exampleTranslation":"그냥 평범한 월요일 아침이었다.","category":"빈도 학습","level":13},{"id":11317,"term":"selection","meaning":"선택; 선발","partOfSpeech":"n.","example":"The bakery had a wide selection of pastries.","exampleTranslation":"그 빵집에는 다양한 종류의 패스트리가 있었다.","category":"빈도 학습","level":13},{"id":11318,"term":"anywhere","meaning":"어디서든; 어디에도","partOfSpeech":"adv.","example":"You can sit anywhere you like.","exampleTranslation":"원하는 곳 어디든 앉아도 돼.","category":"빈도 학습","level":13},{"id":11319,"term":"mental","meaning":"정신적인; 마음의","partOfSpeech":"adj.","example":"Taking breaks is important for your mental health.","exampleTranslation":"휴식을 취하는 것은 정신 건강에 중요하다.","category":"빈도 학습","level":13},{"id":11320,"term":"participant","meaning":"참가자; 참여자","partOfSpeech":"n.","example":"Every participant received a certificate at the end of the workshop.","exampleTranslation":"모든 참가자는 워크숍 마지막에 수료증을 받았다.","category":"빈도 학습","level":13},{"id":11321,"term":"vision","meaning":"시력; 비전; 상상","partOfSpeech":"n.","example":"She has excellent vision and never needed glasses.","exampleTranslation":"그녀는 시력이 아주 좋아서 안경이 필요 없었다.","category":"빈도 학습","level":13},{"id":11322,"term":"personality","meaning":"성격; 개성","partOfSpeech":"n.","example":"His warm personality makes everyone feel comfortable around him.","exampleTranslation":"그의 따뜻한 성격 덕분에 주변 사람들이 편안함을 느낀다.","category":"빈도 학습","level":13},{"id":11323,"term":"specifically","meaning":"구체적으로; 특히","partOfSpeech":"adv.","example":"She specifically asked for a window seat on the flight.","exampleTranslation":"그녀는 비행기에서 창가 자리를 특별히 요청했다.","category":"빈도 학습","level":13},{"id":11324,"term":"fat","meaning":"지방; 뚱뚱한","partOfSpeech":"n./adj.","example":"This yogurt is low in fat and tastes great.","exampleTranslation":"이 요거트는 지방이 적고 맛도 좋다.","category":"빈도 학습","level":13},{"id":11325,"term":"entry","meaning":"입장; 항목; 출품작","partOfSpeech":"n.","example":"Please show your ticket at the entry to the concert hall.","exampleTranslation":"콘서트홀 입구에서 표를 보여 주세요.","category":"빈도 학습","level":13},{"id":11326,"term":"fellow","meaning":"동료; 녀석; 동료의","partOfSpeech":"n.","example":"He chatted with a fellow traveler at the airport lounge.","exampleTranslation":"그는 공항 라운지에서 동료 여행자와 이야기를 나눴다.","category":"빈도 학습","level":13},{"id":11327,"term":"chemical","meaning":"화학 물질; 화학의","partOfSpeech":"n./adj.","example":"Always read the label before using any chemical cleaner at home.","exampleTranslation":"집에서 화학 세제를 사용하기 전에 항상 라벨을 읽으세요.","category":"빈도 학습","level":13},{"id":11328,"term":"capture","meaning":"포착하다; 사로잡다; 포획","partOfSpeech":"v.","example":"She wanted to capture the sunset before the clouds moved in.","exampleTranslation":"그녀는 구름이 끼기 전에 석양을 사진으로 담고 싶었다.","category":"빈도 학습","level":13},{"id":11329,"term":"peak","meaning":"정점; 꼭대기; 최고조의","partOfSpeech":"n.","example":"Traffic is at its peak around eight in the morning.","exampleTranslation":"교통 혼잡은 오전 8시경에 절정에 달한다.","category":"빈도 학습","level":13},{"id":11330,"term":"chairman","meaning":"의장; 회장","partOfSpeech":"n.","example":"The chairman opened the meeting and welcomed the new members.","exampleTranslation":"의장이 회의를 시작하며 새 회원들을 환영했다.","category":"빈도 학습","level":13},{"id":11331,"term":"proportion","meaning":"비율; 균형","partOfSpeech":"n.","example":"A large proportion of students walk to school every day.","exampleTranslation":"학생들의 상당 부분이 매일 걸어서 학교에 다닌다.","category":"빈도 학습","level":13},{"id":11332,"term":"ear","meaning":"귀; 청각","partOfSpeech":"n.","example":"He put his ear to the door and listened carefully.","exampleTranslation":"그는 귀를 문에 대고 조심스럽게 들었다.","category":"빈도 학습","level":13},{"id":11333,"term":"disappear","meaning":"사라지다; 없어지다","partOfSpeech":"v.","example":"My keys tend to disappear right when I'm in a hurry.","exampleTranslation":"내 열쇠는 급할 때마다 꼭 사라지곤 한다.","category":"빈도 학습","level":13},{"id":11334,"term":"shout","meaning":"소리치다; 외침","partOfSpeech":"v.","example":"Don't shout in the library — other people are studying.","exampleTranslation":"도서관에서 소리치지 마세요. 다른 사람들이 공부하고 있어요.","category":"빈도 학습","level":13},{"id":11335,"term":"yard","meaning":"마당; 야드(길이 단위)","partOfSpeech":"n.","example":"The kids were playing in the yard after school.","exampleTranslation":"아이들은 방과 후 마당에서 놀고 있었다.","category":"빈도 학습","level":13},{"id":11336,"term":"constant","meaning":"끊임없는; 일정한; 상수","partOfSpeech":"adj.","example":"Living in the city means constant noise day and night.","exampleTranslation":"도시에서 사는 것은 낮이고 밤이고 끊임없는 소음을 뜻한다.","category":"빈도 학습","level":13},{"id":11337,"term":"significantly","meaning":"상당히; 크게","partOfSpeech":"adv.","example":"The new bus route significantly cut my commute time.","exampleTranslation":"새 버스 노선이 내 출퇴근 시간을 상당히 줄여 주었다.","category":"빈도 학습","level":13},{"id":11338,"term":"hill","meaning":"언덕; 고개","partOfSpeech":"n.","example":"We climbed the hill and had a great view of the town below.","exampleTranslation":"우리는 언덕을 올라 아래 마을의 멋진 경치를 바라봤다.","category":"빈도 학습","level":13},{"id":11339,"term":"considerable","meaning":"상당한; 꽤 많은","partOfSpeech":"adj.","example":"She put considerable effort into preparing for the presentation.","exampleTranslation":"그녀는 발표를 준비하는 데 상당한 노력을 기울였다.","category":"빈도 학습","level":13},{"id":11340,"term":"instruction","meaning":"지시; 설명서; 교육","partOfSpeech":"n.","example":"Read the instruction carefully before assembling the furniture.","exampleTranslation":"가구를 조립하기 전에 설명서를 꼼꼼히 읽으세요.","category":"빈도 학습","level":13},{"id":11341,"term":"intelligence","meaning":"지능; 정보","partOfSpeech":"n.","example":"Her intelligence showed clearly during the debate.","exampleTranslation":"토론에서 그녀의 지능이 또렷이 드러났다.","category":"빈도 학습","level":13},{"id":11342,"term":"ideal","meaning":"이상적인; 이상","partOfSpeech":"adj.","example":"This apartment is ideal for a couple moving to the city.","exampleTranslation":"이 아파트는 도시로 이사하는 커플에게 이상적이다.","category":"빈도 학습","level":13},{"id":11343,"term":"folk","meaning":"사람들; 민속의","partOfSpeech":"n.","example":"The local folk gather at the market every Saturday morning.","exampleTranslation":"매주 토요일 아침 동네 사람들이 시장에 모인다.","category":"빈도 학습","level":13},{"id":11344,"term":"surely","meaning":"분명히; 틀림없이","partOfSpeech":"adv.","example":"You surely don't have to leave so early tonight.","exampleTranslation":"오늘 밤 그렇게 일찍 떠날 필요는 분명히 없잖아요.","category":"빈도 학습","level":13},{"id":11345,"term":"guard","meaning":"경비원; 지키다","partOfSpeech":"n./v.","example":"A guard stood at the entrance to check everyone's ID.","exampleTranslation":"경비원이 입구에서 모든 사람의 신분증을 확인하고 있었다.","category":"빈도 학습","level":13},{"id":11346,"term":"cat","meaning":"고양이","partOfSpeech":"n.","example":"My cat jumps onto the bed every night around midnight.","exampleTranslation":"우리 고양이는 매일 밤 자정쯤 침대 위로 뛰어오른다.","category":"빈도 학습","level":13},{"id":11347,"term":"somewhat","meaning":"다소; 어느 정도","partOfSpeech":"adv.","example":"The weather today is somewhat colder than yesterday.","exampleTranslation":"오늘 날씨는 어제보다 다소 춥다.","category":"빈도 학습","level":13},{"id":11348,"term":"kiss","meaning":"키스하다; 입맞춤","partOfSpeech":"v./n.","example":"She gave her little brother a kiss on the forehead before bed.","exampleTranslation":"그녀는 자기 전에 남동생의 이마에 입을 맞췄다.","category":"빈도 학습","level":13},{"id":11349,"term":"joint","meaning":"공동의; 관절; 이음매","partOfSpeech":"adj./n.","example":"They opened a joint bank account after getting married.","exampleTranslation":"그들은 결혼 후 공동 은행 계좌를 개설했다.","category":"빈도 학습","level":13},{"id":11350,"term":"compete","meaning":"경쟁하다; 겨루다","partOfSpeech":"v.","example":"Three teams will compete for the championship this weekend.","exampleTranslation":"이번 주말에 세 팀이 우승을 위해 경쟁할 것이다.","category":"빈도 학습","level":13},{"id":11351,"term":"poll","meaning":"여론 조사; 투표","partOfSpeech":"n.","example":"A recent poll showed that most people prefer working from home.","exampleTranslation":"최근 여론 조사에서 대부분의 사람들이 재택근무를 선호하는 것으로 나타났다.","category":"빈도 학습","level":13},{"id":11352,"term":"weak","meaning":"약한; 허약한","partOfSpeech":"adj.","example":"She felt weak after not eating all day.","exampleTranslation":"그녀는 하루 종일 아무것도 먹지 않아 기력이 없었다.","category":"빈도 학습","level":13},{"id":11353,"term":"faith","meaning":"믿음; 신뢰; 신앙","partOfSpeech":"n.","example":"I have complete faith in your ability to handle this.","exampleTranslation":"나는 네가 이 일을 처리할 수 있다고 완전히 믿는다.","category":"빈도 학습","level":13},{"id":11354,"term":"reduction","meaning":"감소; 축소; 할인","partOfSpeech":"n.","example":"The store is offering a reduction on all winter coats this week.","exampleTranslation":"그 가게는 이번 주 모든 겨울 코트를 할인 판매하고 있다.","category":"빈도 학습","level":13},{"id":11355,"term":"reserve","meaning":"예약하다; 비축하다; 보유","partOfSpeech":"v./n.","example":"I'd like to reserve a table for two at seven o'clock.","exampleTranslation":"7시에 두 명 자리를 예약하고 싶습니다.","category":"빈도 학습","level":13},{"id":11356,"term":"complaint","meaning":"불만; 항의; 불평","partOfSpeech":"n.","example":"She filed a complaint with the hotel about the noisy room next door.","exampleTranslation":"그녀는 옆방 소음에 대해 호텔에 항의를 제기했다.","category":"빈도 학습","level":13},{"id":11357,"term":"bore","meaning":"지루하게 하다; 구멍을 뚫다","partOfSpeech":"v.","example":"Long meetings without clear goals really bore me.","exampleTranslation":"뚜렷한 목적 없이 길게 이어지는 회의는 정말 지루하다.","category":"빈도 학습","level":13},{"id":11358,"term":"mission","meaning":"임무; 사명","partOfSpeech":"n.","example":"Their mission was to deliver the supplies before the storm hit.","exampleTranslation":"그들의 임무는 폭풍이 오기 전에 물자를 전달하는 것이었다.","category":"빈도 학습","level":13},{"id":11359,"term":"somehow","meaning":"어떻게든; 왠지","partOfSpeech":"adv.","example":"I forgot my umbrella but somehow stayed dry all day.","exampleTranslation":"우산을 잊고 왔는데 어떻게든 하루 종일 비를 맞지 않았다.","category":"빈도 학습","level":13},{"id":11360,"term":"tone","meaning":"말투; 분위기","partOfSpeech":"n.","example":"Please keep a polite tone when talking to customers.","exampleTranslation":"고객과 대화할 때는 정중한 말투를 유지해 주세요.","category":"빈도 학습","level":13},{"id":11361,"term":"neighborhood","meaning":"동네; 이웃 지역","partOfSpeech":"n.","example":"There's a great bakery in my neighborhood.","exampleTranslation":"우리 동네에 빵집이 하나 있는데 정말 맛있어요.","category":"빈도 학습","level":13},{"id":11362,"term":"passenger","meaning":"승객","partOfSpeech":"n.","example":"Every passenger must wear a seatbelt on the bus.","exampleTranslation":"버스에 탄 승객은 모두 안전벨트를 매야 합니다.","category":"빈도 학습","level":13},{"id":11363,"term":"justice","meaning":"정의; 공정함","partOfSpeech":"n.","example":"She believes everyone deserves justice regardless of their background.","exampleTranslation":"그녀는 출신에 상관없이 모두가 공정한 대우를 받아야 한다고 믿습니다.","category":"빈도 학습","level":13},{"id":11364,"term":"phase","meaning":"단계; 시기","partOfSpeech":"n.","example":"We're in the final phase of the project now.","exampleTranslation":"우리는 지금 프로젝트의 마지막 단계에 있습니다.","category":"빈도 학습","level":13},{"id":11365,"term":"thin","meaning":"얇은; 마른","partOfSpeech":"adj.","example":"The walls here are really thin, so I can hear everything.","exampleTranslation":"여기 벽이 정말 얇아서 모든 소리가 다 들려요.","category":"빈도 학습","level":13},{"id":11366,"term":"rush","meaning":"서두르다; 급히 가다","partOfSpeech":"v.","example":"Don't rush — we still have plenty of time.","exampleTranslation":"서두르지 마세요, 아직 시간이 충분해요.","category":"빈도 학습","level":13},{"id":11367,"term":"formal","meaning":"격식을 갖춘; 공식적인","partOfSpeech":"adj.","example":"The dinner was formal, so I wore a suit.","exampleTranslation":"저녁 자리가 격식 있는 자리라 정장을 입었습니다.","category":"빈도 학습","level":13},{"id":11368,"term":"religion","meaning":"종교","partOfSpeech":"n.","example":"People here follow many different religion traditions.","exampleTranslation":"이곳 사람들은 다양한 종교 전통을 따릅니다.","category":"빈도 학습","level":13},{"id":11369,"term":"employer","meaning":"고용주; 사용자","partOfSpeech":"n.","example":"My employer offers two weeks of paid vacation every year.","exampleTranslation":"제 고용주는 매년 2주간의 유급 휴가를 제공합니다.","category":"빈도 학습","level":13},{"id":11370,"term":"reject","meaning":"거절하다; 거부하다","partOfSpeech":"v.","example":"The bank decided to reject his loan application.","exampleTranslation":"은행은 그의 대출 신청을 거절하기로 했습니다.","category":"빈도 학습","level":13},{"id":11371,"term":"latter","meaning":"후자의; 나중의","partOfSpeech":"adj.","example":"Between tea and coffee, I prefer the latter.","exampleTranslation":"차와 커피 중에서 저는 후자인 커피를 더 좋아합니다.","category":"빈도 학습","level":13},{"id":11372,"term":"plate","meaning":"접시; 번호판","partOfSpeech":"n.","example":"Could you pass me a clean plate, please?","exampleTranslation":"깨끗한 접시 하나 건네주시겠어요?","category":"빈도 학습","level":13},{"id":11373,"term":"ban","meaning":"금지하다; 금지","partOfSpeech":"n./v.","example":"The city council voted to ban plastic bags at stores.","exampleTranslation":"시의회는 상점에서 비닐봉지 사용을 금지하기로 투표했습니다.","category":"빈도 학습","level":13},{"id":11374,"term":"steal","meaning":"훔치다","partOfSpeech":"v.","example":"Someone tried to steal her bag on the subway.","exampleTranslation":"지하철에서 누군가 그녀의 가방을 훔치려 했습니다.","category":"빈도 학습","level":13},{"id":11375,"term":"protest","meaning":"항의하다; 시위하다","partOfSpeech":"n./v.","example":"Hundreds of people gathered to protest the new law.","exampleTranslation":"수백 명이 새 법에 항의하기 위해 모였습니다.","category":"빈도 학습","level":13},{"id":11376,"term":"index","meaning":"색인; 지수","partOfSpeech":"n.","example":"You can find the topic in the index at the back of the book.","exampleTranslation":"그 주제는 책 뒤쪽 색인에서 찾을 수 있습니다.","category":"빈도 학습","level":13},{"id":11377,"term":"frequently","meaning":"자주; 빈번히","partOfSpeech":"adv.","example":"She frequently visits her parents on weekends.","exampleTranslation":"그녀는 주말에 자주 부모님을 찾아갑니다.","category":"빈도 학습","level":13},{"id":11378,"term":"circle","meaning":"원; 동그라미","partOfSpeech":"n.","example":"The kids sat in a circle and took turns sharing stories.","exampleTranslation":"아이들은 원을 그리고 앉아 돌아가며 이야기를 나눴습니다.","category":"빈도 학습","level":13},{"id":11379,"term":"helpful","meaning":"도움이 되는; 친절한","partOfSpeech":"adj.","example":"The staff at the hotel were really helpful.","exampleTranslation":"호텔 직원들이 정말 친절하고 도움이 됐습니다.","category":"빈도 학습","level":13},{"id":11380,"term":"command","meaning":"명령; 지시하다","partOfSpeech":"n./v.","example":"The officer gave the command to move forward.","exampleTranslation":"장교가 전진하라는 명령을 내렸습니다.","category":"빈도 학습","level":13},{"id":11381,"term":"attractive","meaning":"매력적인; 눈길을 끄는","partOfSpeech":"adj.","example":"The apartment has an attractive view of the river.","exampleTranslation":"그 아파트에서는 강의 매력적인 전망이 보입니다.","category":"빈도 학습","level":13},{"id":11382,"term":"impression","meaning":"인상; 느낌","partOfSpeech":"n.","example":"He made a great impression at the job interview.","exampleTranslation":"그는 취업 면접에서 좋은 인상을 남겼습니다.","category":"빈도 학습","level":13},{"id":11383,"term":"unable","meaning":"할 수 없는; ~하지 못하는","partOfSpeech":"adj.","example":"I was unable to reach her by phone all day.","exampleTranslation":"하루 종일 전화로 그녀에게 연락할 수가 없었습니다.","category":"빈도 학습","level":13},{"id":11384,"term":"joke","meaning":"농담; 우스갯소리","partOfSpeech":"n.","example":"He told a funny joke that made everyone laugh.","exampleTranslation":"그가 재미있는 농담을 해서 모두 웃었습니다.","category":"빈도 학습","level":13},{"id":11385,"term":"sky","meaning":"하늘","partOfSpeech":"n.","example":"The sky turned orange just before sunset.","exampleTranslation":"해가 지기 직전 하늘이 주황빛으로 물들었습니다.","category":"빈도 학습","level":13},{"id":11386,"term":"column","meaning":"기둥; 칼럼","partOfSpeech":"n.","example":"She writes a weekly column for the local newspaper.","exampleTranslation":"그녀는 지역 신문에 매주 칼럼을 씁니다.","category":"빈도 학습","level":14},{"id":11387,"term":"electronic","meaning":"전자의; 전자기기","partOfSpeech":"adj.","example":"Please turn off all electronic devices before the show starts.","exampleTranslation":"공연이 시작되기 전에 모든 전자기기를 꺼 주세요.","category":"빈도 학습","level":14},{"id":11388,"term":"impose","meaning":"부과하다; 강요하다","partOfSpeech":"v.","example":"The government decided to impose a tax on sugary drinks.","exampleTranslation":"정부는 당분이 많은 음료에 세금을 부과하기로 했습니다.","category":"빈도 학습","level":14},{"id":11389,"term":"criminal","meaning":"범죄자; 범죄의","partOfSpeech":"n.","example":"The criminal was caught near the scene of the theft.","exampleTranslation":"범죄자는 절도 현장 근처에서 붙잡혔습니다.","category":"빈도 학습","level":14},{"id":11390,"term":"besides","meaning":"게다가; ~외에도","partOfSpeech":"adv.","example":"Besides being cheap, the food here is really tasty.","exampleTranslation":"여기 음식은 저렴한 데다가 정말 맛있기도 합니다.","category":"빈도 학습","level":14},{"id":11391,"term":"properly","meaning":"제대로; 올바르게","partOfSpeech":"adv.","example":"Make sure you properly wash your hands before cooking.","exampleTranslation":"요리하기 전에 손을 제대로 씻었는지 확인하세요.","category":"빈도 학습","level":14},{"id":11392,"term":"ancient","meaning":"고대의; 아주 오래된","partOfSpeech":"adj.","example":"We visited an ancient temple during our trip to Japan.","exampleTranslation":"일본 여행 중에 오래된 사원을 방문했습니다.","category":"빈도 학습","level":14},{"id":11393,"term":"coast","meaning":"해안; 해변","partOfSpeech":"n.","example":"They drove along the coast and stopped at a small cafe.","exampleTranslation":"그들은 해안을 따라 드라이브하다가 작은 카페에 들렀습니다.","category":"빈도 학습","level":14},{"id":11394,"term":"ill","meaning":"아픈; 병든","partOfSpeech":"adj.","example":"He stayed home because he felt ill after lunch.","exampleTranslation":"그는 점심 후 몸이 아파서 집에 있었습니다.","category":"빈도 학습","level":14},{"id":11395,"term":"kick","meaning":"차다; 발로 차기","partOfSpeech":"v.","example":"He gave the door a hard kick to open it.","exampleTranslation":"그는 문을 열기 위해 세게 발로 찼습니다.","category":"빈도 학습","level":14},{"id":11396,"term":"closely","meaning":"가까이서; 면밀히","partOfSpeech":"adv.","example":"The doctor examined the wound closely.","exampleTranslation":"의사가 상처를 면밀히 살펴봤습니다.","category":"빈도 학습","level":14},{"id":11397,"term":"multiple","meaning":"여러 개의; 다수의","partOfSpeech":"adj.","example":"She received multiple job offers after graduation.","exampleTranslation":"그녀는 졸업 후 여러 곳에서 취업 제안을 받았습니다.","category":"빈도 학습","level":14},{"id":11398,"term":"yield","meaning":"양보하다; 산출하다","partOfSpeech":"v.","example":"You must yield to pedestrians at the crosswalk.","exampleTranslation":"횡단보도에서는 보행자에게 양보해야 합니다.","category":"빈도 학습","level":14},{"id":11399,"term":"via","meaning":"~를 거쳐; ~을 통해","partOfSpeech":"prep.","example":"We flew to London via Dubai.","exampleTranslation":"우리는 두바이를 거쳐 런던으로 날아갔습니다.","category":"빈도 학습","level":14},{"id":11400,"term":"legislation","meaning":"법률; 입법","partOfSpeech":"n.","example":"New legislation will ban smoking in all public parks.","exampleTranslation":"새 법률이 모든 공공 공원에서의 흡연을 금지할 것입니다.","category":"빈도 학습","level":14},{"id":11401,"term":"county","meaning":"군(郡), 카운티; 지방 행정 구역","partOfSpeech":"n.","example":"She grew up in a small county with only one high school.","exampleTranslation":"그녀는 고등학교가 하나뿐인 작은 카운티에서 자랐습니다.","category":"빈도 학습","level":14},{"id":11402,"term":"unlike","meaning":"~와 달리; ~와 다른","partOfSpeech":"prep.","example":"Unlike her brother, she loves spicy food.","exampleTranslation":"오빠와 달리, 그녀는 매운 음식을 좋아합니다.","category":"빈도 학습","level":14},{"id":11403,"term":"mobile","meaning":"이동 가능한; 휴대폰","partOfSpeech":"adj.","example":"She forgot her mobile at home and felt disconnected all day.","exampleTranslation":"그녀는 집에 휴대폰을 놓고 와서 하루 종일 답답함을 느꼈습니다.","category":"빈도 학습","level":14},{"id":11404,"term":"assistant","meaning":"보조자, 조수; 어시스턴트","partOfSpeech":"n.","example":"The assistant prepared the meeting room before everyone arrived.","exampleTranslation":"어시스턴트는 모두가 도착하기 전에 회의실을 준비했습니다.","category":"빈도 학습","level":14},{"id":11405,"term":"chart","meaning":"도표, 차트; 지도","partOfSpeech":"n.","example":"The chart shows how sales have grown over the past year.","exampleTranslation":"이 차트는 지난 1년간 매출이 어떻게 성장했는지 보여 줍니다.","category":"빈도 학습","level":14},{"id":11406,"term":"hell","meaning":"지옥; (강조) 엄청난","partOfSpeech":"n.","example":"Traffic was hell this morning and I was late to work.","exampleTranslation":"오늘 아침 교통 체증이 끔찍해서 회사에 늦었습니다.","category":"빈도 학습","level":14},{"id":11407,"term":"everywhere","meaning":"어디에나, 도처에","partOfSpeech":"adv.","example":"There were balloons everywhere at the birthday party.","exampleTranslation":"생일 파티 곳곳에 풍선이 있었습니다.","category":"빈도 학습","level":14},{"id":11408,"term":"household","meaning":"가정, 세대; 가정용의","partOfSpeech":"n.","example":"Every household in the neighborhood got a notice about the water outage.","exampleTranslation":"동네의 모든 가정에 단수 안내문이 배달되었습니다.","category":"빈도 학습","level":14},{"id":11409,"term":"acknowledge","meaning":"인정하다; 감사하다","partOfSpeech":"v.","example":"It takes courage to acknowledge your own mistakes.","exampleTranslation":"자신의 실수를 인정하려면 용기가 필요합니다.","category":"빈도 학습","level":14},{"id":11410,"term":"reward","meaning":"보상, 보람; 보상하다","partOfSpeech":"n./v.","example":"The restaurant offers a reward for customers who refer a friend.","exampleTranslation":"그 식당은 친구를 소개해 준 고객에게 보상을 제공합니다.","category":"빈도 학습","level":14},{"id":11411,"term":"east","meaning":"동쪽; 동쪽의","partOfSpeech":"n.","example":"The sun rises in the east every morning.","exampleTranslation":"태양은 매일 아침 동쪽에서 뜹니다.","category":"빈도 학습","level":14},{"id":11412,"term":"hat","meaning":"모자","partOfSpeech":"n.","example":"She always wears a hat when she goes to the beach.","exampleTranslation":"그녀는 해변에 갈 때 항상 모자를 씁니다.","category":"빈도 학습","level":14},{"id":11413,"term":"academic","meaning":"학문적인; 학업의","partOfSpeech":"adj.","example":"Her academic record helped her get into a top university.","exampleTranslation":"그녀의 학업 성적이 명문 대학 입학에 도움이 되었습니다.","category":"빈도 학습","level":14},{"id":11414,"term":"voter","meaning":"유권자, 투표자","partOfSpeech":"n.","example":"Each voter must show an ID before entering the polling station.","exampleTranslation":"각 유권자는 투표소에 들어가기 전에 신분증을 제시해야 합니다.","category":"빈도 학습","level":14},{"id":11415,"term":"meanwhile","meaning":"그러는 동안에; 한편","partOfSpeech":"adv.","example":"She cooked dinner while her husband meanwhile set the table.","exampleTranslation":"그녀가 저녁을 요리하는 동안 남편은 한편으로 식탁을 차렸습니다.","category":"빈도 학습","level":14},{"id":11416,"term":"furthermore","meaning":"게다가, 더욱이","partOfSpeech":"adv.","example":"The hotel is affordable; furthermore, it's right next to the train station.","exampleTranslation":"그 호텔은 가격이 저렴하고, 게다가 기차역 바로 옆에 있습니다.","category":"빈도 학습","level":14},{"id":11417,"term":"accuse","meaning":"고발하다, 비난하다","partOfSpeech":"v.","example":"Don't accuse someone of lying without solid proof.","exampleTranslation":"확실한 증거 없이 누군가를 거짓말쟁이라고 비난하지 마세요.","category":"빈도 학습","level":14},{"id":11418,"term":"scientific","meaning":"과학적인","partOfSpeech":"adj.","example":"The scientific evidence clearly supports the benefits of regular exercise.","exampleTranslation":"과학적 증거는 규칙적인 운동의 효과를 명확히 뒷받침합니다.","category":"빈도 학습","level":14},{"id":11419,"term":"wage","meaning":"임금, 급여","partOfSpeech":"n.","example":"He asked his boss for a higher wage after working there for two years.","exampleTranslation":"그는 2년 일한 뒤 사장에게 임금 인상을 요청했습니다.","category":"빈도 학습","level":14},{"id":11420,"term":"absence","meaning":"부재, 결석; 없음","partOfSpeech":"n.","example":"Her absence from the meeting surprised everyone on the team.","exampleTranslation":"그녀가 회의에 불참한 것은 팀 모두를 놀라게 했습니다.","category":"빈도 학습","level":14},{"id":11421,"term":"construct","meaning":"건설하다, 만들다","partOfSpeech":"v.","example":"They plan to construct a new bridge across the river next year.","exampleTranslation":"그들은 내년에 강을 가로지르는 새 다리를 건설할 계획입니다.","category":"빈도 학습","level":14},{"id":11422,"term":"remark","meaning":"말, 발언; 말하다","partOfSpeech":"n./v.","example":"His remark about the food made everyone laugh at the dinner table.","exampleTranslation":"음식에 대한 그의 발언이 식탁에 있는 모두를 웃게 만들었습니다.","category":"빈도 학습","level":14},{"id":11423,"term":"professor","meaning":"교수","partOfSpeech":"n.","example":"The professor gave extra time to students who needed it on the exam.","exampleTranslation":"교수님은 시험에서 도움이 필요한 학생들에게 시간을 더 주었습니다.","category":"빈도 학습","level":14},{"id":11424,"term":"rare","meaning":"드문, 희귀한","partOfSpeech":"adj.","example":"Seeing a shooting star is rare, so make a wish when you do.","exampleTranslation":"유성을 보는 건 드문 일이니, 보게 되면 소원을 비세요.","category":"빈도 학습","level":14},{"id":11425,"term":"intention","meaning":"의도, 목적","partOfSpeech":"n.","example":"His intention was to surprise her with a home-cooked meal.","exampleTranslation":"그의 의도는 직접 만든 식사로 그녀를 깜짝 놀라게 하는 것이었습니다.","category":"빈도 학습","level":14},{"id":11426,"term":"dozen","meaning":"12개, 한 다스; 다수","partOfSpeech":"n.","example":"She bought a dozen eggs and some milk on her way home.","exampleTranslation":"그녀는 집에 오는 길에 달걀 한 다스와 우유를 샀습니다.","category":"빈도 학습","level":14},{"id":11427,"term":"settlement","meaning":"합의, 해결; 정착지","partOfSpeech":"n.","example":"Both sides reached a settlement and avoided going to court.","exampleTranslation":"양측은 합의에 도달해 법정 다툼을 피했습니다.","category":"빈도 학습","level":14},{"id":11428,"term":"gap","meaning":"틈, 격차; 공백","partOfSpeech":"n.","example":"There is a gap between the wall and the shelf that needs to be fixed.","exampleTranslation":"벽과 선반 사이에 고쳐야 할 틈이 있습니다.","category":"빈도 학습","level":14},{"id":11429,"term":"widely","meaning":"널리, 광범위하게","partOfSpeech":"adv.","example":"This type of tea is widely available in most grocery stores.","exampleTranslation":"이 종류의 차는 대부분의 식료품점에서 널리 구할 수 있습니다.","category":"빈도 학습","level":14},{"id":11430,"term":"minimum","meaning":"최소; 최소한의","partOfSpeech":"n.","example":"You need a minimum of two references to apply for that job.","exampleTranslation":"그 직업에 지원하려면 최소 두 개의 추천서가 필요합니다.","category":"빈도 학습","level":14},{"id":11431,"term":"northern","meaning":"북쪽의, 북부의","partOfSpeech":"adj.","example":"The northern part of the country gets very cold in winter.","exampleTranslation":"그 나라의 북부 지역은 겨울에 매우 춥습니다.","category":"빈도 학습","level":14},{"id":11432,"term":"estate","meaning":"재산, 유산; 부동산","partOfSpeech":"n.","example":"Her grandmother left the estate to the three grandchildren equally.","exampleTranslation":"할머니는 재산을 세 손자녀에게 똑같이 남겼습니다.","category":"빈도 학습","level":14},{"id":11433,"term":"equally","meaning":"똑같이, 동등하게","partOfSpeech":"adv.","example":"Both options are equally good, so just pick one.","exampleTranslation":"두 선택지 모두 똑같이 좋으니 그냥 하나를 고르세요.","category":"빈도 학습","level":14},{"id":11434,"term":"expose","meaning":"노출시키다; 드러내다","partOfSpeech":"v.","example":"Don't expose your skin to direct sunlight for too long.","exampleTranslation":"피부를 너무 오래 직사광선에 노출시키지 마세요.","category":"빈도 학습","level":14},{"id":11435,"term":"alive","meaning":"살아 있는; 생생한","partOfSpeech":"adj.","example":"The plant is still alive even though I forgot to water it last week.","exampleTranslation":"지난주에 물을 잊었는데도 식물이 여전히 살아 있습니다.","category":"빈도 학습","level":14},{"id":11436,"term":"shut","meaning":"닫다; 닫힌","partOfSpeech":"v.","example":"Please shut the window before it rains.","exampleTranslation":"비가 오기 전에 창문을 닫아 주세요.","category":"빈도 학습","level":14},{"id":11437,"term":"victory","meaning":"승리","partOfSpeech":"n.","example":"The team celebrated their victory with a big dinner after the match.","exampleTranslation":"팀은 경기 후 성대한 저녁 식사로 승리를 자축했습니다.","category":"빈도 학습","level":14},{"id":11438,"term":"resolve","meaning":"해결하다; 결심하다","partOfSpeech":"v.","example":"They talked it through and managed to resolve their disagreement.","exampleTranslation":"그들은 충분히 이야기하며 의견 차이를 해결해 냈습니다.","category":"빈도 학습","level":14},{"id":11439,"term":"critic","meaning":"비평가; 비판자","partOfSpeech":"n.","example":"The movie critic gave the film four stars out of five.","exampleTranslation":"영화 비평가는 그 영화에 5점 만점에 4점을 주었습니다.","category":"빈도 학습","level":14},{"id":11440,"term":"variable","meaning":"변하기 쉬운; 변수","partOfSpeech":"adj./n.","example":"The weather here is quite variable in spring.","exampleTranslation":"이곳의 봄 날씨는 꽤 변덕스럽습니다.","category":"빈도 학습","level":14},{"id":11441,"term":"enormous","meaning":"거대한; 엄청난","partOfSpeech":"adj.","example":"The city has enormous shopping malls you can get lost in.","exampleTranslation":"그 도시에는 길을 잃을 만큼 거대한 쇼핑몰이 있습니다.","category":"빈도 학습","level":14},{"id":11442,"term":"permanent","meaning":"영구적인; 영속하는","partOfSpeech":"adj.","example":"She finally got a permanent job after months of temp work.","exampleTranslation":"그녀는 몇 달간 임시직을 전전하다 마침내 정규직을 얻었습니다.","category":"빈도 학습","level":14},{"id":11443,"term":"emotion","meaning":"감정; 정서","partOfSpeech":"n.","example":"He had trouble hiding his emotion when he heard the news.","exampleTranslation":"그는 그 소식을 듣고 감정을 숨기는 데 애를 먹었습니다.","category":"빈도 학습","level":14},{"id":11444,"term":"pursue","meaning":"추구하다; 뒤쫓다","partOfSpeech":"v.","example":"She decided to pursue a career in music after high school.","exampleTranslation":"그녀는 고등학교 졸업 후 음악 분야의 직업을 추구하기로 결심했습니다.","category":"빈도 학습","level":14},{"id":11445,"term":"tall","meaning":"키가 큰; 높은","partOfSpeech":"adj.","example":"My brother is tall enough to reach the top shelf easily.","exampleTranslation":"제 남동생은 맨 위 선반에 쉽게 닿을 만큼 키가 큽니다.","category":"빈도 학습","level":14},{"id":11446,"term":"urge","meaning":"강하게 권하다; 충동","partOfSpeech":"v./n.","example":"I had a sudden urge to call my old friend.","exampleTranslation":"오랜 친구에게 갑자기 전화하고 싶은 충동이 생겼습니다.","category":"빈도 학습","level":14},{"id":11447,"term":"enemy","meaning":"적; 원수","partOfSpeech":"n.","example":"Stress is the worst enemy of a good night's sleep.","exampleTranslation":"스트레스는 숙면의 가장 큰 적입니다.","category":"빈도 학습","level":14},{"id":11448,"term":"appoint","meaning":"임명하다; 지정하다","partOfSpeech":"v.","example":"They will appoint a new manager at Monday's meeting.","exampleTranslation":"그들은 월요일 회의에서 새 관리자를 임명할 것입니다.","category":"빈도 학습","level":14},{"id":11449,"term":"milk","meaning":"우유","partOfSpeech":"n.","example":"Could you pick up some milk on your way home?","exampleTranslation":"집에 오는 길에 우유 좀 사다 줄 수 있어요?","category":"빈도 학습","level":14},{"id":11450,"term":"talent","meaning":"재능; 재주","partOfSpeech":"n.","example":"She has a real talent for learning new languages quickly.","exampleTranslation":"그녀는 새로운 언어를 빠르게 배우는 진짜 재능을 가지고 있습니다.","category":"빈도 학습","level":14},{"id":11451,"term":"smell","meaning":"냄새; 냄새가 나다","partOfSpeech":"n./v.","example":"The fresh bread smell from the bakery filled the street.","exampleTranslation":"제과점에서 나는 갓 구운 빵 냄새가 거리를 가득 채웠습니다.","category":"빈도 학습","level":14},{"id":11452,"term":"prior","meaning":"이전의; 사전의","partOfSpeech":"adj.","example":"You need prior approval before taking a day off.","exampleTranslation":"하루 휴가를 내기 전에 사전 승인이 필요합니다.","category":"빈도 학습","level":14},{"id":11453,"term":"priority","meaning":"우선순위; 중요한 것","partOfSpeech":"n.","example":"Getting enough sleep should be a priority, not a luxury.","exampleTranslation":"충분한 수면은 사치가 아니라 우선순위가 되어야 합니다.","category":"빈도 학습","level":14},{"id":11454,"term":"online","meaning":"온라인으로; 인터넷에 연결된","partOfSpeech":"adv./adj.","example":"I found a great deal on flights by shopping online.","exampleTranslation":"온라인으로 검색하다가 항공권 좋은 특가를 찾았습니다.","category":"빈도 학습","level":14},{"id":11455,"term":"phrase","meaning":"구절; 표현","partOfSpeech":"n.","example":"That phrase comes up a lot in everyday English conversation.","exampleTranslation":"그 표현은 일상 영어 대화에서 자주 나옵니다.","category":"빈도 학습","level":14},{"id":11456,"term":"pilot","meaning":"조종사; 시범의","partOfSpeech":"n./adj.","example":"The pilot announced that we would land in about twenty minutes.","exampleTranslation":"기장이 약 20분 후에 착륙할 것이라고 알렸습니다.","category":"빈도 학습","level":14},{"id":11457,"term":"stable","meaning":"안정적인; 변동 없는","partOfSpeech":"adj.","example":"His health is stable now, so we don't need to worry.","exampleTranslation":"그의 건강 상태가 지금은 안정적이라 걱정하지 않아도 됩니다.","category":"빈도 학습","level":14},{"id":11458,"term":"merely","meaning":"단지; 그저","partOfSpeech":"adv.","example":"I was merely trying to help when I gave that advice.","exampleTranslation":"그 조언을 할 때 저는 그저 도움이 되려 했을 뿐입니다.","category":"빈도 학습","level":14},{"id":11459,"term":"resolution","meaning":"결심; 해결","partOfSpeech":"n.","example":"My New Year's resolution is to exercise three times a week.","exampleTranslation":"제 새해 결심은 일주일에 세 번 운동하는 것입니다.","category":"빈도 학습","level":14},{"id":11460,"term":"communicate","meaning":"소통하다; 전달하다","partOfSpeech":"v.","example":"It's important to communicate clearly with your coworkers.","exampleTranslation":"동료들과 명확하게 소통하는 것이 중요합니다.","category":"빈도 학습","level":14},{"id":11461,"term":"vast","meaning":"광대한; 방대한","partOfSpeech":"adj.","example":"There is a vast difference between knowing and actually doing.","exampleTranslation":"아는 것과 실제로 행동하는 것 사이에는 방대한 차이가 있습니다.","category":"빈도 학습","level":14},{"id":11462,"term":"exhibition","meaning":"전시회; 전람회","partOfSpeech":"n.","example":"We spent the afternoon at a photography exhibition downtown.","exampleTranslation":"우리는 오후를 시내의 사진 전시회에서 보냈습니다.","category":"빈도 학습","level":14},{"id":11463,"term":"producer","meaning":"생산자; 제작자","partOfSpeech":"n.","example":"The producer of that film won several awards last year.","exampleTranslation":"그 영화의 제작자는 작년에 여러 상을 받았습니다.","category":"빈도 학습","level":14},{"id":11464,"term":"regional","meaning":"지역의; 지방의","partOfSpeech":"adj.","example":"You should try some regional dishes when you travel.","exampleTranslation":"여행할 때는 지역 음식을 먹어봐야 합니다.","category":"빈도 학습","level":14},{"id":11465,"term":"immediate","meaning":"즉각적인; 당장의","partOfSpeech":"adj.","example":"The medicine gave immediate relief from the headache.","exampleTranslation":"그 약은 두통을 즉각적으로 완화해 주었습니다.","category":"빈도 학습","level":14},{"id":11466,"term":"childhood","meaning":"어린 시절; 유년기","partOfSpeech":"n.","example":"She spent her childhood in a small town by the sea.","exampleTranslation":"그녀는 바닷가의 작은 마을에서 어린 시절을 보냈습니다.","category":"빈도 학습","level":14},{"id":11467,"term":"draft","meaning":"초안; 초고를 쓰다","partOfSpeech":"n./v.","example":"She sent me a draft of the report to check before the meeting.","exampleTranslation":"그녀는 회의 전에 확인해 달라며 보고서 초안을 보내왔습니다.","category":"빈도 학습","level":14},{"id":11468,"term":"slip","meaning":"미끄러지다; 실수","partOfSpeech":"v./n.","example":"Be careful not to slip on the wet floor near the entrance.","exampleTranslation":"입구 근처 젖은 바닥에서 미끄러지지 않도록 조심하세요.","category":"빈도 학습","level":14},{"id":11469,"term":"accompany","meaning":"동행하다; 함께 가다","partOfSpeech":"v.","example":"Would you like me to accompany you to the doctor's office?","exampleTranslation":"병원까지 같이 가드릴까요?","category":"빈도 학습","level":14},{"id":11470,"term":"politician","meaning":"정치인; 정치가","partOfSpeech":"n.","example":"The politician gave a speech about improving public transport.","exampleTranslation":"그 정치인은 대중교통 개선에 관한 연설을 했습니다.","category":"빈도 학습","level":14},{"id":11471,"term":"knock","meaning":"두드리다; 노크","partOfSpeech":"v./n.","example":"Please knock before you come into my office.","exampleTranslation":"제 사무실에 들어오기 전에 노크해 주세요.","category":"빈도 학습","level":14},{"id":11472,"term":"seed","meaning":"씨앗; 씨를 뿌리다","partOfSpeech":"n./v.","example":"She planted a seed in the pot and watered it every day.","exampleTranslation":"그녀는 화분에 씨앗을 심고 매일 물을 주었습니다.","category":"빈도 학습","level":14},{"id":11473,"term":"illustrate","meaning":"설명하다; 삽화를 넣다","partOfSpeech":"v.","example":"Let me use an example to illustrate what I mean.","exampleTranslation":"제가 뜻하는 바를 예시를 들어 설명해 드리겠습니다.","category":"빈도 학습","level":14},{"id":11474,"term":"imply","meaning":"암시하다; 뜻하다","partOfSpeech":"v.","example":"Are you trying to imply that I made a mistake?","exampleTranslation":"제가 실수를 했다는 걸 암시하려는 건가요?","category":"빈도 학습","level":14},{"id":11475,"term":"temporary","meaning":"임시의; 일시적인","partOfSpeech":"adj.","example":"This is just a temporary fix until the repairman comes.","exampleTranslation":"이건 수리기사가 올 때까지의 임시 조치일 뿐입니다.","category":"빈도 학습","level":14},{"id":11476,"term":"liberal","meaning":"자유주의적인; 관대한","partOfSpeech":"adj.","example":"Her parents were quite liberal about letting her make her own choices.","exampleTranslation":"그녀의 부모님은 그녀가 스스로 선택을 하도록 꽤 관대했습니다.","category":"빈도 학습","level":14},{"id":11477,"term":"lake","meaning":"호수","partOfSpeech":"n.","example":"We rented a cabin by the lake for the weekend.","exampleTranslation":"우리는 주말 동안 호수 근처 오두막을 빌렸습니다.","category":"빈도 학습","level":14},{"id":11478,"term":"qualify","meaning":"자격을 갖추다; 조건을 충족하다","partOfSpeech":"v.","example":"Do I qualify for a student discount at this museum?","exampleTranslation":"이 박물관에서 학생 할인을 받을 자격이 되나요?","category":"빈도 학습","level":14},{"id":11479,"term":"competitive","meaning":"경쟁적인; 경쟁력 있는","partOfSpeech":"adj.","example":"The job market is very competitive right now, so prepare well.","exampleTranslation":"지금 취업 시장은 매우 경쟁적이니 잘 준비하세요.","category":"빈도 학습","level":14},{"id":11480,"term":"truly","meaning":"진정으로; 정말로","partOfSpeech":"adv.","example":"I truly enjoyed meeting your family last night.","exampleTranslation":"어젯밤 당신 가족을 만나서 정말 즐거웠어요.","category":"빈도 학습","level":14},{"id":11481,"term":"hi","meaning":"안녕","partOfSpeech":"phr.","example":"Hi, is anyone home?","exampleTranslation":"안녕, 집에 누구 있어요?","category":"빈도 학습","level":14},{"id":11482,"term":"yellow","meaning":"노란색(의)","partOfSpeech":"adj.","example":"She wore a yellow dress to the party.","exampleTranslation":"그녀는 파티에 노란 드레스를 입고 왔어요.","category":"빈도 학습","level":14},{"id":11483,"term":"disk","meaning":"디스크; 원반","partOfSpeech":"n.","example":"Save the file to your disk before closing.","exampleTranslation":"닫기 전에 파일을 디스크에 저장하세요.","category":"빈도 학습","level":14},{"id":11484,"term":"core","meaning":"핵심; 중심부","partOfSpeech":"n.","example":"Exercise is the core of a healthy lifestyle.","exampleTranslation":"운동은 건강한 생활 방식의 핵심이에요.","category":"빈도 학습","level":14},{"id":11485,"term":"emotional","meaning":"감정적인; 정서적인","partOfSpeech":"adj.","example":"The farewell was an emotional moment for everyone.","exampleTranslation":"그 작별은 모두에게 감동적인 순간이었어요.","category":"빈도 학습","level":14},{"id":11486,"term":"aircraft","meaning":"항공기; 비행기","partOfSpeech":"n.","example":"The aircraft landed smoothly despite the strong wind.","exampleTranslation":"강한 바람에도 불구하고 항공기는 부드럽게 착륙했어요.","category":"빈도 학습","level":14},{"id":11487,"term":"self","meaning":"자아; 자기 자신","partOfSpeech":"n.","example":"Traveling alone helped her discover her true self.","exampleTranslation":"혼자 여행하면서 그녀는 진정한 자신을 발견했어요.","category":"빈도 학습","level":14},{"id":11488,"term":"metal","meaning":"금속","partOfSpeech":"n.","example":"The fence is made of metal and won't rust easily.","exampleTranslation":"그 울타리는 금속으로 만들어져 잘 녹슬지 않아요.","category":"빈도 학습","level":14},{"id":11489,"term":"existence","meaning":"존재; 실재","partOfSpeech":"n.","example":"No one doubts the existence of the problem anymore.","exampleTranslation":"이제 아무도 그 문제의 존재를 의심하지 않아요.","category":"빈도 학습","level":14},{"id":11490,"term":"bone","meaning":"뼈","partOfSpeech":"n.","example":"He broke a bone in his foot while hiking.","exampleTranslation":"그는 하이킹 중에 발의 뼈가 부러졌어요.","category":"빈도 학습","level":14},{"id":11491,"term":"panel","meaning":"패널; 위원회","partOfSpeech":"n.","example":"A panel of judges will review all the entries.","exampleTranslation":"심사 위원단이 모든 출품작을 검토할 거예요.","category":"빈도 학습","level":14},{"id":11492,"term":"prime","meaning":"주요한; 최고의","partOfSpeech":"adj.","example":"Location is the prime factor when buying a house.","exampleTranslation":"집을 살 때 위치가 가장 중요한 요소예요.","category":"빈도 학습","level":15},{"id":11493,"term":"emphasize","meaning":"강조하다","partOfSpeech":"v.","example":"Good teachers emphasize the importance of getting enough sleep.","exampleTranslation":"훌륭한 선생님들은 충분한 수면의 중요성을 강조해요.","category":"빈도 학습","level":15},{"id":11494,"term":"maximum","meaning":"최대(의); 최고 한도","partOfSpeech":"n.","example":"The elevator can hold a maximum of eight people.","exampleTranslation":"엘리베이터는 최대 8명까지 탈 수 있어요.","category":"빈도 학습","level":15},{"id":11495,"term":"effectively","meaning":"효과적으로; 실질적으로","partOfSpeech":"adv.","example":"She manages her time very effectively.","exampleTranslation":"그녀는 시간을 매우 효과적으로 관리해요.","category":"빈도 학습","level":15},{"id":11496,"term":"elsewhere","meaning":"다른 곳에(서)","partOfSpeech":"adv.","example":"If they don't have it here, try looking elsewhere.","exampleTranslation":"여기에 없으면 다른 곳에서 찾아보세요.","category":"빈도 학습","level":15},{"id":11497,"term":"bother","meaning":"신경 쓰다; 귀찮게 하다","partOfSpeech":"v.","example":"Don't bother cooking tonight — let's just order pizza.","exampleTranslation":"오늘 밤은 요리하지 마세요 — 그냥 피자 시켜요.","category":"빈도 학습","level":15},{"id":11498,"term":"initiative","meaning":"주도권; 솔선수범","partOfSpeech":"n.","example":"She took the initiative and introduced herself first.","exampleTranslation":"그녀가 먼저 주도적으로 자기소개를 했어요.","category":"빈도 학습","level":15},{"id":11499,"term":"sharp","meaning":"날카로운; 예리한","partOfSpeech":"adj.","example":"Be careful — that knife is very sharp.","exampleTranslation":"조심하세요 — 그 칼은 매우 날카로워요.","category":"빈도 학습","level":15},{"id":11500,"term":"motion","meaning":"움직임; 동작","partOfSpeech":"n.","example":"The slow motion replay showed exactly what happened.","exampleTranslation":"슬로우 모션 재생으로 무슨 일이 있었는지 정확히 보였어요.","category":"빈도 학습","level":15},{"id":11501,"term":"gray","meaning":"회색(의)","partOfSpeech":"adj.","example":"He wore a gray sweater on a cloudy day.","exampleTranslation":"그는 흐린 날 회색 스웨터를 입었어요.","category":"빈도 학습","level":15},{"id":11502,"term":"plastic","meaning":"플라스틱; 비닐","partOfSpeech":"n.","example":"Please bring your own bag instead of using plastic.","exampleTranslation":"플라스틱 대신 개인 가방을 가져오세요.","category":"빈도 학습","level":15},{"id":11503,"term":"complicate","meaning":"복잡하게 만들다","partOfSpeech":"v.","example":"Adding more rules will only complicate the process.","exampleTranslation":"규칙을 더 추가하면 절차가 더욱 복잡해질 뿐이에요.","category":"빈도 학습","level":15},{"id":11504,"term":"discipline","meaning":"규율; 훈련","partOfSpeech":"n.","example":"Success in any sport requires discipline and hard work.","exampleTranslation":"어떤 스포츠에서든 성공하려면 규율과 노력이 필요해요.","category":"빈도 학습","level":15},{"id":11505,"term":"disappoint","meaning":"실망시키다","partOfSpeech":"v.","example":"I don't want to disappoint my parents with bad grades.","exampleTranslation":"나쁜 성적으로 부모님을 실망시키고 싶지 않아요.","category":"빈도 학습","level":15},{"id":11506,"term":"boss","meaning":"상사; 사장","partOfSpeech":"n.","example":"My boss gave me the day off as a reward.","exampleTranslation":"상사가 보상으로 하루 휴가를 줬어요.","category":"빈도 학습","level":15},{"id":11507,"term":"assumption","meaning":"가정; 추정","partOfSpeech":"n.","example":"Don't make an assumption without checking the facts first.","exampleTranslation":"사실을 먼저 확인하지 않고 추정하지 마세요.","category":"빈도 학습","level":15},{"id":11508,"term":"freeze","meaning":"얼다; 얼리다","partOfSpeech":"v.","example":"The pipes might freeze if it gets too cold tonight.","exampleTranslation":"오늘 밤 너무 추우면 파이프가 얼 수도 있어요.","category":"빈도 학습","level":15},{"id":11509,"term":"extreme","meaning":"극단적인; 극심한","partOfSpeech":"adj.","example":"The hikers faced extreme cold near the mountaintop.","exampleTranslation":"등산객들은 산 정상 근처에서 극심한 추위를 겪었어요.","category":"빈도 학습","level":15},{"id":11510,"term":"passage","meaning":"통로; (글의) 구절","partOfSpeech":"n.","example":"There's a narrow passage between the two buildings.","exampleTranslation":"두 건물 사이에 좁은 통로가 있어요.","category":"빈도 학습","level":15},{"id":11511,"term":"reputation","meaning":"명성; 평판","partOfSpeech":"n.","example":"That restaurant has a great reputation for its seafood.","exampleTranslation":"그 식당은 해산물로 명성이 높아요.","category":"빈도 학습","level":15},{"id":11512,"term":"forth","meaning":"앞으로; 밖으로","partOfSpeech":"adv.","example":"She stepped forth and volunteered to go first.","exampleTranslation":"그녀가 앞으로 나서서 먼저 가겠다고 자원했어요.","category":"빈도 학습","level":15},{"id":11513,"term":"negotiation","meaning":"협상; 교섭","partOfSpeech":"n.","example":"The salary negotiation took about two hours to finish.","exampleTranslation":"급여 협상을 끝내는 데 약 두 시간이 걸렸어요.","category":"빈도 학습","level":15},{"id":11514,"term":"mechanism","meaning":"메커니즘; 작동 방식","partOfSpeech":"n.","example":"No one fully understood the mechanism behind the illness.","exampleTranslation":"그 질병의 작동 방식을 완전히 이해한 사람은 없었어요.","category":"빈도 학습","level":15},{"id":11515,"term":"coat","meaning":"외투; 코트","partOfSpeech":"n.","example":"Don't forget your coat — it's cold outside.","exampleTranslation":"외투 잊지 마세요 — 밖에 추워요.","category":"빈도 학습","level":15},{"id":11516,"term":"democracy","meaning":"민주주의","partOfSpeech":"n.","example":"In a democracy, citizens have the right to vote.","exampleTranslation":"민주주의에서는 시민들이 투표할 권리가 있어요.","category":"빈도 학습","level":15},{"id":11517,"term":"pocket","meaning":"주머니","partOfSpeech":"n.","example":"He slipped his phone into his pocket and walked away.","exampleTranslation":"그는 전화기를 주머니에 넣고 걸어갔어요.","category":"빈도 학습","level":15},{"id":11518,"term":"lucky","meaning":"운이 좋은; 행운의","partOfSpeech":"adj.","example":"You're so lucky to have such a great job!","exampleTranslation":"그런 좋은 직장을 가지다니 정말 운이 좋으시네요!","category":"빈도 학습","level":15},{"id":11519,"term":"crash","meaning":"충돌하다; 추락하다","partOfSpeech":"v.","example":"My computer tends to crash when I open too many tabs.","exampleTranslation":"탭을 너무 많이 열면 컴퓨터가 멈추는 경향이 있어요.","category":"빈도 학습","level":15},{"id":11520,"term":"observation","meaning":"관찰; 주목","partOfSpeech":"n.","example":"Her observation helped us find the problem quickly.","exampleTranslation":"그녀의 관찰 덕분에 우리는 문제를 빨리 찾았다.","category":"빈도 학습","level":15},{"id":11521,"term":"concentration","meaning":"집중; 농도","partOfSpeech":"n.","example":"I need complete silence for concentration while studying.","exampleTranslation":"공부할 때 집중하려면 완전한 정적이 필요해요.","category":"빈도 학습","level":15},{"id":11522,"term":"implication","meaning":"함의; 암시","partOfSpeech":"n.","example":"Did you understand the implication of what he said?","exampleTranslation":"그가 한 말의 함의를 이해했나요?","category":"빈도 학습","level":15},{"id":11523,"term":"deserve","meaning":"~을 받을 자격이 있다; ~할 만하다","partOfSpeech":"v.","example":"You deserve a break after working so hard.","exampleTranslation":"그렇게 열심히 일했으니 쉴 자격이 있어요.","category":"빈도 학습","level":15},{"id":11524,"term":"unusual","meaning":"흔치 않은; 특이한","partOfSpeech":"adj.","example":"It's unusual for him to be late to meetings.","exampleTranslation":"그가 회의에 늦는 건 흔치 않은 일이에요.","category":"빈도 학습","level":15},{"id":11525,"term":"defend","meaning":"방어하다; 옹호하다","partOfSpeech":"v.","example":"She stood up to defend her friend from criticism.","exampleTranslation":"그녀는 친구를 비판으로부터 지키기 위해 나섰다.","category":"빈도 학습","level":15},{"id":11526,"term":"classic","meaning":"전형적인; 고전적인","partOfSpeech":"adj.","example":"This is a classic case of miscommunication.","exampleTranslation":"이건 전형적인 의사소통 실패 사례예요.","category":"빈도 학습","level":15},{"id":11527,"term":"king","meaning":"왕; 최고 지위의 사람","partOfSpeech":"n.","example":"The king greeted his people from the palace balcony.","exampleTranslation":"왕은 궁전 발코니에서 백성들에게 인사했다.","category":"빈도 학습","level":15},{"id":11528,"term":"interaction","meaning":"상호작용; 교류","partOfSpeech":"n.","example":"Daily interaction with native speakers improved her English.","exampleTranslation":"원어민과 매일 교류하면서 그녀의 영어가 늘었다.","category":"빈도 학습","level":15},{"id":11529,"term":"collapse","meaning":"무너지다; 쓰러지다","partOfSpeech":"v.","example":"He was so tired that he collapse onto the couch.","exampleTranslation":"그는 너무 피곤해서 소파에 쓰러졌다.","category":"빈도 학습","level":15},{"id":11530,"term":"borrow","meaning":"빌리다","partOfSpeech":"v.","example":"Can I borrow your pen for a second?","exampleTranslation":"잠깐 펜 좀 빌릴 수 있을까요?","category":"빈도 학습","level":15},{"id":11531,"term":"fundamental","meaning":"기본적인; 근본적인","partOfSpeech":"adj.","example":"Trust is fundamental to any good relationship.","exampleTranslation":"신뢰는 좋은 관계의 근본이에요.","category":"빈도 학습","level":15},{"id":11532,"term":"dish","meaning":"요리; 접시","partOfSpeech":"n.","example":"This dish is my grandmother's specialty.","exampleTranslation":"이 요리는 우리 할머니의 특기예요.","category":"빈도 학습","level":15},{"id":11533,"term":"abroad","meaning":"해외에; 외국으로","partOfSpeech":"adv.","example":"She studied abroad for two years in Canada.","exampleTranslation":"그녀는 캐나다에서 2년간 유학했다.","category":"빈도 학습","level":15},{"id":11534,"term":"soul","meaning":"영혼; 마음","partOfSpeech":"n.","example":"Music feeds my soul when I'm feeling down.","exampleTranslation":"기분이 우울할 때 음악은 내 영혼을 달래준다.","category":"빈도 학습","level":15},{"id":11535,"term":"capable","meaning":"능력 있는; ~을 할 수 있는","partOfSpeech":"adj.","example":"She's capable of handling the project on her own.","exampleTranslation":"그녀는 혼자서 그 프로젝트를 처리할 능력이 있어요.","category":"빈도 학습","level":15},{"id":11536,"term":"defeat","meaning":"패배시키다; 이기다","partOfSpeech":"v.","example":"Our team managed to defeat the champions last night.","exampleTranslation":"우리 팀은 어젯밤 챔피언 팀을 이겼다.","category":"빈도 학습","level":15},{"id":11537,"term":"presidential","meaning":"대통령의; 대통령에 관한","partOfSpeech":"adj.","example":"The presidential election draws a lot of media attention.","exampleTranslation":"대통령 선거는 많은 언론의 주목을 받는다.","category":"빈도 학습","level":15},{"id":11538,"term":"perfectly","meaning":"완벽하게; 아주 잘","partOfSpeech":"adv.","example":"The dress fits her perfectly.","exampleTranslation":"그 드레스는 그녀에게 완벽하게 맞는다.","category":"빈도 학습","level":15},{"id":11539,"term":"enhance","meaning":"향상시키다; 높이다","partOfSpeech":"v.","example":"Regular exercise can enhance your mood and energy.","exampleTranslation":"규칙적인 운동은 기분과 에너지를 높여줄 수 있어요.","category":"빈도 학습","level":15},{"id":11540,"term":"proud","meaning":"자랑스러운; 뿌듯한","partOfSpeech":"adj.","example":"I'm so proud of everything you've accomplished.","exampleTranslation":"네가 이룬 모든 것이 정말 자랑스러워.","category":"빈도 학습","level":15},{"id":11541,"term":"educational","meaning":"교육적인; 교육에 관한","partOfSpeech":"adj.","example":"That documentary was really educational for the kids.","exampleTranslation":"그 다큐멘터리는 아이들에게 정말 교육적이었다.","category":"빈도 학습","level":15},{"id":11542,"term":"distinguish","meaning":"구별하다; 식별하다","partOfSpeech":"v.","example":"It's hard to distinguish the two twins apart.","exampleTranslation":"그 쌍둥이 둘을 구별하기가 정말 어렵다.","category":"빈도 학습","level":15},{"id":11543,"term":"substantial","meaning":"상당한; 실질적인","partOfSpeech":"adj.","example":"There's been a substantial improvement in her grades.","exampleTranslation":"그녀의 성적이 상당히 향상됐다.","category":"빈도 학습","level":15},{"id":11544,"term":"nearby","meaning":"근처의; 가까이에","partOfSpeech":"adj.","example":"Let's grab lunch at that nearby café.","exampleTranslation":"근처 카페에서 점심 먹자.","category":"빈도 학습","level":15},{"id":11545,"term":"manufacturer","meaning":"제조업체; 제조사","partOfSpeech":"n.","example":"The manufacturer offers a two-year warranty on this product.","exampleTranslation":"제조사는 이 제품에 2년 보증을 제공한다.","category":"빈도 학습","level":15},{"id":11546,"term":"slide","meaning":"미끄러지다; 슬라이드","partOfSpeech":"v.","example":"The kids love to slide down the hill in winter.","exampleTranslation":"아이들은 겨울에 언덕을 미끄러져 내려오는 걸 좋아한다.","category":"빈도 학습","level":15},{"id":11547,"term":"valuable","meaning":"소중한; 가치 있는","partOfSpeech":"adj.","example":"Time is the most valuable thing you can give someone.","exampleTranslation":"시간은 당신이 누군가에게 줄 수 있는 가장 소중한 것이다.","category":"빈도 학습","level":15},{"id":11548,"term":"personally","meaning":"개인적으로; 직접","partOfSpeech":"adv.","example":"Personally, I prefer tea over coffee.","exampleTranslation":"개인적으로 저는 커피보다 차를 더 좋아해요.","category":"빈도 학습","level":15},{"id":11549,"term":"breast","meaning":"가슴; 유방","partOfSpeech":"n.","example":"Grilled chicken breast is a healthy dinner option.","exampleTranslation":"닭가슴살 구이는 건강한 저녁 식사 선택지이다.","category":"빈도 학습","level":15},{"id":11550,"term":"cope","meaning":"대처하다; 감당하다","partOfSpeech":"v.","example":"She learned to cope with stress through meditation.","exampleTranslation":"그녀는 명상을 통해 스트레스에 대처하는 법을 배웠다.","category":"빈도 학습","level":15},{"id":11551,"term":"approximately","meaning":"약; 대략","partOfSpeech":"adv.","example":"The drive takes approximately two hours without traffic.","exampleTranslation":"차로 가면 막히지 않을 때 약 두 시간 걸린다.","category":"빈도 학습","level":15},{"id":11552,"term":"accommodation","meaning":"숙소; 숙박 시설","partOfSpeech":"n.","example":"We booked accommodation near the airport for the night.","exampleTranslation":"우리는 하룻밤 공항 근처 숙소를 예약했다.","category":"빈도 학습","level":15},{"id":11553,"term":"highlight","meaning":"강조하다; 가장 좋은 부분","partOfSpeech":"v.","example":"The speaker tried to highlight the key points of her talk.","exampleTranslation":"발표자는 강연의 핵심 요점을 강조하려 했다.","category":"빈도 학습","level":15},{"id":11554,"term":"reporter","meaning":"기자; 취재 기자","partOfSpeech":"n.","example":"A reporter asked the mayor about the new policy.","exampleTranslation":"기자가 시장에게 새 정책에 대해 물었다.","category":"빈도 학습","level":15},{"id":11555,"term":"climate","meaning":"기후; 분위기","partOfSpeech":"n.","example":"The climate here is warm and sunny all year round.","exampleTranslation":"이곳 기후는 일 년 내내 따뜻하고 화창하다.","category":"빈도 학습","level":15},{"id":11556,"term":"shirt","meaning":"셔츠","partOfSpeech":"n.","example":"He spilled coffee on his shirt before the interview.","exampleTranslation":"그는 면접 전에 셔츠에 커피를 쏟았다.","category":"빈도 학습","level":15},{"id":11557,"term":"corporation","meaning":"법인; 대기업","partOfSpeech":"n.","example":"She got a job offer from a large corporation downtown.","exampleTranslation":"그녀는 시내 대기업에서 취업 제안을 받았다.","category":"빈도 학습","level":15},{"id":11558,"term":"chip","meaning":"칩; 파편","partOfSpeech":"n.","example":"There's a chip in this bowl — be careful.","exampleTranslation":"이 그릇에 이가 나갔으니 조심해요.","category":"빈도 학습","level":15},{"id":11559,"term":"winner","meaning":"우승자; 승리자","partOfSpeech":"n.","example":"The winner of the contest received a cash prize.","exampleTranslation":"대회 우승자는 현금 상금을 받았다.","category":"빈도 학습","level":15},{"id":11560,"term":"encounter","meaning":"마주치다; 맞닥뜨리다","partOfSpeech":"v.","example":"I encounter the same problem every morning with my computer.","exampleTranslation":"나는 매일 아침 컴퓨터에서 같은 문제에 맞닥뜨린다.","category":"빈도 학습","level":15},{"id":11561,"term":"brown","meaning":"갈색; 갈색의","partOfSpeech":"n./adj.","example":"She bought a brown leather bag at the market.","exampleTranslation":"그녀는 시장에서 갈색 가죽 가방을 샀다.","category":"빈도 학습","level":15},{"id":11562,"term":"breathe","meaning":"숨을 쉬다; 호흡하다","partOfSpeech":"v.","example":"Just breathe slowly and try to calm down.","exampleTranslation":"천천히 숨을 쉬면서 진정하려고 해봐.","category":"빈도 학습","level":15},{"id":11563,"term":"excuse","meaning":"변명; 용서하다","partOfSpeech":"n./v.","example":"He always has an excuse for being late.","exampleTranslation":"그는 항상 늦는 것에 대한 변명이 있다.","category":"빈도 학습","level":15},{"id":11564,"term":"partly","meaning":"부분적으로; 어느 정도","partOfSpeech":"adv.","example":"The delay was partly due to bad weather.","exampleTranslation":"그 지연은 부분적으로 나쁜 날씨 때문이었다.","category":"빈도 학습","level":15},{"id":11565,"term":"tennis","meaning":"테니스","partOfSpeech":"n.","example":"We play tennis every Sunday at the local park.","exampleTranslation":"우리는 매주 일요일 동네 공원에서 테니스를 친다.","category":"빈도 학습","level":15},{"id":11566,"term":"urban","meaning":"도시의; 도심의","partOfSpeech":"adj.","example":"Urban areas tend to have more job opportunities.","exampleTranslation":"도시 지역은 일자리 기회가 더 많은 편이다.","category":"빈도 학습","level":15},{"id":11567,"term":"confuse","meaning":"혼동하다; 헷갈리게 하다","partOfSpeech":"v.","example":"People often confuse the two brothers because they look so alike.","exampleTranslation":"두 형제가 너무 닮아서 사람들이 자주 혼동한다.","category":"빈도 학습","level":15},{"id":11568,"term":"southern","meaning":"남쪽의; 남부의","partOfSpeech":"adj.","example":"They moved to a southern city to escape the cold winters.","exampleTranslation":"그들은 추운 겨울을 피하려고 남부 도시로 이사했다.","category":"빈도 학습","level":15},{"id":11569,"term":"output","meaning":"산출량; 결과물","partOfSpeech":"n.","example":"The factory increased its output by hiring more workers.","exampleTranslation":"그 공장은 직원을 더 채용해 산출량을 늘렸다.","category":"빈도 학습","level":15},{"id":11570,"term":"beauty","meaning":"아름다움; 미(美)","partOfSpeech":"n.","example":"The beauty of the mountain view took my breath away.","exampleTranslation":"산 풍경의 아름다움에 나는 숨이 멎는 것 같았다.","category":"빈도 학습","level":15},{"id":11571,"term":"massive","meaning":"거대한; 엄청난","partOfSpeech":"adj.","example":"There was a massive crowd waiting outside the concert hall.","exampleTranslation":"콘서트홀 밖에 엄청난 인파가 기다리고 있었다.","category":"빈도 학습","level":15},{"id":11572,"term":"install","meaning":"설치하다","partOfSpeech":"v.","example":"Can you help me install this app on my phone?","exampleTranslation":"내 폰에 이 앱 설치하는 것 좀 도와줄 수 있어?","category":"빈도 학습","level":15},{"id":11573,"term":"calculate","meaning":"계산하다; 산출하다","partOfSpeech":"v.","example":"I need to calculate how much money I spent last month.","exampleTranslation":"지난달에 돈을 얼마나 썼는지 계산해봐야겠다.","category":"빈도 학습","level":15},{"id":11574,"term":"mouse","meaning":"쥐; (컴퓨터) 마우스","partOfSpeech":"n.","example":"The mouse on my desk stopped working this morning.","exampleTranslation":"오늘 아침에 책상 위의 마우스가 작동하지 않았다.","category":"빈도 학습","level":15},{"id":11575,"term":"mathematics","meaning":"수학","partOfSpeech":"n.","example":"She was always good at mathematics in school.","exampleTranslation":"그녀는 학교에서 항상 수학을 잘했다.","category":"빈도 학습","level":15},{"id":11576,"term":"upper","meaning":"위쪽의; 상위의","partOfSpeech":"adj.","example":"The books are on the upper shelf in the bedroom.","exampleTranslation":"책들은 침실의 위쪽 선반에 있다.","category":"빈도 학습","level":15},{"id":11577,"term":"creation","meaning":"창조; 창작물","partOfSpeech":"n.","example":"The chef proudly served his latest creation to the guests.","exampleTranslation":"요리사는 자신의 최신 창작 요리를 손님들에게 자랑스럽게 내놓았다.","category":"빈도 학습","level":15},{"id":11578,"term":"occupy","meaning":"차지하다; 점유하다","partOfSpeech":"v.","example":"The new sofa will occupy too much space in the living room.","exampleTranslation":"새 소파가 거실 공간을 너무 많이 차지할 것이다.","category":"빈도 학습","level":15},{"id":11579,"term":"outline","meaning":"개요; 윤곽을 잡다","partOfSpeech":"n./v.","example":"Let me give you a quick outline of the plan.","exampleTranslation":"계획의 간략한 개요를 알려드릴게요.","category":"빈도 학습","level":15},{"id":11580,"term":"sufficient","meaning":"충분한","partOfSpeech":"adj.","example":"Make sure you have sufficient time before the flight.","exampleTranslation":"비행기 출발 전에 시간이 충분한지 확인하세요.","category":"빈도 학습","level":15},{"id":11581,"term":"luck","meaning":"운; 행운","partOfSpeech":"n.","example":"I had no luck finding a parking spot downtown.","exampleTranslation":"시내에서 주차 공간을 찾는 운이 없었다.","category":"빈도 학습","level":15},{"id":11582,"term":"preserve","meaning":"보존하다; 지키다","partOfSpeech":"v.","example":"We should preserve old buildings in the city center.","exampleTranslation":"우리는 도심의 오래된 건물들을 보존해야 한다.","category":"빈도 학습","level":15},{"id":11583,"term":"split","meaning":"나누다; 쪼개다","partOfSpeech":"v.","example":"Let's split the bill evenly between the four of us.","exampleTranslation":"우리 넷이서 계산서를 똑같이 나누자.","category":"빈도 학습","level":15},{"id":11584,"term":"swing","meaning":"흔들리다; 그네","partOfSpeech":"v./n.","example":"The kids love to swing at the playground after school.","exampleTranslation":"아이들은 방과 후 놀이터에서 그네 타는 것을 좋아한다.","category":"빈도 학습","level":15},{"id":11585,"term":"illness","meaning":"질병; 병","partOfSpeech":"n.","example":"He missed a week of work due to illness.","exampleTranslation":"그는 병 때문에 일주일 동안 결근했다.","category":"빈도 학습","level":15},{"id":11586,"term":"journalist","meaning":"기자; 언론인","partOfSpeech":"n.","example":"The journalist asked the mayor several tough questions.","exampleTranslation":"그 기자는 시장에게 몇 가지 날카로운 질문을 던졌다.","category":"빈도 학습","level":15},{"id":11587,"term":"sudden","meaning":"갑작스러운","partOfSpeech":"adj.","example":"The sudden noise woke everyone up in the middle of the night.","exampleTranslation":"갑작스러운 소리에 한밤중에 모두가 잠에서 깼다.","category":"빈도 학습","level":15},{"id":11588,"term":"advertisement","meaning":"광고","partOfSpeech":"n.","example":"I saw an advertisement for that new restaurant on the bus.","exampleTranslation":"버스에서 그 새 식당 광고를 봤다.","category":"빈도 학습","level":15},{"id":11589,"term":"consistent","meaning":"일관된; 한결같은","partOfSpeech":"adj.","example":"She gets consistent results because she practices every day.","exampleTranslation":"그녀는 매일 연습하기 때문에 일관된 결과를 낸다.","category":"빈도 학습","level":15},{"id":11590,"term":"originally","meaning":"원래; 처음에는","partOfSpeech":"adv.","example":"This building was originally a factory in the 1900s.","exampleTranslation":"이 건물은 원래 1900년대에 공장이었다.","category":"빈도 학습","level":15},{"id":11591,"term":"aside","meaning":"옆으로; 제쳐두고","partOfSpeech":"adv.","example":"Set your phone aside and focus on the conversation.","exampleTranslation":"폰을 옆으로 치우고 대화에 집중해.","category":"빈도 학습","level":15},{"id":11592,"term":"comfort","meaning":"위안; 편안함","partOfSpeech":"n./v.","example":"A warm cup of tea gives me comfort on cold days.","exampleTranslation":"추운 날에는 따뜻한 차 한 잔이 나에게 위안이 된다.","category":"빈도 학습","level":15},{"id":11593,"term":"secondly","meaning":"두 번째로; 다음으로","partOfSpeech":"adv.","example":"First, save the file; secondly, send it to your team.","exampleTranslation":"먼저 파일을 저장하고, 다음으로 팀에 전송하세요.","category":"빈도 학습","level":15},{"id":11594,"term":"severe","meaning":"심각한; 극심한","partOfSpeech":"adj.","example":"The severe storm caused flooding across the whole town.","exampleTranslation":"심각한 폭풍으로 마을 전체에 홍수가 났다.","category":"빈도 학습","level":15},{"id":11595,"term":"gene","meaning":"유전자","partOfSpeech":"n.","example":"Scientists found a gene linked to the risk of heart disease.","exampleTranslation":"과학자들이 심장병 위험과 관련된 유전자를 발견했다.","category":"빈도 학습","level":15},{"id":11596,"term":"prospect","meaning":"전망; 가능성","partOfSpeech":"n.","example":"The prospect of living abroad excited her greatly.","exampleTranslation":"해외에서 살 전망이 그녀를 크게 설레게 했다.","category":"빈도 학습","level":15},{"id":11597,"term":"snow","meaning":"눈; 눈이 내리다","partOfSpeech":"n./v.","example":"It started to snow heavily while we were driving home.","exampleTranslation":"우리가 집으로 운전해 오는 동안 눈이 심하게 내리기 시작했다.","category":"빈도 학습","level":15},{"id":11598,"term":"plot","meaning":"줄거리; 구획","partOfSpeech":"n.","example":"The plot of the movie was hard to follow at first.","exampleTranslation":"그 영화의 줄거리는 처음에 이해하기 어려웠다.","category":"빈도 학습","level":15},{"id":11599,"term":"neck","meaning":"목","partOfSpeech":"n.","example":"My neck is really stiff after sitting at my desk all day.","exampleTranslation":"하루 종일 책상에 앉아 있었더니 목이 정말 뻣뻣하다.","category":"빈도 학습","level":16},{"id":11600,"term":"criterion","meaning":"기준; 판단 근거","partOfSpeech":"n.","example":"Price is not the only criterion when choosing a hotel.","exampleTranslation":"가격만이 호텔을 고를 때 유일한 기준은 아니에요.","category":"빈도 학습","level":16},{"id":11601,"term":"primarily","meaning":"주로; 첫째로","partOfSpeech":"adv.","example":"She moved here primarily for work, not family.","exampleTranslation":"그녀는 가족 때문이 아니라 주로 일 때문에 이곳으로 이사했어요.","category":"빈도 학습","level":16},{"id":11602,"term":"integrate","meaning":"통합하다; 합치다","partOfSpeech":"v.","example":"It took me a while to integrate into the new team.","exampleTranslation":"새 팀에 녹아드는 데 시간이 좀 걸렸어요.","category":"빈도 학습","level":16},{"id":11603,"term":"criticism","meaning":"비판; 비평","partOfSpeech":"n.","example":"She accepted the criticism and improved her work.","exampleTranslation":"그녀는 비판을 받아들이고 작업을 개선했어요.","category":"빈도 학습","level":16},{"id":11604,"term":"convention","meaning":"관례; 대회; 협약","partOfSpeech":"n.","example":"It's a convention to shake hands when you first meet someone.","exampleTranslation":"처음 만날 때 악수하는 건 관례예요.","category":"빈도 학습","level":16},{"id":11605,"term":"bet","meaning":"내기하다; 틀림없이 ~이다","partOfSpeech":"v.","example":"I bet it's going to rain this afternoon.","exampleTranslation":"오늘 오후에 비가 올 것 같아요.","category":"빈도 학습","level":16},{"id":11606,"term":"retain","meaning":"유지하다; 보유하다","partOfSpeech":"v.","example":"He works hard to retain his customers every year.","exampleTranslation":"그는 매년 고객을 유지하기 위해 열심히 일해요.","category":"빈도 학습","level":16},{"id":11607,"term":"sequence","meaning":"순서; 연속","partOfSpeech":"n.","example":"Follow the steps in sequence to assemble the furniture.","exampleTranslation":"가구를 조립하려면 순서대로 단계를 따르세요.","category":"빈도 학습","level":16},{"id":11608,"term":"plain","meaning":"평범한; 꾸밈없는; 분명한","partOfSpeech":"adj.","example":"She wore a plain white shirt to the interview.","exampleTranslation":"그녀는 면접에 평범한 흰 셔츠를 입고 갔어요.","category":"빈도 학습","level":16},{"id":11609,"term":"volunteer","meaning":"자원봉사자; 자원하다","partOfSpeech":"n./v.","example":"She decided to volunteer at the local food bank on weekends.","exampleTranslation":"그녀는 주말에 동네 푸드뱅크에서 자원봉사하기로 했어요.","category":"빈도 학습","level":16},{"id":11610,"term":"rural","meaning":"시골의; 농촌의","partOfSpeech":"adj.","example":"He grew up in a rural town with no traffic lights.","exampleTranslation":"그는 신호등 하나 없는 시골 마을에서 자랐어요.","category":"빈도 학습","level":16},{"id":11611,"term":"calm","meaning":"차분한; 진정하다","partOfSpeech":"adj.","example":"Take a deep breath and stay calm during the test.","exampleTranslation":"시험 중에 심호흡하고 차분하게 있어요.","category":"빈도 학습","level":16},{"id":11612,"term":"abandon","meaning":"버리다; 포기하다","partOfSpeech":"v.","example":"Don't abandon your plans just because things get tough.","exampleTranslation":"힘들다고 계획을 포기하지 마세요.","category":"빈도 학습","level":16},{"id":11613,"term":"examination","meaning":"시험; 검사","partOfSpeech":"n.","example":"The doctor ordered a full examination to find the cause.","exampleTranslation":"의사는 원인을 찾기 위해 정밀 검사를 지시했어요.","category":"빈도 학습","level":16},{"id":11614,"term":"silence","meaning":"침묵; 고요함","partOfSpeech":"n.","example":"There was complete silence in the room after the announcement.","exampleTranslation":"발표가 끝난 후 방 안은 완전한 침묵에 빠졌어요.","category":"빈도 학습","level":16},{"id":11615,"term":"rapidly","meaning":"빠르게; 급속히","partOfSpeech":"adv.","example":"The city has rapidly grown over the past ten years.","exampleTranslation":"그 도시는 지난 10년 동안 빠르게 성장했어요.","category":"빈도 학습","level":16},{"id":11616,"term":"revolution","meaning":"혁명; 대변혁","partOfSpeech":"n.","example":"The smartphone caused a revolution in how we communicate.","exampleTranslation":"스마트폰은 우리가 소통하는 방식에 혁명을 일으켰어요.","category":"빈도 학습","level":16},{"id":11617,"term":"delight","meaning":"기쁨; 매우 기뻐하다","partOfSpeech":"n./v.","example":"The kids shrieked with delight when they saw the puppies.","exampleTranslation":"아이들은 강아지들을 보고 기뻐서 소리를 질렀어요.","category":"빈도 학습","level":16},{"id":11618,"term":"spell","meaning":"철자를 말하다; 주문; 기간","partOfSpeech":"v.","example":"Can you spell your last name for me, please?","exampleTranslation":"성의 철자를 말씀해 주시겠어요?","category":"빈도 학습","level":16},{"id":11619,"term":"premise","meaning":"전제; 근거","partOfSpeech":"n.","example":"The whole plan is based on the premise that costs will stay low.","exampleTranslation":"전체 계획은 비용이 낮게 유지된다는 전제를 바탕으로 해요.","category":"빈도 학습","level":16},{"id":11620,"term":"lean","meaning":"기대다; 기울다; 호리호리한","partOfSpeech":"v.","example":"He tends to lean on his friends when things go wrong.","exampleTranslation":"그는 일이 잘못되면 친구들에게 의지하는 편이에요.","category":"빈도 학습","level":16},{"id":11621,"term":"dramatic","meaning":"극적인; 눈에 띄는","partOfSpeech":"adj.","example":"There has been a dramatic drop in temperatures this week.","exampleTranslation":"이번 주에 기온이 극적으로 떨어졌어요.","category":"빈도 학습","level":16},{"id":11622,"term":"differ","meaning":"다르다; 의견이 다르다","partOfSpeech":"v.","example":"My taste in music tends to differ from my sister's.","exampleTranslation":"음악 취향이 언니랑 달라요.","category":"빈도 학습","level":16},{"id":11623,"term":"grateful","meaning":"감사하는; 고마운","partOfSpeech":"adj.","example":"I'm so grateful for all the help you gave me.","exampleTranslation":"도움을 많이 주셔서 정말 감사해요.","category":"빈도 학습","level":16},{"id":11624,"term":"bike","meaning":"자전거; 오토바이","partOfSpeech":"n.","example":"She rides her bike to the market every Saturday morning.","exampleTranslation":"그녀는 매주 토요일 아침 자전거를 타고 시장에 가요.","category":"빈도 학습","level":16},{"id":11625,"term":"distribute","meaning":"나눠 주다; 배포하다","partOfSpeech":"v.","example":"Volunteers helped distribute food to families in need.","exampleTranslation":"자원봉사자들이 도움이 필요한 가족들에게 음식을 나눠 줬어요.","category":"빈도 학습","level":16},{"id":11626,"term":"intellectual","meaning":"지적인; 지식인","partOfSpeech":"adj.","example":"She finds chess to be a stimulating intellectual challenge.","exampleTranslation":"그녀는 체스가 자극적인 지적 도전이라고 생각해요.","category":"빈도 학습","level":16},{"id":11627,"term":"derive","meaning":"얻다; 유래하다","partOfSpeech":"v.","example":"You can derive a lot of joy from simple things.","exampleTranslation":"사소한 것들에서 큰 기쁨을 얻을 수 있어요.","category":"빈도 학습","level":16},{"id":11628,"term":"crucial","meaning":"결정적인; 매우 중요한","partOfSpeech":"adj.","example":"Getting enough sleep is crucial before a big exam.","exampleTranslation":"중요한 시험 전에 충분히 자는 건 정말 중요해요.","category":"빈도 학습","level":16},{"id":11629,"term":"unemployment","meaning":"실업; 실직 상태","partOfSpeech":"n.","example":"High unemployment is a serious problem in many regions.","exampleTranslation":"높은 실업률은 많은 지역에서 심각한 문제예요.","category":"빈도 학습","level":16},{"id":11630,"term":"wheel","meaning":"바퀴; 핸들","partOfSpeech":"n.","example":"The front wheel of his bicycle needs to be replaced.","exampleTranslation":"그의 자전거 앞바퀴를 교체해야 해요.","category":"빈도 학습","level":16},{"id":11631,"term":"crop","meaning":"농작물; 수확하다","partOfSpeech":"n./v.","example":"The warm summer helped farmers grow a good crop this year.","exampleTranslation":"따뜻한 여름 덕분에 농부들이 올해 좋은 농작물을 키웠어요.","category":"빈도 학습","level":16},{"id":11632,"term":"minority","meaning":"소수; 소수 집단","partOfSpeech":"n.","example":"Only a minority of students chose to stay after class.","exampleTranslation":"수업 후에 남기로 한 학생은 소수에 불과했어요.","category":"빈도 학습","level":16},{"id":11633,"term":"origin","meaning":"기원; 출신; 발단","partOfSpeech":"n.","example":"Do you know the origin of this local festival?","exampleTranslation":"이 지역 축제의 기원을 알아요?","category":"빈도 학습","level":16},{"id":11634,"term":"interpretation","meaning":"해석; 이해; 통역","partOfSpeech":"n.","example":"Her interpretation of the poem surprised everyone in class.","exampleTranslation":"그녀의 시 해석은 반 모든 사람을 놀라게 했어요.","category":"빈도 학습","level":16},{"id":11635,"term":"gentleman","meaning":"신사; 예의 바른 남성","partOfSpeech":"n.","example":"He held the door open like a true gentleman.","exampleTranslation":"그는 진짜 신사처럼 문을 잡아줬어요.","category":"빈도 학습","level":16},{"id":11636,"term":"drama","meaning":"드라마; 연극; 소란","partOfSpeech":"n.","example":"There's always some drama going on in that office.","exampleTranslation":"저 사무실에는 항상 무슨 소란이 있어요.","category":"빈도 학습","level":16},{"id":11637,"term":"landscape","meaning":"풍경; 경관","partOfSpeech":"n.","example":"The mountain landscape was absolutely breathtaking.","exampleTranslation":"산의 풍경이 정말 숨막히게 아름다웠어요.","category":"빈도 학습","level":16},{"id":11638,"term":"educate","meaning":"교육하다; 가르치다","partOfSpeech":"v.","example":"Parents play a key role in helping to educate their children.","exampleTranslation":"부모는 자녀를 교육하는 데 핵심적인 역할을 해요.","category":"빈도 학습","level":16},{"id":11639,"term":"toy","meaning":"장난감; 가지고 놀다","partOfSpeech":"n.","example":"She bought a toy for her nephew's birthday.","exampleTranslation":"그녀는 조카 생일 선물로 장난감을 샀어요.","category":"빈도 학습","level":16},{"id":11640,"term":"fault","meaning":"잘못; 결함","partOfSpeech":"n.","example":"It was my fault that we missed the bus.","exampleTranslation":"버스를 놓친 건 내 잘못이었어.","category":"빈도 학습","level":16},{"id":11641,"term":"exhibit","meaning":"전시하다; 보여주다","partOfSpeech":"v.","example":"The museum will exhibit local artists' work next month.","exampleTranslation":"그 박물관은 다음 달 지역 예술가들의 작품을 전시할 예정이야.","category":"빈도 학습","level":16},{"id":11642,"term":"minor","meaning":"사소한; 소수의","partOfSpeech":"adj.","example":"There was only a minor delay at the airport.","exampleTranslation":"공항에서 잠깐 지연됐을 뿐이었어.","category":"빈도 학습","level":16},{"id":11643,"term":"hunt","meaning":"찾다; 사냥하다","partOfSpeech":"v.","example":"She spent all afternoon trying to hunt down a good deal.","exampleTranslation":"그녀는 오후 내내 좋은 할인 상품을 찾으러 다녔어.","category":"빈도 학습","level":16},{"id":11644,"term":"storm","meaning":"폭풍; 폭풍이 치다","partOfSpeech":"n./v.","example":"A big storm hit the coast last night.","exampleTranslation":"어젯밤 큰 폭풍이 해안을 강타했어.","category":"빈도 학습","level":16},{"id":11645,"term":"thick","meaning":"두꺼운; 짙은","partOfSpeech":"adj.","example":"He wore a thick coat because it was freezing outside.","exampleTranslation":"밖이 너무 추워서 그는 두꺼운 코트를 입었어.","category":"빈도 학습","level":16},{"id":11646,"term":"achievement","meaning":"성취; 업적","partOfSpeech":"n.","example":"Getting the scholarship was a huge achievement for her.","exampleTranslation":"장학금을 받은 건 그녀에게 대단한 성취였어.","category":"빈도 학습","level":16},{"id":11647,"term":"shoot","meaning":"쏘다; 촬영하다","partOfSpeech":"v.","example":"They decided to shoot the video in the park.","exampleTranslation":"그들은 공원에서 영상을 촬영하기로 했어.","category":"빈도 학습","level":16}]`);export{e as default};